/* AUTO-GENERATED — Pennsylvania Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["PA"] = {"code":"PA","name":"Pennsylvania","agency":"Pennsylvania DMV","agencyShort":"DMV","handbook":"https://www.pa.gov/agencies/dmv/driver-services/commercial-drivers/pennsylvania-commercial-driver-license-manual","links":{},"en":[{"q":"On Pennsylvania highways, what is the maximum total outside width of a vehicle, including any load?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"answer":0,"explanation":"Under 75 Pa.C.S. § 4921 (Width of vehicles), the total outside width of a vehicle, including any load, may not exceed 8 feet 6 inches. PennDOT's Driver and Vehicle Services Size and Weight Limitations page states the same figure.","handbook":"","hbref":""},{"q":"What is the maximum height of a vehicle, including any load, generally permitted on Pennsylvania highways?","options":["13 feet 6 inches","13 feet 0 inches","14 feet 0 inches","12 feet 6 inches"],"answer":0,"explanation":"Under 75 Pa.C.S. § 4922 (Height of vehicles), no vehicle, including its load, may exceed a height of 13 feet 6 inches. This is confirmed on PennDOT's Size and Weight Limitations page.","handbook":"","hbref":""},{"q":"What is the maximum overall length of a single (individual) motor vehicle, including load and bumpers, on Pennsylvania highways?","options":["40 feet","45 feet","53 feet","35 feet"],"answer":0,"explanation":"Under 75 Pa.C.S. § 4923 (Length of vehicles), a single motor vehicle, including any load and bumpers, may not exceed 40 feet overall. Special vehicle types (buses, motor homes, boom-equipped vehicles) have separate, higher limits.","handbook":"","hbref":""},{"q":"What is the maximum gross weight of any single vehicle or combination on Pennsylvania highways under the Vehicle Code?","options":["80,000 pounds","73,280 pounds","90,000 pounds","100,000 pounds"],"answer":0,"explanation":"Under 75 Pa.C.S. § 4941, and as stated on PennDOT's Size and Weight Limitations page, the maximum gross weight of any individual vehicle or any combination is 80,000 pounds, subject also to registered weight and axle-weight limits.","handbook":"","hbref":""},{"q":"What is the maximum length of a single semitrailer in a tractor-trailer combination operating in Pennsylvania?","options":["53 feet","48 feet","57 feet","40 feet"],"answer":0,"explanation":"Pennsylvania permits a single trailer in a tractor-semitrailer combination to be up to 53 feet long, provided the kingpin-to-rear-axle distance does not exceed 41 feet. This is reflected in 75 Pa.C.S. Chapter 49 and PennDOT's Size and Weight Limitations page.","handbook":"","hbref":""},{"q":"In a double-trailer (twin) combination in Pennsylvania, what is the maximum length of each trailer?","options":["28 feet 6 inches","28 feet 0 inches","33 feet 0 inches","30 feet 0 inches"],"answer":0,"explanation":"PennDOT's Size and Weight Limitations page states that in a double-trailer combination, each trailer is limited to 28 feet 6 inches, consistent with 75 Pa.C.S. Chapter 49 length provisions.","handbook":"","hbref":""},{"q":"On Pennsylvania's Interstate highway system, what is the maximum gross vehicle weight even when the federal bridge formula would otherwise allow more?","options":["80,000 pounds","85,500 pounds","90,000 pounds","73,280 pounds"],"answer":0,"explanation":"Pennsylvania follows the federal standard: on the Interstate System the gross vehicle weight is capped at 80,000 pounds, even if the Federal Bridge Formula result is higher. This federal limit applies to Pennsylvania Interstates per 23 U.S.C. § 127 and 75 Pa.C.S. § 4941.","handbook":"","hbref":""},{"q":"What is the maximum weight allowed on a single axle (other than a steering axle) for a heavy combination in Pennsylvania?","options":["20,000 pounds","18,000 pounds","22,400 pounds","34,000 pounds"],"answer":0,"explanation":"Under 75 Pa.C.S. § 4943 (and the federal standard Pennsylvania follows), the maximum weight on a single axle is 20,000 pounds. This matches the federal single-axle limit applied on the Interstate System.","handbook":"","hbref":""},{"q":"Under the federal weight standard that Pennsylvania applies, what is the maximum weight on a tandem axle (a group of two consecutive axles)?","options":["34,000 pounds","36,000 pounds","40,000 pounds","20,000 pounds"],"answer":0,"explanation":"Pennsylvania applies the federal tandem-axle limit of 34,000 pounds. 75 Pa.C.S. § 4943 allows two consecutive pairs of axles to carry 34,000 pounds each when the distance between the first and last axles of the pairs is 36 feet or more.","handbook":"","hbref":""},{"q":"What is the primary purpose of the Federal Bridge Formula as applied in Pennsylvania?","options":["To limit the weight on groups of axles to reduce the risk of damage to highway bridges","To set the maximum height of loads passing under bridges","To calculate the toll owed on the Pennsylvania Turnpike","To determine the minimum following distance for heavy trucks"],"answer":0,"explanation":"The Federal Bridge Formula (Bridge Gross Weight Formula) limits the allowable weight on any group of consecutive axles based on the number of axles and the distance between them, to protect bridges. It applies to Pennsylvania's Interstate System under 23 U.S.C. § 127.","handbook":"","hbref":""},{"q":"When is a PennDOT hauling permit required to operate a vehicle in Pennsylvania?","options":["When the vehicle or load exceeds the legal size or weight limits in the Vehicle Code","Only when crossing into another state","Whenever transporting any commercial cargo","Only when the driver lacks a CDL"],"answer":0,"explanation":"Per PennDOT's Size and Weight Limitations page, a vehicle may only be operated outside the legal size/weight limits with a permit from PennDOT. Oversize/overweight hauling permits authorize movement exceeding the limits in 75 Pa.C.S. Chapter 49.","handbook":"","hbref":""},{"q":"Through which PennDOT system are oversize/overweight special hauling permits primarily applied for and issued in Pennsylvania?","options":["APRAS (Automated Permit Routing and Analysis System)","CDLIS (Commercial Driver License Information System)","IRP (International Registration Plan) portal","SAFER (Safety and Fitness Electronic Records)"],"answer":0,"explanation":"PennDOT issues oversize/overweight Special Hauling permits through APRAS, the Automated Permit Routing and Analysis System, which processes hundreds of thousands of permits annually, many automatically. Source: PennDOT APRAS / Apply for a PennDOT Hauling Permit.","handbook":"","hbref":""},{"q":"A vehicle and load measuring more than which width is considered oversize and requires a PennDOT permit?","options":["Greater than 8 feet 6 inches","Greater than 8 feet 0 inches","Greater than 9 feet 0 inches","Greater than 10 feet 0 inches"],"answer":0,"explanation":"Because the legal width under 75 Pa.C.S. § 4921 is 8 feet 6 inches, any vehicle and load wider than 8 feet 6 inches is oversize and requires a PennDOT hauling permit. Source: PennDOT hauling permit / Load Type guidance.","handbook":"","hbref":""},{"q":"A load taller than which height is considered oversize and requires a PennDOT permit?","options":["Greater than 13 feet 6 inches","Greater than 13 feet 0 inches","Greater than 14 feet 0 inches","Greater than 12 feet 6 inches"],"answer":0,"explanation":"Since the legal height limit under 75 Pa.C.S. § 4922 is 13 feet 6 inches, a load exceeding 13 feet 6 inches is oversize and requires a PennDOT hauling permit. Source: PennDOT Size and Weight Limitations / hauling permit guidance.","handbook":"","hbref":""},{"q":"What is the maximum permitted weight on a steering axle before a vehicle is considered overweight in Pennsylvania?","options":["20,000 pounds","12,000 pounds","18,000 pounds","22,400 pounds"],"answer":0,"explanation":"Per PennDOT permit guidance under 75 Pa.C.S. § 4943, a vehicle is overweight if the weight on the steering axle exceeds 20,000 pounds. Above that, a PennDOT overweight permit is required.","handbook":"","hbref":""},{"q":"Under Pennsylvania's annual 'movement during course of manufacture' permit (75 Pa.C.S. § 4968), which raw forest-products commodity may be moved over the maximum weight?","options":["Pulpwood and wood chips","Finished furniture","Bagged mulch for retail sale","Construction lumber to a retail dealer"],"answer":0,"explanation":"75 Pa.C.S. § 4968 permits annual-permit movement over the maximum weight for commodities such as raw milk, raw coal, pulpwood and wood chips while in the course of manufacture and under the manufacturer's control. No permit is issued for goods in transit to a purchaser or dealer.","handbook":"","hbref":""},{"q":"On the Pennsylvania Turnpike, certain permitted loads may exceed the general 80,000-pound limit up to what maximum gross weight?","options":["100,000 pounds","80,000 pounds","90,000 pounds","120,000 pounds"],"answer":0,"explanation":"The Pennsylvania Turnpike sets its own commercial permit limits, allowing permitted gross weight up to 100,000 pounds (with axle weight up to 22,400 pounds). Source: PA Turnpike Commercial Permits and Restrictions. PennDOT highways remain capped at 80,000 lb.","handbook":"","hbref":""},{"q":"Under 75 Pa.C.S. § 4943, what is the maximum weight on a pair of axles spaced more than 8 feet apart on a heavy combination?","options":["22,400 pounds each","18,000 pounds each","20,000 pounds each","34,000 pounds each"],"answer":0,"explanation":"Under 75 Pa.C.S. § 4943's axle-spacing rules, axles spaced more than 8 feet apart may carry up to 22,400 pounds each, whereas axles less than 6 feet apart are limited to 18,000 pounds each.","handbook":"","hbref":""},{"q":"Why does the Federal Bridge Formula sometimes limit a truck to LESS than 80,000 pounds even when no single axle group is overloaded?","options":["Because closely spaced axle groups concentrate weight, so the formula reduces the allowable gross weight to protect bridges","Because the steering axle is always excluded from the gross weight","Because Pennsylvania caps all trucks at 73,280 pounds","Because tolls increase with axle spacing"],"answer":0,"explanation":"The Federal Bridge Formula ties allowable weight to the number of axles and the distance spanned. When axles are closely spaced, the formula yields a value below 80,000 pounds to limit stress on bridge spans. Pennsylvania applies this on the Interstate System per 23 U.S.C. § 127.","handbook":"","hbref":""},{"q":"An oversize/overweight movement that exceeds the largest standard permit thresholds in Pennsylvania (a 'superload') must be handled how?","options":["Submitted through APRAS for review, often requiring manual analysis and routing before approval","Driven without a permit if moved at night","Approved automatically at any PennDOT photo license center","Exempt from all routing because it pays a higher toll"],"answer":0,"explanation":"Superload applications must be submitted through PennDOT's APRAS system; while most routine permits are approved automatically in about a minute, superloads and roughly one in five applications require manual review and route analysis. Source: PennDOT APRAS.","handbook":"","hbref":""},{"q":"In Pennsylvania, which class of CDL is required to operate a combination of vehicles with a Gross Combination Weight Rating (GCWR) of 26,001 pounds or more, when the towed vehicle has a GVWR exceeding 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Per the PennDOT Commercial Driver's License Fact Sheet (June 2025) and PUB 223, a Class A CDL covers a combination vehicle with a GCWR of 26,001 pounds or more, provided the GVWR of the towed vehicle is in excess of 10,000 pounds. Source: PennDOT CDL Fact Sheet / Commercial Driver's Manual (PUB 223).","handbook":"","hbref":""},{"q":"Under Pennsylvania CDL rules, a single vehicle with a Gross Vehicle Weight Rating (GVWR) of 26,001 pounds or more (or such a vehicle towing a unit not over 10,000 pounds) requires which license class?","options":["Class A","Class B","Class C","Class M"],"answer":1,"explanation":"PennDOT defines Class B as a single vehicle with a GVWR of 26,001 pounds or more, or any such vehicle towing a vehicle not in excess of 10,000 pounds. Source: PennDOT CDL Fact Sheet (June 2025) / PUB 223.","handbook":"","hbref":""},{"q":"According to PennDOT, a Pennsylvania Class C CDL is used for a single vehicle under 26,001 pounds GVWR that transports placarded hazardous materials, carries 16 or more people, or is a school bus. What must a Class C CDL also include?","options":["An S, P, or H endorsement","A motorcycle (M) endorsement","A Class A air-brake certification","A farm-vehicle waiver"],"answer":0,"explanation":"The PennDOT CDL Fact Sheet states a Class C CDL covers single vehicles under 26,001 lbs GVWR that transport placarded hazmat, are designed to carry 16+ including the driver, or are a school bus, and that a Class C CDL must include an S, P, or H endorsement. Source: PennDOT CDL Fact Sheet (June 2025).","handbook":"","hbref":""},{"q":"In Pennsylvania, what does the 'N' endorsement authorize a CDL holder to do?","options":["Operate tank vehicles","Operate double and triple trailers","Carry passengers in a bus","Transport placarded hazardous materials"],"answer":0,"explanation":"PennDOT states endorsement N authorizes the driver to operate tank vehicles. (Endorsement T is for doubles/triples, P for passengers, and H for placarded hazmat.) Source: PennDOT CDL Fact Sheet (June 2025) / PUB 223.","handbook":"","hbref":""},{"q":"Which Pennsylvania CDL endorsement is required to drive double and triple trailers?","options":["Endorsement T","Endorsement N","Endorsement X","Endorsement H"],"answer":0,"explanation":"PennDOT states endorsement T authorizes the driving of double and triple trailers. Source: PennDOT CDL Fact Sheet (June 2025) / PUB 223.","handbook":"","hbref":""},{"q":"On a Pennsylvania CDL, what does the combined 'X' endorsement represent?","options":["Both hazardous materials and tank vehicle (H and N)","Both passenger and school bus (P and S)","Both doubles/triples and tank (T and N)","An expired endorsement pending renewal"],"answer":0,"explanation":"PennDOT lists endorsement X as hazardous materials and tank vehicle combined (H,N). Source: PennDOT CDL Fact Sheet (June 2025).","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Pennsylvania CDL for intrastate driving (operating a commercial vehicle only within Pennsylvania)?","options":["18 years old","16 years old","19 years old","21 years old"],"answer":0,"explanation":"Pennsylvania requires a minimum age of 18 to hold a CDL for intrastate (in-state only) commercial driving. Source: PennDOT Driver and Vehicle Services, Commercial Drivers / License Types & Restrictions.","handbook":"","hbref":""},{"q":"What is the minimum age required to operate a commercial motor vehicle in interstate commerce (across state lines) with a Pennsylvania CDL?","options":["21 years old","18 years old","19 years old","25 years old"],"answer":0,"explanation":"To operate a CMV in interstate commerce, a driver must be at least 21. Drivers 18-20 may only operate intrastate within Pennsylvania. Source: PennDOT Commercial Drivers / 49 CFR 391.11 as applied in Pennsylvania.","handbook":"","hbref":""},{"q":"After passing the required knowledge test and being issued a Pennsylvania commercial learner's permit, what is the minimum waiting period before a Class A, B, or C skills test may be scheduled?","options":["15 days","10 days","30 days","7 days"],"answer":0,"explanation":"Per PennDOT, skills testing cannot be taken until 15 days after the knowledge test is passed and a permit is issued. This satisfies the federal 14-day CLP-hold requirement. Source: PennDOT CDL Fact Sheet (June 2025) and CDL Learner's Permit FAQs.","handbook":"","hbref":""},{"q":"A Pennsylvania Knowledge Test Authorization (KTA) / commercial learner's permit is valid for how long, giving the applicant time to pass all knowledge and skills tests?","options":["One year from the date of issuance","90 days from the date of issuance","Six months from the date of issuance","Two years from the date of issuance"],"answer":0,"explanation":"PennDOT states the KTA is valid for one year from the date of issuance, and applicants have one year to pass all knowledge and skills tests to obtain their CDL. Source: PennDOT CDL Learner's Permit FAQs.","handbook":"","hbref":""},{"q":"Every person who applies for a Pennsylvania commercial learner's permit or holds a CDL must complete which document identifying the type of commercial operation they perform?","options":["A Self-Certification Form (DL-11CD)","A REAL ID waiver form","An IRP apportioned registration form","A Form I-9 employment authorization"],"answer":0,"explanation":"PennDOT requires every CDL holder and every CLP applicant to submit a Self-Certification Form (DL-11CD) identifying their type of driving. Source: PennDOT CDL Fact Sheet (June 2025) and Self-Certification/Medical Examiner FAQs.","handbook":"","hbref":""},{"q":"Which of the following is one of the four medical self-certification categories a Pennsylvania CDL applicant must choose from?","options":["Non-excepted Interstate","Excepted Out-of-State","Placarded Interstate","Restricted Intrastate"],"answer":0,"explanation":"The four self-certification categories are Non-excepted Interstate, Non-excepted Intrastate, Excepted Interstate, and Excepted Intrastate. A Non-excepted Interstate driver must have a valid Medical Examiner's Certificate on file with PennDOT. Source: PennDOT Self-Certification/Medical Examiner FAQs.","handbook":"","hbref":""},{"q":"A Pennsylvania driver who self-certifies as 'Non-excepted Intrastate' is subject to federal physical qualification standards while driving only within the state. What license restriction does PennDOT add in this case?","options":["A 'K' restriction (intrastate commerce only)","An 'L' restriction (no air brakes)","An 'E' restriction (no manual transmission)","An 'O' restriction (no fifth-wheel combination)"],"answer":0,"explanation":"PennDOT applies restriction K limiting the driver to intrastate commerce only. The K restriction appears for intrastate-only commercial operation. Source: PennDOT CDL Fact Sheet (June 2025) and Self-Certification FAQs.","handbook":"","hbref":""},{"q":"Effective February 7, 2022, Entry-Level Driver Training (ELDT) is required in Pennsylvania for first-time applicants of which credential(s)?","options":["A first Class A or B CDL, or a first P, S, or H endorsement","Any CDL renewal regardless of class","Only a HazMat (H) endorsement","Only intrastate Class C CDLs"],"answer":0,"explanation":"Per FMCSA rules adopted by PennDOT, ELDT (effective Feb 7, 2022) applies to obtaining a Class A or B CDL for the first time, upgrading to Class A or B, or obtaining a P, S, or H endorsement for the first time. It is not retroactive. Source: PennDOT Entry Level Driver Training page / 49 CFR Part 380.","handbook":"","hbref":""},{"q":"Where must a Pennsylvania entry-level driver obtain their required ELDT training before taking the skills test?","options":["From a provider listed on the FMCSA Training Provider Registry (TPR)","From any PennDOT driver license center","From an employer's informal on-the-job program","From any AAA-affiliated driving school"],"answer":0,"explanation":"PennDOT requires ELDT to be completed with a provider listed on the FMCSA Training Provider Registry (tpr.fmcsa.dot.gov) before the skills test. Source: PennDOT CDL Fact Sheet (June 2025) / Entry Level Driver Training page.","handbook":"","hbref":""},{"q":"To obtain a Pennsylvania HazMat (H) endorsement, an applicant must pass a knowledge test and complete which federal background screening?","options":["A TSA Security Threat Assessment with fingerprinting","An E-Verify employment check","A PennDOT-only driving record review","An FAA medical certification"],"answer":0,"explanation":"PennDOT requires HazMat applicants to complete a federal Transportation Security Administration (TSA) Security Threat Assessment, including fingerprinting (Form DL-288, PUB 512). PennDOT must receive federal approval before issuing the H endorsement. Source: PennDOT Hazardous Materials Endorsement Fact Sheet (FS-HM) and FAQs.","handbook":"","hbref":""},{"q":"On the official PennDOT CDL knowledge tests, how many questions are on the Hazardous Materials (H) endorsement test?","options":["30 questions","20 questions","25 questions","50 questions"],"answer":0,"explanation":"PennDOT lists the Hazardous Materials Endorsement knowledge test as 30 questions, and the HazMat test is offered in English only. Source: PennDOT CDL Fact Sheet (June 2025).","handbook":"","hbref":""},{"q":"Before earning a Pennsylvania School Bus (S) endorsement, which endorsement must the driver also hold?","options":["The Passenger (P) endorsement","The Tank (N) endorsement","The Doubles/Triples (T) endorsement","The HazMat (H) endorsement"],"answer":0,"explanation":"PennDOT requires the Passenger (P) endorsement as a prerequisite for the School Bus (S) endorsement; the S knowledge test requires the passenger endorsement. Source: PennDOT CDL Fact Sheet (June 2025) / School Transportation FAQs.","handbook":"","hbref":""},{"q":"Which statement about the Pennsylvania School Bus (S) endorsement card is correct per PennDOT?","options":["A School Bus endorsement card is issued annually","The S endorsement never requires renewal","The S endorsement is issued only every eight years","The S endorsement card is mailed by the TSA"],"answer":0,"explanation":"The PennDOT CDL Fact Sheet notes that endorsement S authorizes operating a school bus and that a School Bus endorsement card is issued annually. Source: PennDOT CDL Fact Sheet (June 2025).","handbook":"","hbref":""},{"q":"When applying in person for a Pennsylvania CDL/CLP, an applicant must generally provide proof of identity and lawful status, proof of Social Security number, and how many proofs of Pennsylvania residency?","options":["Two proofs of Pennsylvania residency","One proof of Pennsylvania residency","Three proofs of Pennsylvania residency","No proof of residency is required"],"answer":0,"explanation":"PennDOT requires one document proving identity/lawful status, one document proving the Social Security number, and two documents proving Pennsylvania residency. Source: PennDOT Proof of Identity and Residency requirements (PUB 195US).","handbook":"","hbref":""},{"q":"In Pennsylvania, what is the maximum blood alcohol concentration (BAC) at or above which a driver is considered to be operating a commercial motor vehicle (CMV) under the influence?","options":["0.02 percent","0.04 percent","0.08 percent","0.10 percent"],"answer":1,"explanation":"Pennsylvania prohibits operating a CMV with a BAC of 0.04 percent or greater, half the 0.08 percent limit for non-commercial drivers. Source: PA CDL Manual; 75 Pa.C.S. and 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Pennsylvania's implied consent rules, what happens to a CMV driver who refuses to submit to chemical testing after a proper officer warning?","options":["A written warning only with no disqualification","A 30-day CDL disqualification","A 1-year CDL disqualification, treated like a DUI conviction","A 6-month CDL disqualification"],"answer":2,"explanation":"A CMV driver who refuses chemical testing is disqualified for at least 1 year, the same as a major-offense conviction. Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Pennsylvania, a first major offense (such as operating a CMV with a BAC of 0.04 percent or higher) results in a CDL disqualification of at least how long?","options":["60 days","6 months","1 year","3 years"],"answer":2,"explanation":"A first major offense disqualifies a Pennsylvania CDL holder for a minimum of 1 year. Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Pennsylvania, if a driver commits a first major offense while operating a CMV that is placarded for hazardous materials, the disqualification period increases to:","options":["1 year","2 years","3 years","5 years"],"answer":2,"explanation":"A first major offense committed while transporting placarded hazardous materials raises the disqualification from 1 year to 3 years. Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the CDL disqualification period in Pennsylvania for a second major offense (for example, a second DUI in a CMV)?","options":["3 years","5 years","10 years","Lifetime"],"answer":3,"explanation":"Two major offenses in any vehicle result in a lifetime CDL disqualification in Pennsylvania. Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Pennsylvania, being convicted of TWO serious traffic violations in separate incidents within a 3-year period results in a CDL disqualification of:","options":["30 days","60 days","120 days","1 year"],"answer":1,"explanation":"Two serious traffic violations within 3 years disqualify a Pennsylvania CDL holder for 60 days. Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Pennsylvania, being convicted of THREE serious traffic violations in separate incidents within a 3-year period results in a CDL disqualification of:","options":["60 days","90 days","120 days","1 year"],"answer":2,"explanation":"Three serious traffic violations within 3 years disqualify a Pennsylvania CDL holder for 120 days, served consecutively after any 60-day disqualification. Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of the following is classified as a SERIOUS traffic violation for a Pennsylvania CDL holder?","options":["A burned-out tail lamp","Exceeding the speed limit by 15 mph or more","Parking in a no-stopping zone","Driving with an expired registration"],"answer":1,"explanation":"Speeding 15 mph or more over the limit is a serious traffic violation; others include reckless driving, improper lane change, following too closely, texting, and handheld phone use. Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"For a Pennsylvania CDL driver, what is the disqualification for a FIRST conviction of violating a railroad-highway grade crossing law?","options":["30 days","60 days","120 days","1 year"],"answer":1,"explanation":"A first railroad-grade-crossing violation disqualifies a Pennsylvania CDL holder for 60 days. Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"For a Pennsylvania CDL driver, a SECOND railroad-highway grade crossing violation within a 3-year period results in a disqualification of:","options":["60 days","120 days","1 year","3 years"],"answer":1,"explanation":"A second railroad-grade-crossing violation within 3 years disqualifies a Pennsylvania CDL holder for 120 days. Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"For a Pennsylvania CDL driver, a THIRD or subsequent railroad-highway grade crossing violation within a 3-year period results in a disqualification of:","options":["120 days","180 days","1 year","3 years"],"answer":2,"explanation":"A third or subsequent railroad-grade-crossing violation within 3 years disqualifies a Pennsylvania CDL holder for 1 year. Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Pennsylvania, a FIRST conviction for violating an out-of-service (OOS) order while hauling NON-hazardous materials disqualifies a CDL driver for:","options":["90 days","180 days","1 year","2 years"],"answer":2,"explanation":"A first out-of-service order violation (non-hazmat) disqualifies a Pennsylvania CDL holder for at least 1 year. Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Pennsylvania, a SECOND out-of-service order violation within a 10-year period (non-hazmat) results in a CDL disqualification of:","options":["1 year","2 years","3 years","5 years"],"answer":2,"explanation":"A second out-of-service order violation within 10 years (non-hazmat) disqualifies a Pennsylvania CDL holder for at least 3 years. Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Pennsylvania, a FIRST out-of-service order violation while transporting hazardous materials or carrying 16 or more passengers disqualifies a CDL driver for:","options":["1 year","2 years","3 years","5 years"],"answer":1,"explanation":"A first out-of-service order violation while hauling hazmat or carrying 16+ passengers disqualifies a Pennsylvania CDL holder for at least 2 years. Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Pennsylvania, a SECOND out-of-service order violation within 10 years while transporting hazardous materials or carrying 16 or more passengers disqualifies a CDL driver for:","options":["2 years","3 years","5 years","Lifetime"],"answer":2,"explanation":"A second out-of-service order violation within 10 years while hauling hazmat or carrying 16+ passengers disqualifies a Pennsylvania CDL holder for at least 5 years. Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"For a Pennsylvania CDL holder, using a handheld mobile phone while driving a CMV is treated as:","options":["A non-reportable equipment violation","A serious traffic violation that can lead to disqualification","An automatic 1-year disqualification on the first offense","A lifetime disqualification offense"],"answer":1,"explanation":"Using a handheld phone while operating a CMV is a serious traffic violation; two within 3 years cause a 60-day disqualification and three cause 120 days. Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51 and 392.82.","handbook":"","hbref":""},{"q":"For a Pennsylvania CDL holder, texting while driving a commercial motor vehicle is:","options":["Permitted if the vehicle is stopped at a light","A serious traffic violation that can lead to disqualification","Only a parking-type fine with no license effect","Allowed for dispatch communication"],"answer":1,"explanation":"Texting while operating a CMV is a serious traffic violation; accumulating these within 3 years leads to 60- or 120-day disqualifications. Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51 and 392.80.","handbook":"","hbref":""},{"q":"In Pennsylvania, which conviction carries a LIFETIME CDL disqualification with NO option for reinstatement after 10 years?","options":["A second DUI in a CMV","Using a CMV to commit a felony involving manufacturing or distributing a controlled substance","Two serious traffic violations within 3 years","A first out-of-service order violation"],"answer":1,"explanation":"Using a CMV in a felony involving manufacturing, distributing, or dispensing a controlled substance results in a lifetime disqualification that cannot be reduced. Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A Pennsylvania CDL driver convicted of a major offense that results in a fatality through negligent or criminal operation of a CMV is disqualified for at least:","options":["60 days","120 days","1 year","5 years"],"answer":2,"explanation":"Causing a fatality through negligent or criminal operation of a CMV is a major offense carrying a minimum 1-year disqualification (3 years if placarded for hazmat). Source: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Pennsylvania's school bus law, when a school bus has its red signal lights flashing and stop arm out, how far before reaching the bus must a meeting or overtaking driver stop?","options":["At least 10 feet","At least 15 feet","At least 20 feet","At least 25 feet"],"answer":0,"explanation":"Pennsylvania requires drivers meeting or overtaking a school bus with flashing red signal lights to stop at least 10 feet from the bus and not proceed until the lights stop flashing and the stop arm is withdrawn. Source: 75 Pa.C.S. § 3345 (Meeting or overtaking school bus); PA Commercial Driver's Manual (PUB 223).","handbook":"","hbref":""},{"q":"On a Pennsylvania highway with separate roadways divided by a physical barrier or clearly indicated dividing section, a driver on the OPPOSITE roadway from a stopped school bus with flashing red lights must:","options":["Not be required to stop","Stop at least 10 feet from the median","Stop only if children are visible","Slow to 15 mph but need not stop"],"answer":0,"explanation":"Pennsylvania's divided-highway exception states a driver on a highway with separate roadways need not stop for a school bus with flashing red lights that is on a DIFFERENT roadway. A 'separate roadway' requires a physical barrier or clearly indicated dividing section; painted lines or signs alone do not create one. Source: 75 Pa.C.S. § 3345.","handbook":"","hbref":""},{"q":"Which feature is REQUIRED for Pennsylvania's school-bus 'separate roadways' exception to apply (so opposing traffic need not stop)?","options":["A physical barrier or clearly indicated dividing section","A double yellow center line","A center left-turn lane","A posted sign reading 'DIVIDED HIGHWAY'"],"answer":0,"explanation":"In Pennsylvania the exception applies only where roadways are separated by a physical barrier or a clearly indicated dividing section. Pavement markings or signs alone are NOT construed as creating a separate roadway, so on roads divided only by paint, all directions must still stop. Source: 75 Pa.C.S. § 3345.","handbook":"","hbref":""},{"q":"A vehicle required to stop at a railroad grade crossing in Pennsylvania must stop within what distance of the nearest rail?","options":["Within 50 feet but not less than 15 feet","Within 100 feet but not less than 25 feet","Within 30 feet but not less than 10 feet","Within 75 feet but not less than 20 feet"],"answer":0,"explanation":"Pennsylvania law requires vehicles that must stop at railroad crossings (school buses, passenger buses, and trucks carrying certain fuels/explosives/radioactive materials) to stop within 50 feet but not less than 15 feet from the nearest rail, then look and listen. Source: 75 Pa.C.S. § 3342 (Vehicles required to stop at railroad crossings); PA CDL Manual.","handbook":"","hbref":""},{"q":"Which vehicle is NOT required to stop at every railroad grade crossing under Pennsylvania law?","options":["An empty dry-van tractor-trailer carrying no hazardous materials","A school bus, whether or not carrying passengers","A bus transporting passengers","A truck carrying placarded explosives"],"answer":0,"explanation":"Pennsylvania requires school buses (loaded or empty), passenger-carrying buses, and trucks hauling gasoline, diesel/fuel oil, explosives, or radioactive materials to stop at crossings. An ordinary empty freight van without hazardous cargo is not required to stop. Source: 75 Pa.C.S. § 3342.","handbook":"","hbref":""},{"q":"When a Pennsylvania CMV that must stop is crossing railroad tracks, the driver is specifically prohibited from doing what?","options":["Manually shifting gears while on the tracks","Using the engine brake","Crossing in low gear","Activating four-way flashers"],"answer":0,"explanation":"Pennsylvania law directs that a required-to-stop driver cross in a gear that will not require changing gears while crossing, and shall not manually shift gears while on the track(s). Source: 75 Pa.C.S. § 3342; PA CDL Manual.","handbook":"","hbref":""},{"q":"At a Pennsylvania railroad crossing marked with a sign reading 'EXEMPT,' a placarded hazmat truck or bus:","options":["Is not required to stop","Must still stop within 50 feet of the rail","Must stop and sound the horn","Must stop only if a gate is present"],"answer":0,"explanation":"Pennsylvania exempts crossings posted with an 'exempt' sign (and abandoned crossings posted as such) from the mandatory-stop rule; an officer or flagman directing the vehicle through, or a green traffic signal, also relieves the duty to stop. Source: 75 Pa.C.S. § 3342.","handbook":"","hbref":""},{"q":"Under Pennsylvania's Move Over law, when a driver CANNOT safely move into a non-adjacent lane near an emergency response area, the driver must instead pass at a speed no more than how much below the posted limit?","options":["20 mph below the posted speed limit","10 mph below the posted speed limit","15 mph below the posted speed limit","25 mph below the posted speed limit"],"answer":0,"explanation":"Pennsylvania's Move Over (Steer Clear) law requires passing in a lane not adjacent to the emergency response area when possible; if that is impossible, illegal, or unsafe, the driver must pass at no more than 20 mph below the posted speed limit and at a speed reasonable for safety. Source: 75 Pa.C.S. § 3327.","handbook":"","hbref":""},{"q":"Pennsylvania's Move Over law (Act 105 of 2020) assigns how many points for failing to merge into a lane not next to an emergency response area?","options":["2 points","3 points","4 points","5 points"],"answer":0,"explanation":"Act 105 of 2020 added a 2-point penalty for failing to move over, plus escalating fines of $500 (first), $1,000 (second), and $2,000 with a 90-day suspension (third or subsequent). Source: 75 Pa.C.S. § 3327; PennDOT Move Over campaign.","handbook":"","hbref":""},{"q":"Besides police, fire, ambulance, and tow trucks, Pennsylvania's Move Over law also protects which of the following?","options":["A disabled vehicle displaying at least two emergency markings (e.g., hazard lights and flares)","Any vehicle parked legally on the shoulder","Only government-owned vehicles","Vehicles stopped at a red light"],"answer":0,"explanation":"Pennsylvania extended the Move Over duty to disabled vehicles that display at least two emergency markings such as hazard lights, caution signs/devices, or road flares. Drivers must change lanes or slow to no more than 20 mph below the limit. Source: 75 Pa.C.S. § 3327 (duty in relation to disabled vehicles).","handbook":"","hbref":""},{"q":"On a Pennsylvania limited-access highway with three or more lanes in one direction, where may a truck combination over 10,000 pounds travel?","options":["Any lane except the left-hand lane (which is barred except to prepare for a permitted left turn)","Only the center lane at all times","Only the right-hand lane at all times","Any lane, with no restriction"],"answer":0,"explanation":"Pennsylvania prohibits a vehicle or combination over 10,000 pounds from being driven in the LEFT-hand lane of a limited-access highway having three or more lanes in the same direction, except when preparing for a legally permitted left turn at an intersection, exit, or driveway. Source: 75 Pa.C.S. § 3313 (Restrictions on use of limited access highways).","handbook":"","hbref":""},{"q":"On Pennsylvania limited-access highways with two or more lanes in one direction, the general rule for all vehicles is to drive in the right lanes EXCEPT when:","options":["Overtaking and passing, moving faster than traffic flow, or preparing for a permitted left turn","Traveling at night","The road is wet","A passenger requests the left lane"],"answer":0,"explanation":"Pennsylvania requires vehicles to use the right-hand lanes when available, except when overtaking and passing a vehicle, traveling at a speed greater than the traffic flow, or preparing for a legally permitted left turn. Source: 75 Pa.C.S. § 3313.","handbook":"","hbref":""},{"q":"Absent a posted sign, the default maximum speed limit on most Pennsylvania roadways (not urban districts or freeways) is:","options":["55 mph","50 mph","60 mph","65 mph"],"answer":0,"explanation":"Pennsylvania sets a statutory maximum of 55 mph in locations not otherwise posted, 35 mph in any urban district, and up to 65 or 70 mph on freeways where the department posts that limit. Source: 75 Pa.C.S. § 3362 (Maximum speed limits).","handbook":"","hbref":""},{"q":"On a Pennsylvania freeway posted at 70 mph, how does the maximum speed limit for a heavy commercial truck compare to that for a passenger car?","options":["It is the same—70 mph applies to all vehicles","Trucks are limited to 55 mph","Trucks are limited to 60 mph","Trucks are limited to 65 mph"],"answer":0,"explanation":"Pennsylvania does not set a separate, lower truck speed limit; the posted 65 or 70 mph freeway maximum applies to all vehicles. (Lower limits can apply on specific downgrades or via posted signs.) Source: 75 Pa.C.S. § 3362.","handbook":"","hbref":""},{"q":"The maximum posted speed limit on the Pennsylvania Turnpike mainline (I-76) is:","options":["70 mph","65 mph","75 mph","80 mph"],"answer":0,"explanation":"The Pennsylvania Turnpike's maximum posted speed limit is 70 mph, in place on most of the mainline (e.g., between the Blue Mountain and Morgantown interchanges) and many PennDOT freeways. No section is posted at 75 mph. Source: Pennsylvania Turnpike Commission / PennDOT; 75 Pa.C.S. § 3362.","handbook":"","hbref":""},{"q":"Pennsylvania's urban-district statutory speed limit, where no other limit is posted, is:","options":["35 mph","25 mph","30 mph","40 mph"],"answer":0,"explanation":"In any urban district, Pennsylvania's statutory maximum speed is 35 mph unless a different limit is posted after a traffic study. Source: 75 Pa.C.S. § 3362.","handbook":"","hbref":""},{"q":"A truck driver whose CMV is stopped on the traveled portion of a two-lane, two-way Pennsylvania highway must place warning devices within what time, and where?","options":["Within 10 minutes: at 10 ft, 100 ft to the rear, and 100 ft to the front","Within 15 minutes: at 25 ft, 50 ft, and 100 ft","Within 30 minutes: at 10 ft, 200 ft, and 300 ft","Within 5 minutes: all three within 50 ft"],"answer":0,"explanation":"Following the federal standard that Pennsylvania applies, a stopped CMV must display warning devices within 10 minutes. On a two-way road, place one within 10 ft of the vehicle toward approaching traffic, one about 100 ft to the rear, and one about 100 ft to the front. Source: PA CDL Manual (PUB 223); 49 CFR 392.22.","handbook":"","hbref":""},{"q":"When a CMV is stopped on a one-way or divided Pennsylvania highway, where are the three warning devices placed toward approaching traffic?","options":["About 10 ft, 100 ft, and 200 ft to the rear","About 10 ft, 50 ft, and 100 ft to the rear","About 25 ft, 100 ft, and 250 ft to the rear","About 10 ft, 100 ft, and 150 ft to the rear"],"answer":0,"explanation":"On a one-way or divided highway, place warning devices at about 10 feet, 100 feet, and 200 feet toward approaching traffic (the side from which traffic comes), within 10 minutes of stopping. Source: PA CDL Manual (PUB 223); 49 CFR 392.22.","handbook":"","hbref":""},{"q":"Which class of hazardous materials is PROHIBITED from being transported through the Pennsylvania Turnpike's tunnels?","options":["All explosives and other Table 1 materials (e.g., poison gas, radioactive)","Only flammable liquids in bulk","Only corrosive materials","Only refrigerated gases"],"answer":0,"explanation":"The Pennsylvania Turnpike bans all Table 1 materials—including all explosives, poison gas, dangerous-when-wet, poison-inhalation-hazard, and radioactive materials—from its tunnels; certain non-bulk shipments of other hazmat may be allowed. Source: Pennsylvania Turnpike Commission Hazardous Materials Tunnel Restrictions; 67 Pa. Code § 601.5.","handbook":"","hbref":""},{"q":"A driver convicted of illegally passing a stopped school bus with flashing red lights in Pennsylvania faces a base fine plus surcharge of:","options":["$250 fine plus a $35 surcharge (with points and a license suspension)","$100 fine with no surcharge","$500 fine plus a $50 surcharge","$50 fine plus a $25 surcharge"],"answer":0,"explanation":"Pennsylvania penalizes illegally passing a stopped school bus with a $250 fine and a $35 surcharge; an officer-observed violation also brings 5 points and a 60-day license suspension. Source: 75 Pa.C.S. § 3345.","handbook":"","hbref":""},{"q":"Which agency issues commercial driver's licenses (CDLs) in Pennsylvania?","options":["The Pennsylvania State Police, Commercial Vehicle Unit","The Pennsylvania Department of Transportation (PennDOT), Bureau of Driver and Vehicle Services","The Pennsylvania Public Utility Commission (PUC)","The Federal Motor Carrier Safety Administration (FMCSA)"],"answer":1,"explanation":"Pennsylvania CDLs are issued by PennDOT through its Bureau of Driver and Vehicle Services. FMCSA sets federal standards but does not issue state licenses. Source: PennDOT Commercial Driver's License Fact Sheet (PUB 223 reference) and pa.gov Driver and Vehicle Services.","handbook":"","hbref":""},{"q":"In Pennsylvania, what is the minimum age to obtain a CDL for intrastate (within-Pennsylvania) driving versus interstate driving?","options":["21 for both intrastate and interstate","16 for intrastate and 18 for interstate","18 for intrastate and 21 for interstate","18 for both intrastate and interstate"],"answer":2,"explanation":"Pennsylvania allows a CDL at age 18 for intrastate operation only, while interstate operation (and hazmat or passenger transport across state lines) requires the driver to be at least 21. Source: PennDOT CDL licensing requirements (pa.gov) consistent with 49 CFR 383.3.","handbook":"","hbref":""},{"q":"Before taking the CDL skills test in Pennsylvania, an applicant must first obtain which credential?","options":["A medical waiver from PennDOT","A Commercial Learner's Permit (CLP)","A REAL ID-compliant photo license","A Class C non-commercial CDL"],"answer":1,"explanation":"Applicants must pass the required knowledge test(s) and be issued a Commercial Learner's Permit before they may take the skills test. Source: PennDOT CDL Learner's Permit FAQs and CDL Fact Sheet (pa.gov).","handbook":"","hbref":""},{"q":"What form does a Pennsylvania CDL or CLP applicant use to self-certify the type of commercial driving they perform?","options":["Driver's Record Request DL-503","Commercial Learner's Permit Application DL-31CD","Medical Examiner's Certificate DL-26","Self-Certification Form DL-11CD"],"answer":3,"explanation":"Every CDL holder and every CLP applicant must submit the Self-Certification Form DL-11CD declaring their category of operation. DL-31CD is the CLP application, a separate form. Source: PennDOT Self-Certification/Medical Examiner's Certification FAQs and Form DL-11CD (pa.gov).","handbook":"","hbref":""},{"q":"Which one of the following is NOT one of the four self-certification categories a Pennsylvania CDL applicant must choose from?","options":["Exempt Agricultural Operator","Excepted Intrastate","Non-excepted Intrastate","Non-excepted Interstate"],"answer":0,"explanation":"The four self-certification categories are Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate, and Excepted Intrastate. \"Exempt Agricultural Operator\" is not a self-certification category. Source: PennDOT Self-Certification Form DL-11CD and CDL Fact Sheet (pa.gov).","handbook":"","hbref":""},{"q":"Which self-certification category requires the driver to have a valid Medical Examiner's Certificate (DOT physical card) on record with PennDOT?","options":["Non-excepted Interstate","Excepted Intrastate","Excepted Interstate and Excepted Intrastate","Excepted Interstate"],"answer":0,"explanation":"Only drivers who self-certify as Non-excepted (Interstate or Intrastate) must keep a valid Medical Examiner's Certificate on record with PennDOT. Excepted categories are not required to provide a MEC. Source: PennDOT Self-Certification/Medical Examiner's Certification FAQs (pa.gov).","handbook":"","hbref":""},{"q":"As of June 23, 2025, how must a Pennsylvania non-excepted CDL holder's Medical Examiner's Certificate (DOT physical) be submitted to PennDOT?","options":["It is transmitted electronically from the FMCSA National Registry directly to PennDOT","The driver hands the paper card to a clerk at any PennDOT Driver License Center","The driver emails a scanned copy to PennDOT","The driver mails the paper card to the PennDOT CDL Unit in Harrisburg"],"answer":0,"explanation":"Since June 23, 2025, PennDOT only accepts Medical Examiner's Certificate information transmitted electronically from the FMCSA National Registry; it no longer accepts MECs in person, by mail, or by email. Source: PennDOT Self-Certification/Medical Examiner's Certification FAQs (pa.gov).","handbook":"","hbref":""},{"q":"The three components of the Pennsylvania CDL skills test are the pre-trip (vehicle) inspection, the on-road driving test, and which third component?","options":["A written defensive-driving examination","Basic vehicle control (off-the-road maneuvers and parking)","A timed brake-reaction reflex test","A coupling-and-uncoupling lab simulation"],"answer":1,"explanation":"Pennsylvania's CDL skills test has three parts: pre-trip inspection, basic vehicle control (off-the-road maneuvers and vehicle parking exercise), and the on-road driving test. Source: PennDOT CDL Fact Sheet, \"Skills Tests\" section (pa.gov).","handbook":"","hbref":""},{"q":"Which federal training requirement must a Pennsylvania applicant complete before being allowed to take the CDL skills test for a first-time Class A or Class B license?","options":["A PennDOT-administered classroom defensive driving course","Entry-Level Driver Training (ELDT) from a registered provider","A 40-hour OSHA safety course","A state-issued apprenticeship completion certificate"],"answer":1,"explanation":"Entry-Level Driver Training (ELDT) from a provider on the FMCSA Training Provider Registry must be completed before taking the skills test for an initial Class A or B CDL (and for first-time P, S, or H endorsements). Source: PennDOT CDL Fact Sheet (pa.gov) and FMCSA ELDT rule (49 CFR Part 380).","handbook":"","hbref":""},{"q":"According to the PennDOT CDL Fact Sheet, how many questions are on the Class A general knowledge written test in Pennsylvania?","options":["50 questions","30 questions","70 questions","100 questions"],"answer":2,"explanation":"PennDOT's CDL Fact Sheet lists the Class A written knowledge test as 70 questions, while Class B and Class C are each 50 questions. Source: PennDOT CDL Fact Sheet, \"What Tests Do I Need to Take?\" (pa.gov).","handbook":"","hbref":""},{"q":"How many questions are on the Pennsylvania Hazardous Materials (HazMat) endorsement knowledge test, and in what language is it offered?","options":["25 questions, English only","30 questions, English only","50 questions, multiple languages","20 questions, multiple languages"],"answer":1,"explanation":"PennDOT lists the HazMat endorsement knowledge test as 30 questions, and the HazMat test is offered in English only (other CDL knowledge tests are available in multiple languages). Source: PennDOT CDL Fact Sheet (pa.gov).","handbook":"","hbref":""},{"q":"Per the PennDOT CDL Fact Sheet, how soon after passing the knowledge test and being issued a permit can a Pennsylvania applicant take the skills test?","options":["Not until 15 days after the knowledge test is passed and the permit is issued","Not until 30 days after the permit is issued","Not until 60 days after the permit is issued","Immediately after passing the knowledge test"],"answer":0,"explanation":"PennDOT states that skills testing cannot be taken until 15 days after the knowledge testing is passed and a permit is issued (an applicant may schedule the skills test immediately, but cannot sit it before the 15-day point). Source: PennDOT CDL Fact Sheet, \"Skills Tests\" note (pa.gov).","handbook":"","hbref":""},{"q":"What is the standard validity period of a Pennsylvania commercial driver's license before it must be renewed (for a driver under 65)?","options":["5 years","8 years","2 years","4 years"],"answer":3,"explanation":"A Pennsylvania CDL is generally valid for 4 years; drivers age 65 and older are issued on a 2-year cycle. Source: PennDOT Driver and Vehicle Services licensing information (pa.gov).","handbook":"","hbref":""},{"q":"How long is a Pennsylvania CDL issued to a driver who is 65 years of age or older?","options":["4 years","2 years","3 years","1 year"],"answer":1,"explanation":"While the standard Pennsylvania CDL cycle is 4 years, drivers 65 and older are placed on a 2-year renewal cycle. Source: PennDOT Driver and Vehicle Services licensing information (pa.gov).","handbook":"","hbref":""},{"q":"If a Pennsylvania non-excepted CDL holder lets their Medical Examiner's Certificate expire and does not provide a new one, what happens to their license?","options":["The commercial (CDL) designation is downgraded to a non-commercial license","A $500 civil penalty is assessed but the CDL remains valid","The license is permanently revoked and cannot be reinstated","Nothing changes until the next 4-year renewal"],"answer":0,"explanation":"If a non-excepted driver's medical certification lapses, PennDOT removes the commercial designation and downgrades the credential to a non-commercial driver's license; the driver must reapply for a CLP to regain commercial privileges. Source: PennDOT Self-Certification/Medical Examiner's Certification FAQs (pa.gov).","handbook":"","hbref":""},{"q":"In Pennsylvania, which document is used to apply for the Commercial Learner's Permit itself?","options":["Form MV-1, the vehicle title application","Form DL-180, the non-commercial learner's permit application","Form DL-11CD, the Self-Certification Form","Form DL-31CD, the Commercial Learner's Permit Application"],"answer":3,"explanation":"The Commercial Learner's Permit Application is Form DL-31CD. Form DL-11CD is the separate self-certification form, and a CLP applicant typically submits both. Source: PennDOT CDL Learner's Permit FAQs (pa.gov).","handbook":"","hbref":""},{"q":"Under PennDOT rules, once a Pennsylvania CDL applicant begins the process, how long do they have to pass all required knowledge and skills tests before having to restart?","options":["Six months","90 days","One year","Two years"],"answer":2,"explanation":"PennDOT gives the applicant one year to pass all knowledge and skills tests to obtain the CDL; the permit may be extended with a new DL-31CD application if testing is not completed in time. Source: PennDOT CDL Learner's Permit FAQs (pa.gov).","handbook":"","hbref":""},{"q":"A driver wants a Class C CDL solely to operate a 20-passenger vehicle. According to the PennDOT CDL Fact Sheet, what must a Class C CDL include?","options":["An S, P, or H endorsement","No endorsement of any kind","A double/triple-trailer endorsement","An air-brake restriction code only"],"answer":0,"explanation":"PennDOT defines Class C as single vehicles under 26,001 lbs that transport hazmat requiring placarding, carry 16+ passengers, or are school buses; the Fact Sheet states a Class C CDL must include an S, P, or H endorsement. Source: PennDOT CDL Fact Sheet, license classes (pa.gov).","handbook":"","hbref":""},{"q":"Per the PennDOT CDL Fact Sheet, which endorsement separately requires Entry-Level Driver Training for the first time it is obtained?","options":["The Hazardous Materials (H) endorsement","The Doubles/Triples (T) endorsement","The Tank Vehicle (N) endorsement","The air-brake restriction removal"],"answer":0,"explanation":"PennDOT's Fact Sheet shows ELDT is required (for initial only) for the Passenger, School Bus, and Hazardous Materials (H) endorsements; the Doubles/Triples and Tank endorsements are listed as not requiring ELDT. Source: PennDOT CDL Fact Sheet endorsement/testing table (pa.gov).","handbook":"","hbref":""},{"q":"When a Pennsylvania applicant reports for the CDL skills test, what vehicle must they bring?","options":["Any passenger car with a valid registration","A PennDOT-owned test vehicle assigned at the center","A vehicle one class smaller than the CDL being sought","A representative vehicle of the class and type they intend to drive"],"answer":3,"explanation":"The skills test must be taken in a vehicle of the class and type the applicant intends to drive (for example, a school bus endorsement skills test must be taken in a school bus). Source: PennDOT CDL Fact Sheet, \"Skills Tests\" section (pa.gov).","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная общая наружная ширина транспортного средства, включая любой груз, на автомагистралях Пенсильвании?","options":["8 футов 6 дюймов","8 футов 0 дюймов","9 футов 0 дюймов","10 футов 0 дюймов"],"explanation":"Согласно 75 Pa.C.S. § 4921 (Ширина транспортных средств), общая наружная ширина транспортного средства, включая любой груз, не может превышать 8 футов 6 дюймов. На странице PennDOT Driver and Vehicle Services «Size and Weight Limitations» указана та же величина."},"1":{"q":"Какова максимальная высота транспортного средства, включая любой груз, обычно разрешённая на автомагистралях Пенсильвании?","options":["13 футов 6 дюймов","13 футов 0 дюймов","14 футов 0 дюймов","12 футов 6 дюймов"],"explanation":"Согласно 75 Pa.C.S. § 4922 (Высота транспортных средств), ни одно транспортное средство, включая его груз, не может превышать высоту 13 футов 6 дюймов. Это подтверждено на странице PennDOT «Size and Weight Limitations»."},"2":{"q":"Какова максимальная общая длина одиночного (отдельного) автомобиля, включая груз и бамперы, на автомагистралях Пенсильвании?","options":["40 футов","45 футов","53 фута","35 футов"],"explanation":"Согласно 75 Pa.C.S. § 4923 (Длина транспортных средств), одиночный автомобиль, включая любой груз и бамперы, не может превышать в общей сложности 40 футов. Для особых типов транспортных средств (автобусы, дома на колёсах, транспортные средства со стрелой) установлены отдельные, более высокие пределы."},"3":{"q":"Каков максимальный полный вес любого одиночного транспортного средства или автопоезда на автомагистралях Пенсильвании согласно Транспортному кодексу (Vehicle Code)?","options":["80,000 фунтов","73,280 фунтов","90,000 фунтов","100,000 фунтов"],"explanation":"Согласно 75 Pa.C.S. § 4941 и как указано на странице PennDOT «Size and Weight Limitations», максимальный полный вес любого отдельного транспортного средства или любого автопоезда составляет 80,000 фунтов, при условии также соблюдения пределов зарегистрированного веса и веса на оси."},"4":{"q":"Какова максимальная длина одиночного полуприцепа в составе автопоезда «тягач-полуприцеп», эксплуатируемого в Пенсильвании?","options":["53 фута","48 футов","57 футов","40 футов"],"explanation":"Пенсильвания допускает одиночный прицеп в составе автопоезда «тягач-полуприцеп» длиной до 53 футов при условии, что расстояние от шкворня до задней оси не превышает 41 фут. Это отражено в 75 Pa.C.S. Chapter 49 и на странице PennDOT «Size and Weight Limitations»."},"5":{"q":"В составе автопоезда с двумя прицепами (сдвоенный состав) в Пенсильвании какова максимальная длина каждого прицепа?","options":["28 футов 6 дюймов","28 футов 0 дюймов","33 фута 0 дюймов","30 футов 0 дюймов"],"explanation":"На странице PennDOT «Size and Weight Limitations» указано, что в составе автопоезда с двумя прицепами каждый прицеп ограничен 28 футами 6 дюймами, что соответствует положениям о длине 75 Pa.C.S. Chapter 49."},"6":{"q":"На системе межштатных автомагистралей (Interstate) Пенсильвании каков максимальный полный вес транспортного средства, даже когда федеральная мостовая формула в иных случаях допускала бы больше?","options":["80,000 фунтов","85,500 фунтов","90,000 фунтов","73,280 фунтов"],"explanation":"Пенсильвания следует федеральному стандарту: в системе межштатных автомагистралей (Interstate) полный вес транспортного средства ограничен 80,000 фунтов, даже если результат федеральной мостовой формулы (Federal Bridge Formula) выше. Этот федеральный предел применяется к межштатным автомагистралям Пенсильвании согласно 23 U.S.C. § 127 и 75 Pa.C.S. § 4941."},"7":{"q":"Каков максимальный вес, допустимый на одиночной оси (кроме рулевой оси) для тяжёлого автопоезда в Пенсильвании?","options":["20,000 фунтов","18,000 фунтов","22,400 фунтов","34,000 фунтов"],"explanation":"Согласно 75 Pa.C.S. § 4943 (и федеральному стандарту, которому следует Пенсильвания), максимальный вес на одиночной оси составляет 20,000 фунтов. Это соответствует федеральному пределу для одиночной оси, применяемому в системе межштатных автомагистралей (Interstate)."},"8":{"q":"Согласно федеральному стандарту веса, который применяет Пенсильвания, каков максимальный вес на сдвоенной оси (группе из двух последовательных осей)?","options":["34,000 фунтов","36,000 фунтов","40,000 фунтов","20,000 фунтов"],"explanation":"Пенсильвания применяет федеральный предел для сдвоенной оси в 34,000 фунтов. 75 Pa.C.S. § 4943 допускает, чтобы две последовательные пары осей несли по 34,000 фунтов каждая, когда расстояние между первой и последней осями этих пар составляет 36 футов или более."},"9":{"q":"Каково основное назначение федеральной мостовой формулы (Federal Bridge Formula) в её применении в Пенсильвании?","options":["Ограничивать вес на группах осей, чтобы снизить риск повреждения автодорожных мостов","Устанавливать максимальную высоту грузов, проходящих под мостами","Рассчитывать плату за проезд по платной дороге Pennsylvania Turnpike","Определять минимальную дистанцию следования для тяжёлых грузовиков"],"explanation":"Федеральная мостовая формула (Bridge Gross Weight Formula) ограничивает допустимый вес на любой группе последовательных осей в зависимости от числа осей и расстояния между ними, чтобы защитить мосты. Она применяется к системе межштатных автомагистралей (Interstate) Пенсильвании согласно 23 U.S.C. § 127."},"10":{"q":"Когда требуется разрешение PennDOT на перевозку (hauling permit) для эксплуатации транспортного средства в Пенсильвании?","options":["Когда транспортное средство или груз превышает законные пределы размеров или веса, установленные Транспортным кодексом (Vehicle Code)","Только при пересечении границы в другой штат","Всякий раз при перевозке любого коммерческого груза","Только когда у водителя нет CDL"],"explanation":"Согласно странице PennDOT «Size and Weight Limitations», транспортное средство может эксплуатироваться вне законных пределов размеров/веса только при наличии разрешения от PennDOT. Разрешения на перевозку негабаритных/сверхтяжёлых грузов санкционируют движение, превышающее пределы, установленные в 75 Pa.C.S. Chapter 49."},"11":{"q":"Через какую систему PennDOT в основном подаются заявки и выдаются специальные разрешения на перевозку негабаритных/сверхтяжёлых грузов в Пенсильвании?","options":["APRAS (Automated Permit Routing and Analysis System)","CDLIS (Commercial Driver License Information System)","Портал IRP (International Registration Plan)","SAFER (Safety and Fitness Electronic Records)"],"explanation":"PennDOT выдаёт специальные разрешения на перевозку негабаритных/сверхтяжёлых грузов через APRAS, Automated Permit Routing and Analysis System, которая обрабатывает сотни тысяч разрешений ежегодно, многие из них автоматически. Источник: PennDOT APRAS / Apply for a PennDOT Hauling Permit."},"12":{"q":"Транспортное средство с грузом, превышающее какую ширину, считается негабаритным и требует разрешения PennDOT?","options":["Более 8 футов 6 дюймов","Более 8 футов 0 дюймов","Более 9 футов 0 дюймов","Более 10 футов 0 дюймов"],"explanation":"Поскольку законная ширина согласно 75 Pa.C.S. § 4921 составляет 8 футов 6 дюймов, любое транспортное средство с грузом шире 8 футов 6 дюймов является негабаритным и требует разрешения PennDOT на перевозку. Источник: рекомендации PennDOT по разрешениям на перевозку / Load Type."},"13":{"q":"Груз выше какой высоты считается негабаритным и требует разрешения PennDOT?","options":["Более 13 футов 6 дюймов","Более 13 футов 0 дюймов","Более 14 футов 0 дюймов","Более 12 футов 6 дюймов"],"explanation":"Поскольку законный предел высоты согласно 75 Pa.C.S. § 4922 составляет 13 футов 6 дюймов, груз, превышающий 13 футов 6 дюймов, является негабаритным и требует разрешения PennDOT на перевозку. Источник: PennDOT «Size and Weight Limitations» / рекомендации по разрешениям на перевозку."},"14":{"q":"Каков максимальный допустимый вес на рулевой оси, прежде чем транспортное средство будет считаться перегруженным в Пенсильвании?","options":["20,000 фунтов","12,000 фунтов","18,000 фунтов","22,400 фунтов"],"explanation":"Согласно рекомендациям PennDOT по разрешениям в рамках 75 Pa.C.S. § 4943, транспортное средство считается перегруженным, если вес на рулевой оси превышает 20,000 фунтов. Свыше этого требуется разрешение PennDOT на перевозку сверхтяжёлого груза (overweight permit)."},"15":{"q":"В рамках ежегодного пенсильванского разрешения на «движение в ходе производства» (75 Pa.C.S. § 4968) какой необработанный лесопродукт может перевозиться сверх максимального веса?","options":["Балансовая древесина и древесная щепа","Готовая мебель","Фасованная мульча для розничной продажи","Строительный пиломатериал розничному дилеру"],"explanation":"75 Pa.C.S. § 4968 разрешает перевозку по ежегодному разрешению сверх максимального веса для таких товаров, как сырое молоко, необработанный уголь, балансовая древесина и древесная щепа, пока они находятся в процессе производства и под контролем производителя. Разрешение не выдаётся для товаров, следующих к покупателю или дилеру."},"16":{"q":"На платной дороге Pennsylvania Turnpike определённые грузы, перевозимые по разрешению, могут превышать общий предел в 80,000 фунтов до какого максимального полного веса?","options":["100,000 фунтов","80,000 фунтов","90,000 фунтов","120,000 фунтов"],"explanation":"Платная дорога Pennsylvania Turnpike устанавливает собственные пределы для коммерческих разрешений, допуская разрешённый полный вес до 100,000 фунтов (с весом на оси до 22,400 фунтов). Источник: PA Turnpike Commercial Permits and Restrictions. Автомагистрали PennDOT остаются ограничены 80,000 фунтов (lb)."},"17":{"q":"Согласно 75 Pa.C.S. § 4943, каков максимальный вес на паре осей, расположенных на расстоянии более 8 футов друг от друга, для тяжёлого автопоезда?","options":["22,400 фунтов каждая","18,000 фунтов каждая","20,000 фунтов каждая","34,000 фунтов каждая"],"explanation":"Согласно правилам о расстоянии между осями в 75 Pa.C.S. § 4943, оси, расположенные на расстоянии более 8 футов друг от друга, могут нести до 22,400 фунтов каждая, тогда как оси на расстоянии менее 6 футов друг от друга ограничены 18,000 фунтов каждая."},"18":{"q":"Почему федеральная мостовая формула (Federal Bridge Formula) иногда ограничивает грузовик весом МЕНЬШЕ 80,000 фунтов, даже когда ни одна группа осей не перегружена?","options":["Потому что близко расположенные группы осей концентрируют вес, поэтому формула снижает допустимый полный вес для защиты мостов","Потому что рулевая ось всегда исключается из полного веса","Потому что Пенсильвания ограничивает все грузовики весом в 73,280 фунтов","Потому что плата за проезд растёт с увеличением расстояния между осями"],"explanation":"Федеральная мостовая формула связывает допустимый вес с числом осей и охватываемым расстоянием. Когда оси расположены близко друг к другу, формула даёт значение ниже 80,000 фунтов, чтобы ограничить нагрузку на пролёты мостов. Пенсильвания применяет это в системе межштатных автомагистралей (Interstate) согласно 23 U.S.C. § 127."},"19":{"q":"Как должна оформляться перевозка негабаритного/сверхтяжёлого груза, превышающая наибольшие стандартные пороги разрешений в Пенсильвании (так называемый «superload»)?","options":["Подаваться через APRAS для рассмотрения, что зачастую требует ручного анализа и прокладки маршрута до утверждения","Перевозиться без разрешения, если движение осуществляется ночью","Утверждаться автоматически в любом фотолицензионном центре PennDOT","Освобождаться от любой прокладки маршрута, поскольку оплачивается более высокая плата за проезд"],"explanation":"Заявки на superload должны подаваться через систему PennDOT APRAS; в то время как большинство рутинных разрешений утверждается автоматически примерно за минуту, superload-грузы и приблизительно каждая пятая заявка требуют ручного рассмотрения и анализа маршрута. Источник: PennDOT APRAS."},"20":{"q":"В Пенсильвании какой класс CDL требуется для управления автопоездом с полной разрешённой массой автопоезда (GCWR) 26,001 фунт или более, когда буксируемое транспортное средство имеет GVWR, превышающую 10,000 фунтов?","options":["Class A","Class B","Class C","Class D"],"explanation":"Согласно информационному листку PennDOT Commercial Driver's License Fact Sheet (June 2025) и PUB 223, Class A CDL охватывает автопоезд с GCWR 26,001 фунт или более при условии, что GVWR буксируемого транспортного средства превышает 10,000 фунтов. Источник: PennDOT CDL Fact Sheet / Commercial Driver's Manual (PUB 223)."},"21":{"q":"Согласно правилам CDL Пенсильвании, одиночное транспортное средство с полной разрешённой массой (GVWR) 26,001 фунт или более (или такое транспортное средство, буксирующее единицу не более 10,000 фунтов) требует какого класса прав?","options":["Class A","Class B","Class C","Class M"],"explanation":"PennDOT определяет Class B как одиночное транспортное средство с GVWR 26,001 фунт или более, или любое такое транспортное средство, буксирующее транспортное средство не более 10,000 фунтов. Источник: PennDOT CDL Fact Sheet (June 2025) / PUB 223."},"22":{"q":"Согласно PennDOT, пенсильванские права Class C CDL используются для одиночного транспортного средства с GVWR менее 26,001 фунта, которое перевозит опасные материалы с табличками (placarded), перевозит 16 или более человек либо является школьным автобусом. Что также должны включать права Class C CDL?","options":["Подтверждение (endorsement) S, P или H","Подтверждение для мотоцикла (M)","Сертификацию по пневматическим тормозам Class A","Освобождение для сельскохозяйственного транспортного средства"],"explanation":"В PennDOT CDL Fact Sheet указано, что Class C CDL охватывает одиночные транспортные средства с GVWR менее 26,001 lbs, которые перевозят опасные материалы с табличками (placarded hazmat), рассчитаны на перевозку 16+ человек, включая водителя, либо являются школьным автобусом, и что Class C CDL должны включать подтверждение S, P или H. Источник: PennDOT CDL Fact Sheet (June 2025)."},"23":{"q":"В Пенсильвании что разрешает держателю CDL подтверждение (endorsement) «N»?","options":["Управлять автоцистернами","Управлять сдвоенными и строенными прицепами","Перевозить пассажиров в автобусе","Перевозить опасные материалы с табличками (placarded)"],"explanation":"PennDOT указывает, что подтверждение N разрешает водителю управлять автоцистернами. (Подтверждение T — для сдвоенных/строенных прицепов, P — для пассажиров, а H — для опасных материалов с табличками.) Источник: PennDOT CDL Fact Sheet (June 2025) / PUB 223."},"24":{"q":"Какое подтверждение (endorsement) CDL в Пенсильвании требуется для управления сдвоенными и строенными прицепами?","options":["Подтверждение T","Подтверждение N","Подтверждение X","Подтверждение H"],"explanation":"PennDOT указывает, что подтверждение T разрешает управление сдвоенными и строенными прицепами. Источник: PennDOT CDL Fact Sheet (June 2025) / PUB 223."},"25":{"q":"Что представляет собой объединённое подтверждение (endorsement) «X» в пенсильванских правах CDL?","options":["И опасные материалы, и автоцистерны (H и N)","И пассажирское, и школьный автобус (P и S)","И сдвоенные/строенные, и автоцистерны (T и N)","Истёкшее подтверждение, ожидающее продления"],"explanation":"PennDOT перечисляет подтверждение X как объединённое подтверждение для опасных материалов и автоцистерн (H,N). Источник: PennDOT CDL Fact Sheet (June 2025)."},"26":{"q":"Каков минимальный возраст для получения пенсильванских прав CDL для вождения внутри штата (управление коммерческим транспортным средством только в пределах Пенсильвании)?","options":["18 лет","16 лет","19 лет","21 год"],"explanation":"Пенсильвания требует минимального возраста 18 лет для владения CDL для коммерческого вождения внутри штата (только в пределах штата). Источник: PennDOT Driver and Vehicle Services, Commercial Drivers / License Types & Restrictions."},"27":{"q":"Каков минимальный возраст, требуемый для управления коммерческим транспортным средством в межштатной торговле (через границы штатов) с пенсильванскими правами CDL?","options":["21 год","18 лет","19 лет","25 лет"],"explanation":"Для управления CMV в межштатной торговле водитель должен быть не моложе 21 года. Водители 18-20 лет могут управлять только внутри штата в пределах Пенсильвании. Источник: PennDOT Commercial Drivers / 49 CFR 391.11 в применении в Пенсильвании."},"28":{"q":"После сдачи требуемого теста на знания и выдачи пенсильванского коммерческого ученического разрешения (commercial learner's permit), каков минимальный период ожидания, прежде чем можно назначить экзамен по навыкам (skills test) для Class A, B или C?","options":["15 дней","10 дней","30 дней","7 дней"],"explanation":"Согласно PennDOT, экзамен по навыкам нельзя сдавать до истечения 15 дней после сдачи теста на знания и выдачи разрешения. Это удовлетворяет федеральному требованию о 14-дневном удержании CLP. Источник: PennDOT CDL Fact Sheet (June 2025) и CDL Learner's Permit FAQs."},"29":{"q":"Пенсильванское разрешение на тест на знания (Knowledge Test Authorization, KTA) / коммерческое ученическое разрешение действительно в течение какого срока, давая заявителю время сдать все тесты на знания и навыки?","options":["Один год со дня выдачи","90 дней со дня выдачи","Шесть месяцев со дня выдачи","Два года со дня выдачи"],"explanation":"PennDOT указывает, что KTA действительно в течение одного года со дня выдачи, и у заявителей есть один год, чтобы сдать все тесты на знания и навыки для получения CDL. Источник: PennDOT CDL Learner's Permit FAQs."},"30":{"q":"Каждый, кто подаёт заявление на пенсильванское коммерческое ученическое разрешение или владеет CDL, должен заполнить какой документ, определяющий тип выполняемых им коммерческих перевозок?","options":["Форму самосертификации (Self-Certification Form, DL-11CD)","Форму отказа от REAL ID","Форму пропорциональной регистрации IRP","Форму I-9 о разрешении на трудоустройство"],"explanation":"PennDOT требует от каждого держателя CDL и каждого заявителя на CLP подать форму самосертификации (Self-Certification Form, DL-11CD), определяющую их тип вождения. Источник: PennDOT CDL Fact Sheet (June 2025) и Self-Certification/Medical Examiner FAQs."},"31":{"q":"Что из перечисленного является одной из четырёх категорий медицинской самосертификации, из которых должен выбрать заявитель на CDL в Пенсильвании?","options":["Non-excepted Interstate","Excepted Out-of-State","Placarded Interstate","Restricted Intrastate"],"explanation":"Четыре категории самосертификации — это Non-excepted Interstate, Non-excepted Intrastate, Excepted Interstate и Excepted Intrastate. Водитель категории Non-excepted Interstate должен иметь действительный сертификат медицинского эксперта (Medical Examiner's Certificate) в реестре PennDOT. Источник: PennDOT Self-Certification/Medical Examiner FAQs."},"32":{"q":"Водитель в Пенсильвании, который самосертифицируется как «Non-excepted Intrastate», подпадает под федеральные стандарты физической пригодности при вождении только в пределах штата. Какое ограничение прав добавляет PennDOT в этом случае?","options":["Ограничение «K» (только внутриштатная торговля)","Ограничение «L» (без пневматических тормозов)","Ограничение «E» (без механической коробки передач)","Ограничение «O» (без сцепки с седельно-сцепным устройством)"],"explanation":"PennDOT применяет ограничение K, ограничивающее водителя только внутриштатной торговлей. Ограничение K появляется для коммерческой деятельности только внутри штата. Источник: PennDOT CDL Fact Sheet (June 2025) и Self-Certification FAQs."},"33":{"q":"С 7 февраля 2022 года обучение водителей начального уровня (Entry-Level Driver Training, ELDT) требуется в Пенсильвании для впервые обращающихся заявителей на какой(ие) документ(ы)?","options":["Первые права Class A или B CDL, либо первое подтверждение P, S или H","Любое продление CDL независимо от класса","Только подтверждение HazMat (H)","Только внутриштатные права Class C CDL"],"explanation":"Согласно правилам FMCSA, принятым PennDOT, ELDT (вступившее в силу 7 февраля 2022 года) применяется при получении прав Class A или B CDL впервые, при повышении до Class A или B либо при получении подтверждения P, S или H впервые. Оно не имеет обратной силы. Источник: PennDOT Entry Level Driver Training page / 49 CFR Part 380."},"34":{"q":"Где водитель начального уровня в Пенсильвании должен пройти требуемое обучение ELDT перед сдачей экзамена по навыкам?","options":["У провайдера, внесённого в реестр провайдеров обучения FMCSA (Training Provider Registry, TPR)","В любом центре выдачи водительских прав PennDOT","По неформальной программе обучения на рабочем месте у работодателя","В любой автошколе, аффилированной с AAA"],"explanation":"PennDOT требует прохождения ELDT у провайдера, внесённого в реестр провайдеров обучения FMCSA (tpr.fmcsa.dot.gov), перед экзаменом по навыкам. Источник: PennDOT CDL Fact Sheet (June 2025) / Entry Level Driver Training page."},"35":{"q":"Чтобы получить пенсильванское подтверждение HazMat (H), заявитель должен сдать тест на знания и пройти какую федеральную проверку благонадёжности?","options":["Оценку угрозы безопасности TSA (Security Threat Assessment) с дактилоскопией","Проверку трудоустройства E-Verify","Проверку водительского досье только силами PennDOT","Медицинскую сертификацию FAA"],"explanation":"PennDOT требует от заявителей на HazMat пройти федеральную оценку угрозы безопасности Управления транспортной безопасности (TSA Security Threat Assessment), включая дактилоскопию (Form DL-288, PUB 512). PennDOT должен получить федеральное одобрение перед выдачей подтверждения H. Источник: PennDOT Hazardous Materials Endorsement Fact Sheet (FS-HM) and FAQs."},"36":{"q":"На официальных тестах PennDOT на знания для CDL сколько вопросов содержится в тесте на подтверждение для опасных материалов (Hazardous Materials, H)?","options":["30 вопросов","20 вопросов","25 вопросов","50 вопросов"],"explanation":"PennDOT указывает, что тест на знания для подтверждения для опасных материалов (Hazardous Materials Endorsement) состоит из 30 вопросов, и тест HazMat предлагается только на английском языке. Источник: PennDOT CDL Fact Sheet (June 2025)."},"37":{"q":"Прежде чем получить пенсильванское подтверждение для школьного автобуса (School Bus, S), какое подтверждение водитель также должен иметь?","options":["Подтверждение для пассажиров (Passenger, P)","Подтверждение для автоцистерн (Tank, N)","Подтверждение для сдвоенных/строенных прицепов (Doubles/Triples, T)","Подтверждение HazMat (H)"],"explanation":"PennDOT требует подтверждение для пассажиров (Passenger, P) в качестве предварительного условия для подтверждения для школьного автобуса (School Bus, S); тест на знания для S требует наличия пассажирского подтверждения. Источник: PennDOT CDL Fact Sheet (June 2025) / School Transportation FAQs."},"38":{"q":"Какое утверждение о карточке пенсильванского подтверждения для школьного автобуса (School Bus, S) верно согласно PennDOT?","options":["Карточка подтверждения для школьного автобуса выдаётся ежегодно","Подтверждение S никогда не требует продления","Подтверждение S выдаётся только раз в восемь лет","Карточка подтверждения S высылается TSA"],"explanation":"PennDOT CDL Fact Sheet отмечает, что подтверждение S разрешает управление школьным автобусом и что карточка подтверждения для школьного автобуса выдаётся ежегодно. Источник: PennDOT CDL Fact Sheet (June 2025)."},"39":{"q":"При личной подаче заявления на пенсильванские права CDL/CLP заявитель, как правило, должен предоставить подтверждение личности и законного статуса, подтверждение номера социального страхования (Social Security number) и сколько подтверждений проживания в Пенсильвании?","options":["Два подтверждения проживания в Пенсильвании","Одно подтверждение проживания в Пенсильвании","Три подтверждения проживания в Пенсильвании","Подтверждение проживания не требуется"],"explanation":"PennDOT требует один документ, подтверждающий личность/законный статус, один документ, подтверждающий номер социального страхования (Social Security number), и два документа, подтверждающих проживание в Пенсильвании. Источник: требования PennDOT Proof of Identity and Residency (PUB 195US)."},"40":{"q":"В Пенсильвании каков максимальный уровень концентрации алкоголя в крови (BAC), при котором (или выше которого) водитель считается управляющим коммерческим транспортным средством (CMV) в состоянии опьянения?","options":["0.02 процента","0.04 процента","0.08 процента","0.10 процента"],"explanation":"Пенсильвания запрещает управление CMV с BAC 0.04 процента или выше, что составляет половину предела в 0.08 процента для некоммерческих водителей. Источник: PA CDL Manual; 75 Pa.C.S. и 49 CFR 383.51."},"41":{"q":"Согласно правилам подразумеваемого согласия (implied consent) Пенсильвании, что происходит с водителем CMV, который отказывается пройти химическое тестирование после надлежащего предупреждения сотрудника?","options":["Только письменное предупреждение без дисквалификации","30-дневная дисквалификация CDL","1-летняя дисквалификация CDL, рассматриваемая как осуждение за DUI","6-месячная дисквалификация CDL"],"explanation":"Водитель CMV, который отказывается от химического тестирования, дисквалифицируется не менее чем на 1 год, так же как при осуждении за тяжкое правонарушение. Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51."},"42":{"q":"В Пенсильвании первое тяжкое правонарушение (например, управление CMV с BAC 0.04 процента или выше) приводит к дисквалификации CDL на срок не менее какого?","options":["60 дней","6 месяцев","1 год","3 года"],"explanation":"Первое тяжкое правонарушение дисквалифицирует держателя CDL в Пенсильвании минимум на 1 год. Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51."},"43":{"q":"В Пенсильвании, если водитель совершает первое тяжкое правонарушение во время управления CMV, на котором установлены таблички (placarded) для опасных материалов, срок дисквалификации увеличивается до:","options":["1 год","2 года","3 года","5 лет"],"explanation":"Первое тяжкое правонарушение, совершённое при перевозке опасных материалов с табличками (placarded), повышает дисквалификацию с 1 года до 3 лет. Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51."},"44":{"q":"Каков срок дисквалификации CDL в Пенсильвании за второе тяжкое правонарушение (например, второе DUI на CMV)?","options":["3 года","5 лет","10 лет","Пожизненно"],"explanation":"Два тяжких правонарушения на любом транспортном средстве приводят к пожизненной дисквалификации CDL в Пенсильвании. Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51."},"45":{"q":"В Пенсильвании осуждение за ДВА серьёзных нарушения правил дорожного движения в отдельных инцидентах в течение 3-летнего периода приводит к дисквалификации CDL на:","options":["30 дней","60 дней","120 дней","1 год"],"explanation":"Два серьёзных нарушения правил дорожного движения в течение 3 лет дисквалифицируют держателя CDL в Пенсильвании на 60 дней. Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51."},"46":{"q":"В Пенсильвании осуждение за ТРИ серьёзных нарушения правил дорожного движения в отдельных инцидентах в течение 3-летнего периода приводит к дисквалификации CDL на:","options":["60 дней","90 дней","120 дней","1 год"],"explanation":"Три серьёзных нарушения правил дорожного движения в течение 3 лет дисквалифицируют держателя CDL в Пенсильвании на 120 дней, отбываемых последовательно после любой 60-дневной дисквалификации. Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51."},"47":{"q":"Что из перечисленного классифицируется как СЕРЬЁЗНОЕ нарушение правил дорожного движения для держателя CDL в Пенсильвании?","options":["Перегоревший задний фонарь","Превышение скорости на 15 mph или более","Парковка в зоне запрета остановки","Вождение с просроченной регистрацией"],"explanation":"Превышение скорости на 15 mph или более над пределом является серьёзным нарушением правил дорожного движения; к другим относятся неосторожное вождение, неправильная смена полосы, слишком близкое следование, переписка в сообщениях и использование телефона в руке. Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51."},"48":{"q":"Для водителя CDL в Пенсильвании какова дисквалификация за ПЕРВОЕ осуждение за нарушение закона о железнодорожном переезде в одном уровне (railroad-highway grade crossing)?","options":["30 дней","60 дней","120 дней","1 год"],"explanation":"Первое нарушение на железнодорожном переезде в одном уровне дисквалифицирует держателя CDL в Пенсильвании на 60 дней. Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51."},"49":{"q":"Для водителя CDL в Пенсильвании ВТОРОЕ нарушение на железнодорожном переезде в одном уровне (railroad-highway grade crossing) в течение 3-летнего периода приводит к дисквалификации на:","options":["60 дней","120 дней","1 год","3 года"],"explanation":"Второе нарушение на железнодорожном переезде в одном уровне в течение 3 лет дисквалифицирует держателя CDL в Пенсильвании на 120 дней. Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51."},"50":{"q":"Для водителя CDL в Пенсильвании ТРЕТЬЕ или последующее нарушение на железнодорожном переезде в одном уровне (railroad-highway grade crossing) в течение 3-летнего периода приводит к дисквалификации на:","options":["120 дней","180 дней","1 год","3 года"],"explanation":"Третье или последующее нарушение на железнодорожном переезде в одном уровне в течение 3 лет дисквалифицирует держателя CDL в Пенсильвании на 1 год. Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51."},"51":{"q":"В Пенсильвании ПЕРВОЕ осуждение за нарушение предписания о выводе из эксплуатации (out-of-service, OOS) при перевозке НЕопасных материалов дисквалифицирует водителя CDL на:","options":["90 дней","180 дней","1 год","2 года"],"explanation":"Первое нарушение предписания о выводе из эксплуатации (не-hazmat) дисквалифицирует держателя CDL в Пенсильвании не менее чем на 1 год. Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51."},"52":{"q":"В Пенсильвании ВТОРОЕ нарушение предписания о выводе из эксплуатации (out-of-service) в течение 10-летнего периода (не-hazmat) приводит к дисквалификации CDL на:","options":["1 год","2 года","3 года","5 лет"],"explanation":"Второе нарушение предписания о выводе из эксплуатации в течение 10 лет (не-hazmat) дисквалифицирует держателя CDL в Пенсильвании не менее чем на 3 года. Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51."},"53":{"q":"В Пенсильвании ПЕРВОЕ нарушение предписания о выводе из эксплуатации (out-of-service) при перевозке опасных материалов или 16 и более пассажиров дисквалифицирует водителя CDL на:","options":["1 год","2 года","3 года","5 лет"],"explanation":"Первое нарушение предписания о выводе из эксплуатации при перевозке hazmat или 16+ пассажиров дисквалифицирует держателя CDL в Пенсильвании не менее чем на 2 года. Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51."},"54":{"q":"В Пенсильвании ВТОРОЕ нарушение предписания о выводе из эксплуатации (out-of-service) в течение 10 лет при перевозке опасных материалов или 16 и более пассажиров дисквалифицирует водителя CDL на:","options":["2 года","3 года","5 лет","Пожизненно"],"explanation":"Второе нарушение предписания о выводе из эксплуатации в течение 10 лет при перевозке hazmat или 16+ пассажиров дисквалифицирует держателя CDL в Пенсильвании не менее чем на 5 лет. Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51."},"55":{"q":"Для держателя CDL в Пенсильвании использование мобильного телефона в руке во время управления CMV рассматривается как:","options":["Неподотчётное нарушение, связанное с оборудованием","Серьёзное нарушение правил дорожного движения, которое может привести к дисквалификации","Автоматическая 1-летняя дисквалификация при первом правонарушении","Правонарушение, влекущее пожизненную дисквалификацию"],"explanation":"Использование телефона в руке во время управления CMV является серьёзным нарушением правил дорожного движения; два в течение 3 лет вызывают 60-дневную дисквалификацию, а три — 120 дней. Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51 и 392.82."},"56":{"q":"Для держателя CDL в Пенсильвании переписка в сообщениях (texting) во время управления коммерческим транспортным средством является:","options":["Допустимой, если транспортное средство остановлено на светофоре","Серьёзным нарушением правил дорожного движения, которое может привести к дисквалификации","Лишь штрафом парковочного типа без влияния на права","Разрешённой для связи с диспетчером"],"explanation":"Переписка в сообщениях во время управления CMV является серьёзным нарушением правил дорожного движения; их накопление в течение 3 лет приводит к дисквалификации на 60 или 120 дней. Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51 и 392.80."},"57":{"q":"В Пенсильвании какое осуждение влечёт ПОЖИЗНЕННУЮ дисквалификацию CDL БЕЗ возможности восстановления спустя 10 лет?","options":["Второе DUI на CMV","Использование CMV для совершения тяжкого преступления (felony), связанного с производством или распространением контролируемого вещества","Два серьёзных нарушения правил дорожного движения в течение 3 лет","Первое нарушение предписания о выводе из эксплуатации"],"explanation":"Использование CMV в тяжком преступлении (felony), связанном с производством, распространением или сбытом контролируемого вещества, приводит к пожизненной дисквалификации, которая не может быть сокращена. Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51."},"58":{"q":"Водитель CDL в Пенсильвании, осуждённый за тяжкое правонарушение, повлёкшее смертельный исход в результате небрежного или преступного управления CMV, дисквалифицируется на срок не менее:","options":["60 дней","120 дней","1 год","5 лет"],"explanation":"Причинение смертельного исхода в результате небрежного или преступного управления CMV является тяжким правонарушением, влекущим минимальную 1-летнюю дисквалификацию (3 года, если установлены таблички (placarded) для hazmat). Источник: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51."},"59":{"q":"Согласно закону Пенсильвании о школьных автобусах, на каком расстоянии до автобуса со включёнными мигающими красными сигнальными огнями и выдвинутым знаком «Стоп» должен остановиться водитель, движущийся навстречу или обгоняющий автобус?","options":["Не менее 10 feet","Не менее 15 feet","Не менее 20 feet","Не менее 25 feet"],"explanation":"Пенсильвания требует, чтобы водители, движущиеся навстречу школьному автобусу или обгоняющие его, при включённых мигающих красных сигнальных огнях останавливались не менее чем за 10 feet от автобуса и не начинали движение до тех пор, пока огни не перестанут мигать, а знак «Стоп» не будет убран. Источник: 75 Pa.C.S. § 3345 (Встречное движение и обгон школьного автобуса); PA Commercial Driver's Manual (PUB 223)."},"60":{"q":"На автомагистрали Пенсильвании с раздельными проезжими частями, разделёнными физическим барьером или чётко обозначенной разделительной полосой, водитель, находящийся на ПРОТИВОПОЛОЖНОЙ проезжей части по отношению к остановившемуся школьному автобусу с мигающими красными огнями, должен:","options":["Не обязан останавливаться","Остановиться не менее чем за 10 feet от разделительной полосы","Останавливаться только если видны дети","Снизить скорость до 15 mph, но останавливаться не обязан"],"explanation":"Исключение Пенсильвании для разделённых автомагистралей гласит, что водитель на автомагистрали с раздельными проезжими частями не обязан останавливаться для школьного автобуса с мигающими красными огнями, который находится на ДРУГОЙ проезжей части. «Раздельная проезжая часть» требует наличия физического барьера или чётко обозначенной разделительной полосы; одна лишь разметка или знаки её не создают. Источник: 75 Pa.C.S. § 3345."},"61":{"q":"Какой элемент ТРЕБУЕТСЯ для применения в Пенсильвании исключения о «раздельных проезжих частях» для школьных автобусов (чтобы встречный поток не был обязан останавливаться)?","options":["Физический барьер или чётко обозначенная разделительная полоса","Двойная сплошная жёлтая осевая линия","Центральная полоса для левого поворота","Установленный знак «DIVIDED HIGHWAY»"],"explanation":"В Пенсильвании это исключение применяется только там, где проезжие части разделены физическим барьером или чётко обозначенной разделительной полосой. Одна лишь дорожная разметка или знаки НЕ считаются создающими раздельную проезжую часть, поэтому на дорогах, разделённых только разметкой, останавливаться обязаны все направления. Источник: 75 Pa.C.S. § 3345."},"62":{"q":"Транспортное средство, обязанное остановиться на железнодорожном переезде в Пенсильвании, должно остановиться на каком расстоянии от ближайшего рельса?","options":["В пределах 50 feet, но не ближе 15 feet","В пределах 100 feet, но не ближе 25 feet","В пределах 30 feet, но не ближе 10 feet","В пределах 75 feet, но не ближе 20 feet"],"explanation":"Закон Пенсильвании требует, чтобы транспортные средства, обязанные останавливаться на железнодорожных переездах (школьные автобусы, пассажирские автобусы и грузовики, перевозящие определённое топливо/взрывчатые/радиоактивные материалы), останавливались в пределах 50 feet, но не ближе 15 feet от ближайшего рельса, после чего смотрели и слушали. Источник: 75 Pa.C.S. § 3342 (Транспортные средства, обязанные останавливаться на железнодорожных переездах); PA CDL Manual."},"63":{"q":"Какое транспортное средство НЕ обязано останавливаться на каждом железнодорожном переезде согласно закону Пенсильвании?","options":["Пустой тягач с сухогрузным фургоном, не перевозящий опасные материалы","Школьный автобус, независимо от того, везёт он пассажиров или нет","Автобус, перевозящий пассажиров","Грузовик, перевозящий взрывчатые вещества с табличками опасности"],"explanation":"Пенсильвания требует, чтобы школьные автобусы (с пассажирами или пустые), пассажирские автобусы и грузовики, перевозящие бензин, дизельное/печное топливо, взрывчатые или радиоактивные материалы, останавливались на переездах. Обычный пустой грузовой фургон без опасного груза останавливаться не обязан. Источник: 75 Pa.C.S. § 3342."},"64":{"q":"Когда CMV в Пенсильвании, обязанный остановиться, пересекает железнодорожные пути, водителю прямо запрещено делать что именно?","options":["Вручную переключать передачи, находясь на путях","Использовать моторный тормоз","Пересекать на пониженной передаче","Включать аварийную сигнализацию"],"explanation":"Закон Пенсильвании предписывает, чтобы водитель, обязанный остановиться, пересекал пути на такой передаче, при которой не потребуется переключение во время проезда, и не переключал передачи вручную, находясь на пути (путях). Источник: 75 Pa.C.S. § 3342; PA CDL Manual."},"65":{"q":"На железнодорожном переезде в Пенсильвании, обозначенном знаком «EXEMPT», грузовик с опасными материалами с табличками опасности или автобус:","options":["Не обязан останавливаться","Всё равно должен остановиться в пределах 50 feet от рельса","Должен остановиться и подать звуковой сигнал","Должен останавливаться только при наличии шлагбаума"],"explanation":"Пенсильвания освобождает переезды, обозначенные знаком «exempt» (а также заброшенные переезды, обозначенные как таковые), от обязательного правила остановки; сотрудник полиции или регулировщик, пропускающий транспортное средство, либо зелёный сигнал светофора также освобождают от обязанности останавливаться. Источник: 75 Pa.C.S. § 3342."},"66":{"q":"Согласно закону Пенсильвании «Move Over», когда водитель НЕ МОЖЕТ безопасно перестроиться в несмежную полосу вблизи зоны реагирования на чрезвычайные ситуации, водитель вместо этого должен проехать со скоростью не более чем на сколько ниже установленного ограничения?","options":["На 20 mph ниже установленного ограничения скорости","На 10 mph ниже установленного ограничения скорости","На 15 mph ниже установленного ограничения скорости","На 25 mph ниже установленного ограничения скорости"],"explanation":"Закон Пенсильвании «Move Over» (Steer Clear) требует по возможности проезжать по полосе, не смежной с зоной реагирования на чрезвычайные ситуации; если это невозможно, незаконно или небезопасно, водитель должен проехать со скоростью не более чем на 20 mph ниже установленного ограничения и с разумной для безопасности скоростью. Источник: 75 Pa.C.S. § 3327."},"67":{"q":"Закон Пенсильвании «Move Over» (Act 105 of 2020) начисляет сколько штрафных баллов за непеперестроение в полосу, не смежную с зоной реагирования на чрезвычайные ситуации?","options":["2 балла","3 балла","4 балла","5 баллов"],"explanation":"Act 105 of 2020 добавил штраф в 2 балла за непеперестроение, плюс возрастающие денежные штрафы: $500 (за первое нарушение), $1,000 (за второе) и $2,000 с приостановлением действия прав на 90 дней (за третье или последующее). Источник: 75 Pa.C.S. § 3327; кампания PennDOT Move Over."},"68":{"q":"Помимо полиции, пожарных, скорой помощи и эвакуаторов, закон Пенсильвании «Move Over» также защищает что из перечисленного?","options":["Неисправное транспортное средство, отображающее не менее двух аварийных обозначений (например, аварийные огни и сигнальные шашки)","Любое транспортное средство, законно припаркованное на обочине","Только транспортные средства, принадлежащие государству","Транспортные средства, остановившиеся на красный сигнал"],"explanation":"Пенсильвания распространила обязанность по закону «Move Over» на неисправные транспортные средства, отображающие не менее двух аварийных обозначений, таких как аварийные огни, предупреждающие знаки/устройства или сигнальные шашки. Водители должны сменить полосу или снизить скорость не более чем до 20 mph ниже ограничения. Источник: 75 Pa.C.S. § 3327 (обязанность в отношении неисправных транспортных средств)."},"69":{"q":"На автомагистрали Пенсильвании с ограниченным доступом, имеющей три или более полос в одном направлении, где может двигаться грузовой состав весом более 10,000 pounds?","options":["По любой полосе, кроме левой (которая запрещена, за исключением подготовки к разрешённому левому повороту)","Только по центральной полосе в любое время","Только по правой полосе в любое время","По любой полосе без ограничений"],"explanation":"Пенсильвания запрещает движение транспортного средства или состава весом более 10,000 pounds по ЛЕВОЙ полосе автомагистрали с ограниченным доступом, имеющей три или более полос в одном направлении, за исключением случаев подготовки к законно разрешённому левому повороту на перекрёстке, съезде или к выезду. Источник: 75 Pa.C.S. § 3313 (Ограничения на использование автомагистралей с ограниченным доступом)."},"70":{"q":"На автомагистралях Пенсильвании с ограниченным доступом, имеющих две или более полос в одном направлении, общее правило для всех транспортных средств — двигаться по правым полосам, ЗА ИСКЛЮЧЕНИЕМ случаев, когда:","options":["Выполняется обгон и опережение, движение быстрее транспортного потока или подготовка к разрешённому левому повороту","Движение происходит ночью","Дорога мокрая","Пассажир просит перейти в левую полосу"],"explanation":"Пенсильвания требует, чтобы транспортные средства использовали правые полосы, когда они доступны, за исключением случаев обгона и опережения транспортного средства, движения со скоростью выше транспортного потока или подготовки к законно разрешённому левому повороту. Источник: 75 Pa.C.S. § 3313."},"71":{"q":"При отсутствии установленного знака стандартное максимальное ограничение скорости на большинстве дорог Пенсильвании (за исключением городских районов и автострад) составляет:","options":["55 mph","50 mph","60 mph","65 mph"],"explanation":"Пенсильвания устанавливает законодательный максимум 55 mph в местах, где иное не обозначено знаками, 35 mph в любом городском районе и до 65 или 70 mph на автострадах, где департамент устанавливает это ограничение знаками. Источник: 75 Pa.C.S. § 3362 (Максимальные ограничения скорости)."},"72":{"q":"На автостраде Пенсильвании с установленным ограничением 70 mph, как соотносится максимальное ограничение скорости для тяжёлого коммерческого грузовика с ограничением для легкового автомобиля?","options":["Оно такое же — 70 mph применяется ко всем транспортным средствам","Грузовики ограничены 55 mph","Грузовики ограничены 60 mph","Грузовики ограничены 65 mph"],"explanation":"Пенсильвания не устанавливает отдельного, более низкого ограничения скорости для грузовиков; установленный максимум 65 или 70 mph на автостраде применяется ко всем транспортным средствам. (Более низкие ограничения могут применяться на отдельных спусках или посредством установленных знаков.) Источник: 75 Pa.C.S. § 3362."},"73":{"q":"Максимальное установленное ограничение скорости на основной магистрали Pennsylvania Turnpike (I-76) составляет:","options":["70 mph","65 mph","75 mph","80 mph"],"explanation":"Максимальное установленное ограничение скорости на Pennsylvania Turnpike составляет 70 mph и действует на большей части основной магистрали (например, между развязками Blue Mountain и Morgantown) и на многих автострадах PennDOT. Ни один участок не имеет ограничения 75 mph. Источник: Pennsylvania Turnpike Commission / PennDOT; 75 Pa.C.S. § 3362."},"74":{"q":"Законодательное ограничение скорости в городском районе Пенсильвании, где не установлено иное ограничение, составляет:","options":["35 mph","25 mph","30 mph","40 mph"],"explanation":"В любом городском районе законодательная максимальная скорость в Пенсильвании составляет 35 mph, если после проведения транспортного исследования не установлено иное ограничение. Источник: 75 Pa.C.S. § 3362."},"75":{"q":"Водитель грузовика, чей CMV остановился на проезжей части двухполосной двусторонней автомагистрали Пенсильвании, должен расставить предупреждающие устройства в течение какого времени и где?","options":["В течение 10 минут: на 10 ft, 100 ft сзади и 100 ft спереди","В течение 15 минут: на 25 ft, 50 ft и 100 ft","В течение 30 минут: на 10 ft, 200 ft и 300 ft","В течение 5 минут: все три в пределах 50 ft"],"explanation":"Следуя федеральному стандарту, который применяет Пенсильвания, остановившийся CMV должен выставить предупреждающие устройства в течение 10 минут. На двусторонней дороге одно устройство размещается в пределах 10 ft от транспортного средства в сторону приближающегося потока, одно — примерно в 100 ft сзади и одно — примерно в 100 ft спереди. Источник: PA CDL Manual (PUB 223); 49 CFR 392.22."},"76":{"q":"Когда CMV остановился на односторонней или разделённой автомагистрали Пенсильвании, где размещаются три предупреждающих устройства в сторону приближающегося потока?","options":["Примерно в 10 ft, 100 ft и 200 ft сзади","Примерно в 10 ft, 50 ft и 100 ft сзади","Примерно в 25 ft, 100 ft и 250 ft сзади","Примерно в 10 ft, 100 ft и 150 ft сзади"],"explanation":"На односторонней или разделённой автомагистрали предупреждающие устройства размещаются примерно в 10 feet, 100 feet и 200 feet в сторону приближающегося потока (со стороны, откуда идёт движение), в течение 10 минут после остановки. Источник: PA CDL Manual (PUB 223); 49 CFR 392.22."},"77":{"q":"Перевозка какого класса опасных материалов ЗАПРЕЩЕНА через туннели Pennsylvania Turnpike?","options":["Все взрывчатые вещества и прочие материалы Table 1 (например, ядовитый газ, радиоактивные)","Только легковоспламеняющиеся жидкости навалом/наливом","Только коррозионные материалы","Только охлаждённые газы"],"explanation":"Pennsylvania Turnpike запрещает все материалы Table 1 — включая все взрывчатые вещества, ядовитый газ, материалы, опасные при контакте с водой, материалы с ингаляционной токсичностью и радиоактивные материалы — в своих туннелях; определённые мелкие (нерасфасованные навалом) перевозки прочих опасных материалов могут быть разрешены. Источник: Pennsylvania Turnpike Commission Hazardous Materials Tunnel Restrictions; 67 Pa. Code § 601.5."},"78":{"q":"Водитель, признанный виновным в незаконном обгоне остановившегося школьного автобуса с мигающими красными огнями в Пенсильвании, подвергается базовому штрафу плюс надбавке в размере:","options":["Штраф $250 плюс надбавка $35 (с баллами и приостановлением действия прав)","Штраф $100 без надбавки","Штраф $500 плюс надбавка $50","Штраф $50 плюс надбавка $25"],"explanation":"Пенсильвания наказывает незаконный обгон остановившегося школьного автобуса штрафом $250 и надбавкой $35; нарушение, замеченное сотрудником полиции, также влечёт 5 баллов и приостановление действия прав на 60 дней. Источник: 75 Pa.C.S. § 3345."},"79":{"q":"Какое ведомство выдаёт коммерческие водительские удостоверения (CDL) в Пенсильвании?","options":["Pennsylvania State Police, Commercial Vehicle Unit","Pennsylvania Department of Transportation (PennDOT), Bureau of Driver and Vehicle Services","Pennsylvania Public Utility Commission (PUC)","Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"CDL в Пенсильвании выдаёт PennDOT через своё Bureau of Driver and Vehicle Services. FMCSA устанавливает федеральные стандарты, но не выдаёт удостоверения штатов. Источник: PennDOT Commercial Driver's License Fact Sheet (ссылка PUB 223) и pa.gov Driver and Vehicle Services."},"80":{"q":"Каков в Пенсильвании минимальный возраст для получения CDL для внутриштатных перевозок (в пределах Пенсильвании) по сравнению с межштатными перевозками?","options":["21 для внутриштатных и для межштатных перевозок","16 для внутриштатных и 18 для межштатных","18 для внутриштатных и 21 для межштатных","18 для внутриштатных и для межштатных перевозок"],"explanation":"Пенсильвания разрешает получение CDL в возрасте 18 лет только для внутриштатных перевозок, тогда как для межштатных перевозок (а также для перевозки опасных материалов или пассажиров через границы штатов) водитель должен быть не моложе 21 года. Источник: требования к лицензированию CDL PennDOT (pa.gov) в соответствии с 49 CFR 383.3."},"81":{"q":"Прежде чем сдавать экзамен по навыкам CDL в Пенсильвании, заявитель должен сначала получить какой документ?","options":["Медицинский отказ (waiver) от PennDOT","Commercial Learner's Permit (CLP)","Фотоудостоверение, соответствующее REAL ID","Некоммерческое удостоверение Class C CDL"],"explanation":"Заявители должны сдать необходимый теоретический экзамен (экзамены) и получить Commercial Learner's Permit, прежде чем они смогут сдавать экзамен по навыкам. Источник: PennDOT CDL Learner's Permit FAQs и CDL Fact Sheet (pa.gov)."},"82":{"q":"Какую форму использует заявитель на CDL или CLP в Пенсильвании для самостоятельного подтверждения типа коммерческих перевозок, которые он выполняет?","options":["Driver's Record Request DL-503","Commercial Learner's Permit Application DL-31CD","Medical Examiner's Certificate DL-26","Self-Certification Form DL-11CD"],"explanation":"Каждый держатель CDL и каждый заявитель на CLP должен подать Self-Certification Form DL-11CD с указанием своей категории перевозок. DL-31CD — это заявление на CLP, отдельная форма. Источник: PennDOT Self-Certification/Medical Examiner's Certification FAQs и форма DL-11CD (pa.gov)."},"83":{"q":"Какая из перечисленных НЕ является одной из четырёх категорий самостоятельной сертификации, из которых должен выбрать заявитель на CDL в Пенсильвании?","options":["Exempt Agricultural Operator","Excepted Intrastate","Non-excepted Intrastate","Non-excepted Interstate"],"explanation":"Четыре категории самостоятельной сертификации — это Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate и Excepted Intrastate. «Exempt Agricultural Operator» не является категорией самостоятельной сертификации. Источник: PennDOT Self-Certification Form DL-11CD и CDL Fact Sheet (pa.gov)."},"84":{"q":"Какая категория самостоятельной сертификации требует, чтобы у водителя был действующий Medical Examiner's Certificate (карта прохождения DOT-медосмотра), зарегистрированный в PennDOT?","options":["Non-excepted Interstate","Excepted Intrastate","Excepted Interstate и Excepted Intrastate","Excepted Interstate"],"explanation":"Только водители, самостоятельно сертифицированные как Non-excepted (Interstate или Intrastate), обязаны иметь действующий Medical Examiner's Certificate, зарегистрированный в PennDOT. От категорий Excepted предоставление MEC не требуется. Источник: PennDOT Self-Certification/Medical Examiner's Certification FAQs (pa.gov)."},"85":{"q":"По состоянию на June 23, 2025, как должен передаваться в PennDOT Medical Examiner's Certificate (DOT-медосмотр) держателя CDL категории non-excepted в Пенсильвании?","options":["Он передаётся электронно из FMCSA National Registry напрямую в PennDOT","Водитель вручает бумажную карту служащему в любом PennDOT Driver License Center","Водитель отправляет отсканированную копию по электронной почте в PennDOT","Водитель отправляет бумажную карту почтой в PennDOT CDL Unit в Harrisburg"],"explanation":"С June 23, 2025 PennDOT принимает информацию из Medical Examiner's Certificate только в электронном виде, передаваемую из FMCSA National Registry; он больше не принимает MEC лично, по почте или по электронной почте. Источник: PennDOT Self-Certification/Medical Examiner's Certification FAQs (pa.gov)."},"86":{"q":"Тремя составляющими экзамена по навыкам CDL в Пенсильвании являются предрейсовый (технический) осмотр транспортного средства, экзамен по вождению на дороге и какая третья составляющая?","options":["Письменный экзамен по безопасному вождению","Базовое управление транспортным средством (внедорожные манёвры и парковка)","Тест на скорость реакции при торможении на время","Лабораторная симуляция сцепки и расцепки"],"explanation":"Экзамен по навыкам CDL в Пенсильвании состоит из трёх частей: предрейсовый осмотр, базовое управление транспортным средством (внедорожные манёвры и упражнение по парковке) и экзамен по вождению на дороге. Источник: PennDOT CDL Fact Sheet, раздел «Skills Tests» (pa.gov)."},"87":{"q":"Какое федеральное требование к обучению должен выполнить заявитель в Пенсильвании, прежде чем ему разрешат сдавать экзамен по навыкам CDL для впервые получаемого удостоверения Class A или Class B?","options":["Аудиторный курс безопасного вождения, проводимый PennDOT","Entry-Level Driver Training (ELDT) от зарегистрированного поставщика","40-часовой курс по технике безопасности OSHA","Выданный штатом сертификат о завершении ученичества"],"explanation":"Entry-Level Driver Training (ELDT) от поставщика из FMCSA Training Provider Registry должно быть завершено до сдачи экзамена по навыкам для первичного CDL Class A или B (а также для впервые получаемых эндорсментов P, S или H). Источник: PennDOT CDL Fact Sheet (pa.gov) и правило FMCSA ELDT (49 CFR Part 380)."},"88":{"q":"Согласно PennDOT CDL Fact Sheet, сколько вопросов содержит письменный экзамен по общим знаниям для Class A в Пенсильвании?","options":["50 вопросов","30 вопросов","70 вопросов","100 вопросов"],"explanation":"PennDOT CDL Fact Sheet указывает, что письменный теоретический экзамен Class A состоит из 70 вопросов, тогда как Class B и Class C — каждый из 50 вопросов. Источник: PennDOT CDL Fact Sheet, раздел «What Tests Do I Need to Take?» (pa.gov)."},"89":{"q":"Сколько вопросов содержит экзамен на знания для эндорсмента по перевозке опасных материалов (HazMat) в Пенсильвании и на каком языке он предлагается?","options":["25 вопросов, только на английском","30 вопросов, только на английском","50 вопросов, на нескольких языках","20 вопросов, на нескольких языках"],"explanation":"PennDOT указывает, что экзамен на знания для эндорсмента HazMat состоит из 30 вопросов, и экзамен HazMat предлагается только на английском языке (другие теоретические экзамены CDL доступны на нескольких языках). Источник: PennDOT CDL Fact Sheet (pa.gov)."},"90":{"q":"Согласно PennDOT CDL Fact Sheet, как скоро после сдачи теоретического экзамена и выдачи разрешения заявитель в Пенсильвании может сдавать экзамен по навыкам?","options":["Не ранее чем через 15 дней после сдачи теоретического экзамена и выдачи разрешения","Не ранее чем через 30 дней после выдачи разрешения","Не ранее чем через 60 дней после выдачи разрешения","Сразу после сдачи теоретического экзамена"],"explanation":"PennDOT указывает, что экзамен по навыкам нельзя сдавать ранее чем через 15 дней после сдачи теоретического экзамена и выдачи разрешения (заявитель может записаться на экзамен по навыкам сразу, но не может сдавать его до истечения 15-дневного срока). Источник: PennDOT CDL Fact Sheet, примечание «Skills Tests» (pa.gov)."},"91":{"q":"Каков стандартный срок действия коммерческого водительского удостоверения Пенсильвании до того, как его необходимо продлить (для водителя младше 65 лет)?","options":["5 лет","8 лет","2 года","4 года"],"explanation":"CDL Пенсильвании, как правило, действителен в течение 4 лет; водителям в возрасте 65 лет и старше удостоверение выдаётся с 2-летним циклом. Источник: информация о лицензировании PennDOT Driver and Vehicle Services (pa.gov)."},"92":{"q":"На какой срок выдаётся CDL Пенсильвании водителю в возрасте 65 лет или старше?","options":["4 года","2 года","3 года","1 год"],"explanation":"Хотя стандартный цикл CDL Пенсильвании составляет 4 года, водителям 65 лет и старше устанавливается 2-летний цикл продления. Источник: информация о лицензировании PennDOT Driver and Vehicle Services (pa.gov)."},"93":{"q":"Если держатель CDL категории non-excepted в Пенсильвании допускает истечение срока действия своего Medical Examiner's Certificate и не предоставляет новый, что происходит с его удостоверением?","options":["Коммерческое (CDL) обозначение понижается до некоммерческого удостоверения","Налагается гражданский штраф $500, но CDL остаётся действительным","Удостоверение аннулируется навсегда и не подлежит восстановлению","Ничего не меняется до следующего 4-летнего продления"],"explanation":"Если медицинская сертификация водителя категории non-excepted истекает, PennDOT снимает коммерческое обозначение и понижает удостоверение до некоммерческого водительского удостоверения; водитель должен повторно подать заявление на CLP, чтобы восстановить коммерческие права. Источник: PennDOT Self-Certification/Medical Examiner's Certification FAQs (pa.gov)."},"94":{"q":"Какой документ используется в Пенсильвании для подачи заявления на сам Commercial Learner's Permit?","options":["Form MV-1, заявление на регистрацию права собственности на транспортное средство","Form DL-180, заявление на некоммерческое ученическое разрешение","Form DL-11CD, Self-Certification Form","Form DL-31CD, Commercial Learner's Permit Application"],"explanation":"Заявление на Commercial Learner's Permit — это Form DL-31CD. Form DL-11CD — это отдельная форма самостоятельной сертификации, и заявитель на CLP обычно подаёт обе. Источник: PennDOT CDL Learner's Permit FAQs (pa.gov)."},"95":{"q":"Согласно правилам PennDOT, как только заявитель на CDL в Пенсильвании начинает процесс, сколько времени у него есть, чтобы сдать все необходимые теоретические экзамены и экзамены по навыкам, прежде чем придётся начинать заново?","options":["Шесть месяцев","90 дней","Один год","Два года"],"explanation":"PennDOT даёт заявителю один год на сдачу всех теоретических экзаменов и экзаменов по навыкам для получения CDL; разрешение может быть продлено посредством нового заявления DL-31CD, если экзамены не завершены в срок. Источник: PennDOT CDL Learner's Permit FAQs (pa.gov)."},"96":{"q":"Водитель хочет получить CDL Class C исключительно для управления 20-пассажирским транспортным средством. Согласно PennDOT CDL Fact Sheet, что должен включать CDL Class C?","options":["Эндорсмент S, P или H","Никакого эндорсмента вообще","Эндорсмент на двойные/тройные прицепы","Только код ограничения по пневматическим тормозам"],"explanation":"PennDOT определяет Class C как одиночные транспортные средства менее 26,001 lbs, которые перевозят опасные материалы, требующие табличек опасности, перевозят 16+ пассажиров или являются школьными автобусами; Fact Sheet указывает, что CDL Class C должен включать эндорсмент S, P или H. Источник: PennDOT CDL Fact Sheet, классы удостоверений (pa.gov)."},"97":{"q":"Согласно PennDOT CDL Fact Sheet, какой эндорсмент отдельно требует прохождения Entry-Level Driver Training при первом получении?","options":["Эндорсмент по перевозке опасных материалов (H)","Эндорсмент на двойные/тройные прицепы (T)","Эндорсмент на автоцистерны (N)","Снятие ограничения по пневматическим тормозам"],"explanation":"Fact Sheet PennDOT показывает, что ELDT требуется (только при первичном получении) для эндорсментов Passenger, School Bus и Hazardous Materials (H); эндорсменты на двойные/тройные прицепы и автоцистерны указаны как не требующие ELDT. Источник: таблица эндорсментов/тестирования PennDOT CDL Fact Sheet (pa.gov)."},"98":{"q":"Когда заявитель в Пенсильвании является на экзамен по навыкам CDL, какое транспортное средство он должен привезти?","options":["Любой легковой автомобиль с действующей регистрацией","Принадлежащее PennDOT тестовое транспортное средство, выделяемое в центре","Транспортное средство на один класс меньше, чем запрашиваемый CDL","Репрезентативное транспортное средство того класса и типа, которым он намерен управлять"],"explanation":"Экзамен по навыкам должен сдаваться на транспортном средстве того класса и типа, которым заявитель намерен управлять (например, экзамен по навыкам для эндорсмента школьного автобуса должен сдаваться на школьном автобусе). Источник: PennDOT CDL Fact Sheet, раздел «Skills Tests» (pa.gov)."}},"tr":{"0":{"q":"Pennsylvania kara yollarında, yük dahil bir aracın izin verilen maksimum toplam dış genişliği nedir?","options":["8 fit 6 inç","8 fit 0 inç","9 fit 0 inç","10 fit 0 inç"],"explanation":"75 Pa.C.S. § 4921 (Araçların genişliği) uyarınca, yük dahil bir aracın toplam dış genişliği 8 fit 6 inçi aşamaz. PennDOT'un Sürücü ve Araç Hizmetleri Boyut ve Ağırlık Sınırlamaları sayfası da aynı değeri belirtir."},"1":{"q":"Pennsylvania kara yollarında genel olarak izin verilen, yük dahil bir aracın maksimum yüksekliği nedir?","options":["13 fit 6 inç","13 fit 0 inç","14 fit 0 inç","12 fit 6 inç"],"explanation":"75 Pa.C.S. § 4922 (Araçların yüksekliği) uyarınca, hiçbir araç, yükü dahil, 13 fit 6 inç yüksekliği aşamaz. Bu durum PennDOT'un Boyut ve Ağırlık Sınırlamaları sayfasında teyit edilmektedir."},"2":{"q":"Pennsylvania kara yollarında, yük ve tamponlar dahil tek (münferit) bir motorlu aracın maksimum toplam uzunluğu nedir?","options":["40 fit","45 fit","53 fit","35 fit"],"explanation":"75 Pa.C.S. § 4923 (Araçların uzunluğu) uyarınca, yük ve tamponlar dahil tek bir motorlu araç toplamda 40 fiti aşamaz. Özel araç türlerinin (otobüsler, karavanlar, bom donanımlı araçlar) ayrı ve daha yüksek sınırları vardır."},"3":{"q":"Araç Kanunu uyarınca Pennsylvania kara yollarında herhangi bir tek aracın veya kombinasyonun maksimum brüt ağırlığı nedir?","options":["80,000 pound","73,280 pound","90,000 pound","100,000 pound"],"explanation":"75 Pa.C.S. § 4941 uyarınca ve PennDOT'un Boyut ve Ağırlık Sınırlamaları sayfasında belirtildiği üzere, herhangi bir münferit aracın veya herhangi bir kombinasyonun maksimum brüt ağırlığı, ayrıca tescilli ağırlık ve aks ağırlığı sınırlarına da tabi olarak, 80,000 pounddur."},"4":{"q":"Pennsylvania'da çalışan bir çekici-römork kombinasyonundaki tek bir yarı römorkun maksimum uzunluğu nedir?","options":["53 fit","48 fit","57 fit","40 fit"],"explanation":"Pennsylvania, çekici-yarı römork kombinasyonundaki tek bir römorkun, kingpin'den arka aksa mesafe 41 fiti aşmaması koşuluyla 53 fit uzunluğa kadar olmasına izin verir. Bu durum 75 Pa.C.S. Bölüm 49'a ve PennDOT'un Boyut ve Ağırlık Sınırlamaları sayfasına yansımaktadır."},"5":{"q":"Pennsylvania'da çift römorklu (ikiz) bir kombinasyonda, her bir römorkun maksimum uzunluğu nedir?","options":["28 fit 6 inç","28 fit 0 inç","33 fit 0 inç","30 fit 0 inç"],"explanation":"PennDOT'un Boyut ve Ağırlık Sınırlamaları sayfası, çift römorklu bir kombinasyonda her römorkun, 75 Pa.C.S. Bölüm 49 uzunluk hükümleriyle uyumlu olarak 28 fit 6 inç ile sınırlı olduğunu belirtir."},"6":{"q":"Pennsylvania'nın Eyaletler Arası kara yolu sisteminde, federal köprü formülünün aksi takdirde daha fazlasına izin vereceği durumlarda bile maksimum brüt araç ağırlığı nedir?","options":["80,000 pound","85,500 pound","90,000 pound","73,280 pound"],"explanation":"Pennsylvania federal standardı izler: Eyaletler Arası Sistemde brüt araç ağırlığı, Federal Köprü Formülü sonucu daha yüksek olsa bile 80,000 pound ile sınırlandırılmıştır. Bu federal sınır, 23 U.S.C. § 127 ve 75 Pa.C.S. § 4941 uyarınca Pennsylvania Eyaletler Arası yollarına uygulanır."},"7":{"q":"Pennsylvania'da ağır bir kombinasyon için tek bir aks (direksiyon aksı dışında) üzerinde izin verilen maksimum ağırlık nedir?","options":["20,000 pound","18,000 pound","22,400 pound","34,000 pound"],"explanation":"75 Pa.C.S. § 4943 uyarınca (ve Pennsylvania'nın izlediği federal standart uyarınca), tek bir aks üzerindeki maksimum ağırlık 20,000 pounddur. Bu, Eyaletler Arası Sistemde uygulanan federal tek aks sınırıyla örtüşür."},"8":{"q":"Pennsylvania'nın uyguladığı federal ağırlık standardı uyarınca, bir tandem aks (ardışık iki akstan oluşan bir grup) üzerindeki maksimum ağırlık nedir?","options":["34,000 pound","36,000 pound","40,000 pound","20,000 pound"],"explanation":"Pennsylvania, 34,000 poundluk federal tandem aks sınırını uygular. 75 Pa.C.S. § 4943, çiftlerin ilk ve son aksları arasındaki mesafe 36 fit veya daha fazla olduğunda, ardışık iki çift aksın her birinin 34,000 pound taşımasına izin verir."},"9":{"q":"Pennsylvania'da uygulandığı şekliyle Federal Köprü Formülünün başlıca amacı nedir?","options":["Kara yolu köprülerinin hasar görme riskini azaltmak için aks grupları üzerindeki ağırlığı sınırlamak","Köprülerin altından geçen yüklerin maksimum yüksekliğini belirlemek","Pennsylvania Turnpike üzerinde ödenecek ücreti hesaplamak","Ağır kamyonlar için minimum takip mesafesini belirlemek"],"explanation":"Federal Köprü Formülü (Brüt Köprü Ağırlığı Formülü), köprüleri korumak amacıyla, aks sayısına ve aralarındaki mesafeye dayanarak ardışık herhangi bir aks grubu üzerindeki izin verilen ağırlığı sınırlar. 23 U.S.C. § 127 uyarınca Pennsylvania'nın Eyaletler Arası Sistemine uygulanır."},"10":{"q":"Pennsylvania'da bir aracı çalıştırmak için ne zaman PennDOT taşıma izni gereklidir?","options":["Araç veya yük, Araç Kanunundaki yasal boyut veya ağırlık sınırlarını aştığında","Yalnızca başka bir eyalete geçerken","Herhangi bir ticari kargo taşırken her zaman","Yalnızca sürücünün CDL'si olmadığında"],"explanation":"PennDOT'un Boyut ve Ağırlık Sınırlamaları sayfasına göre, bir araç yasal boyut/ağırlık sınırlarının dışında yalnızca PennDOT'tan alınan bir izinle çalıştırılabilir. Aşırı boyutlu/aşırı ağır taşıma izinleri, 75 Pa.C.S. Bölüm 49'daki sınırları aşan hareketi yetkilendirir."},"11":{"q":"Pennsylvania'da aşırı boyutlu/aşırı ağır özel taşıma izinleri için başvurular ağırlıklı olarak hangi PennDOT sistemi aracılığıyla yapılır ve düzenlenir?","options":["APRAS (Otomatik İzin Yönlendirme ve Analiz Sistemi)","CDLIS (Ticari Sürücü Belgesi Bilgi Sistemi)","IRP (Uluslararası Tescil Planı) portalı","SAFER (Güvenlik ve Uygunluk Elektronik Kayıtları)"],"explanation":"PennDOT, aşırı boyutlu/aşırı ağır Özel Taşıma izinlerini, yıllık yüz binlerce izni, çoğu otomatik olarak işleyen APRAS (Otomatik İzin Yönlendirme ve Analiz Sistemi) aracılığıyla düzenler. Kaynak: PennDOT APRAS / PennDOT Taşıma İzni İçin Başvuru."},"12":{"q":"Yük dahil bir aracın, hangi genişliğin üzerinde olması aşırı boyutlu sayılır ve PennDOT izni gerektirir?","options":["8 fit 6 inçten fazla","8 fit 0 inçten fazla","9 fit 0 inçten fazla","10 fit 0 inçten fazla"],"explanation":"75 Pa.C.S. § 4921 uyarınca yasal genişlik 8 fit 6 inç olduğundan, 8 fit 6 inçten daha geniş herhangi bir araç ve yük aşırı boyutludur ve PennDOT taşıma izni gerektirir. Kaynak: PennDOT taşıma izni / Yük Türü kılavuzu."},"13":{"q":"Hangi yükseklikten daha uzun bir yük aşırı boyutlu sayılır ve PennDOT izni gerektirir?","options":["13 fit 6 inçten fazla","13 fit 0 inçten fazla","14 fit 0 inçten fazla","12 fit 6 inçten fazla"],"explanation":"75 Pa.C.S. § 4922 uyarınca yasal yükseklik sınırı 13 fit 6 inç olduğundan, 13 fit 6 inçi aşan bir yük aşırı boyutludur ve PennDOT taşıma izni gerektirir. Kaynak: PennDOT Boyut ve Ağırlık Sınırlamaları / taşıma izni kılavuzu."},"14":{"q":"Pennsylvania'da bir araç aşırı ağır sayılmadan önce direksiyon aksı üzerinde izin verilen maksimum ağırlık nedir?","options":["20,000 pound","12,000 pound","18,000 pound","22,400 pound"],"explanation":"75 Pa.C.S. § 4943 kapsamındaki PennDOT izin kılavuzuna göre, direksiyon aksı üzerindeki ağırlık 20,000 poundu aşarsa bir araç aşırı ağırdır. Bunun üzerinde, bir PennDOT aşırı ağırlık izni gereklidir."},"15":{"q":"Pennsylvania'nın yıllık 'imalat sürecinde hareket' izni (75 Pa.C.S. § 4968) uyarınca, hangi ham orman ürünü emtia maksimum ağırlığın üzerinde taşınabilir?","options":["Kağıt hamuru odunu ve odun yongaları","Bitmiş mobilya","Perakende satış için torbalanmış malç","Bir perakende satıcıya yapı kerestesi"],"explanation":"75 Pa.C.S. § 4968, imalat sürecinde ve üreticinin kontrolü altındayken ham süt, ham kömür, kağıt hamuru odunu ve odun yongaları gibi emtialar için maksimum ağırlığın üzerinde yıllık izinli harekete izin verir. Bir alıcıya veya satıcıya nakil halindeki mallar için izin verilmez."},"16":{"q":"Pennsylvania Turnpike üzerinde, belirli izinli yükler genel 80,000 poundluk sınırı hangi maksimum brüt ağırlığa kadar aşabilir?","options":["100,000 pound","80,000 pound","90,000 pound","120,000 pound"],"explanation":"Pennsylvania Turnpike kendi ticari izin sınırlarını belirler ve izinli brüt ağırlığın 100,000 pounda kadar (aks ağırlığı 22,400 pounda kadar) olmasına izin verir. Kaynak: PA Turnpike Ticari İzinler ve Kısıtlamalar. PennDOT kara yolları 80,000 lb ile sınırlı kalmaya devam eder."},"17":{"q":"75 Pa.C.S. § 4943 uyarınca, ağır bir kombinasyonda 8 fitten daha fazla aralıklı bir çift aks üzerindeki maksimum ağırlık nedir?","options":["Her biri 22,400 pound","Her biri 18,000 pound","Her biri 20,000 pound","Her biri 34,000 pound"],"explanation":"75 Pa.C.S. § 4943'ün aks aralığı kurallarına göre, 8 fitten daha fazla aralıklı akslar her biri 22,400 pounda kadar taşıyabilirken, 6 fitten daha az aralıklı akslar her biri 18,000 pound ile sınırlıdır."},"18":{"q":"Federal Köprü Formülü, tek bir aks grubu aşırı yüklenmemiş olsa bile bir kamyonu neden bazen 80,000 pounddan DAHA AZINA sınırlar?","options":["Yakın aralıklı aks grupları ağırlığı yoğunlaştırdığı için, formül köprüleri korumak amacıyla izin verilen brüt ağırlığı azaltır","Direksiyon aksı her zaman brüt ağırlığın dışında tutulduğu için","Pennsylvania tüm kamyonları 73,280 pound ile sınırladığı için","Ücretler aks aralığıyla arttığı için"],"explanation":"Federal Köprü Formülü, izin verilen ağırlığı aks sayısına ve kaplanan mesafeye bağlar. Akslar yakın aralıklı olduğunda, formül köprü açıklıkları üzerindeki gerilimi sınırlamak için 80,000 pound'un altında bir değer verir. Pennsylvania bunu 23 U.S.C. § 127 uyarınca Eyaletler Arası Sistemde uygular."},"19":{"q":"Pennsylvania'da en büyük standart izin eşiklerini aşan aşırı boyutlu/aşırı ağır bir hareket ('süper yük') nasıl ele alınmalıdır?","options":["APRAS aracılığıyla incelemeye sunulmalı, genellikle onaydan önce manuel analiz ve yönlendirme gerektirir","Gece taşınıyorsa izinsiz sürülebilir","Herhangi bir PennDOT fotoğraflı ehliyet merkezinde otomatik olarak onaylanır","Daha yüksek ücret ödediği için tüm yönlendirmelerden muaftır"],"explanation":"Süper yük başvuruları PennDOT'un APRAS sistemi aracılığıyla sunulmalıdır; çoğu rutin izin yaklaşık bir dakikada otomatik olarak onaylanırken, süper yükler ve yaklaşık her beş başvurudan biri manuel inceleme ve rota analizi gerektirir. Kaynak: PennDOT APRAS."},"20":{"q":"Pennsylvania'da, çekilen aracın GVWR'si 10,000 poundu aştığında, 26,001 pound veya daha fazla Brüt Kombinasyon Ağırlık Derecesine (GCWR) sahip bir araç kombinasyonunu kullanmak için hangi sınıf CDL gereklidir?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf D"],"explanation":"PennDOT Ticari Sürücü Belgesi Bilgi Formuna (Haziran 2025) ve PUB 223'e göre, çekilen aracın GVWR'sinin 10,000 poundu aşması koşuluyla, Sınıf A CDL, 26,001 pound veya daha fazla GCWR'ye sahip bir kombinasyon aracını kapsar. Kaynak: PennDOT CDL Bilgi Formu / Ticari Sürücü Kılavuzu (PUB 223)."},"21":{"q":"Pennsylvania CDL kuralları uyarınca, 26,001 pound veya daha fazla Brüt Araç Ağırlık Derecesine (GVWR) sahip tek bir araç (veya 10,000 poundu aşmayan bir birim çeken böyle bir araç) hangi ehliyet sınıfını gerektirir?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf M"],"explanation":"PennDOT, Sınıf B'yi 26,001 pound veya daha fazla GVWR'ye sahip tek bir araç ya da 10,000 poundu aşmayan bir aracı çeken böyle herhangi bir araç olarak tanımlar. Kaynak: PennDOT CDL Bilgi Formu (Haziran 2025) / PUB 223."},"22":{"q":"PennDOT'a göre, Pennsylvania Sınıf C CDL, plakartlı tehlikeli madde taşıyan, 16 veya daha fazla kişi taşıyan ya da bir okul otobüsü olan 26,001 pound GVWR'nin altındaki tek bir araç için kullanılır. Bir Sınıf C CDL ayrıca neyi içermelidir?","options":["Bir S, P veya H onayı","Bir motosiklet (M) onayı","Bir Sınıf A hava freni sertifikası","Bir çiftlik aracı muafiyeti"],"explanation":"PennDOT CDL Bilgi Formu, Sınıf C CDL'nin, plakartlı tehlikeli madde taşıyan, sürücü dahil 16 veya daha fazla kişi taşıyacak şekilde tasarlanmış ya da bir okul otobüsü olan 26,001 lbs GVWR altındaki tek araçları kapsadığını ve Sınıf C CDL'nin bir S, P veya H onayını içermesi gerektiğini belirtir. Kaynak: PennDOT CDL Bilgi Formu (Haziran 2025)."},"23":{"q":"Pennsylvania'da 'N' onayı, bir CDL sahibine ne yapma yetkisi verir?","options":["Tanker araçlarını kullanma","Çift ve üçlü römorkları kullanma","Bir otobüste yolcu taşıma","Plakartlı tehlikeli madde taşıma"],"explanation":"PennDOT, N onayının sürücüye tanker araçlarını kullanma yetkisi verdiğini belirtir. (T onayı çiftler/üçlüler, P yolcular ve H plakartlı tehlikeli madde içindir.) Kaynak: PennDOT CDL Bilgi Formu (Haziran 2025) / PUB 223."},"24":{"q":"Çift ve üçlü römorkları sürmek için hangi Pennsylvania CDL onayı gereklidir?","options":["T onayı","N onayı","X onayı","H onayı"],"explanation":"PennDOT, T onayının çift ve üçlü römorkların sürülmesine yetki verdiğini belirtir. Kaynak: PennDOT CDL Bilgi Formu (Haziran 2025) / PUB 223."},"25":{"q":"Bir Pennsylvania CDL'sinde, birleşik 'X' onayı neyi temsil eder?","options":["Hem tehlikeli madde hem de tanker aracı (H ve N)","Hem yolcu hem de okul otobüsü (P ve S)","Hem çiftler/üçlüler hem de tanker (T ve N)","Yenileme bekleyen süresi dolmuş bir onay"],"explanation":"PennDOT, X onayını tehlikeli madde ve tanker aracı birleşimi (H,N) olarak listeler. Kaynak: PennDOT CDL Bilgi Formu (Haziran 2025)."},"26":{"q":"Eyalet içi sürüş (ticari bir aracı yalnızca Pennsylvania içinde kullanma) için bir Pennsylvania CDL almanın minimum yaşı nedir?","options":["18 yaşında","16 yaşında","19 yaşında","21 yaşında"],"explanation":"Pennsylvania, eyalet içi (yalnızca eyalet içinde) ticari sürüş için bir CDL'ye sahip olmak için minimum 18 yaş şartı arar. Kaynak: PennDOT Sürücü ve Araç Hizmetleri, Ticari Sürücüler / Ehliyet Türleri ve Kısıtlamalar."},"27":{"q":"Bir Pennsylvania CDL ile eyaletler arası ticarette (eyalet sınırları boyunca) bir ticari motorlu aracı kullanmak için gereken minimum yaş nedir?","options":["21 yaşında","18 yaşında","19 yaşında","25 yaşında"],"explanation":"Eyaletler arası ticarette bir CMV kullanmak için bir sürücünün en az 21 yaşında olması gerekir. 18-20 yaş arası sürücüler yalnızca Pennsylvania içinde eyalet içi olarak kullanabilir. Kaynak: PennDOT Ticari Sürücüler / Pennsylvania'da uygulandığı şekliyle 49 CFR 391.11."},"28":{"q":"Gerekli bilgi testini geçtikten ve bir Pennsylvania ticari öğrenci ehliyeti verildikten sonra, bir Sınıf A, B veya C beceri testinin planlanabilmesi için gereken minimum bekleme süresi nedir?","options":["15 gün","10 gün","30 gün","7 gün"],"explanation":"PennDOT'a göre, beceri testi, bilgi testi geçilip bir ehliyet verildikten 15 gün sonrasına kadar yapılamaz. Bu, federal 14 günlük CLP-bekletme şartını karşılar. Kaynak: PennDOT CDL Bilgi Formu (Haziran 2025) ve CDL Öğrenci Ehliyeti SSS."},"29":{"q":"Bir Pennsylvania Bilgi Testi Yetkilendirmesi (KTA) / ticari öğrenci ehliyeti, başvuru sahibine tüm bilgi ve beceri testlerini geçmesi için süre tanıyarak ne kadar süre geçerlidir?","options":["Düzenlenme tarihinden itibaren bir yıl","Düzenlenme tarihinden itibaren 90 gün","Düzenlenme tarihinden itibaren altı ay","Düzenlenme tarihinden itibaren iki yıl"],"explanation":"PennDOT, KTA'nın düzenlenme tarihinden itibaren bir yıl geçerli olduğunu ve başvuru sahiplerinin CDL'lerini almak için tüm bilgi ve beceri testlerini geçmek üzere bir yılları olduğunu belirtir. Kaynak: PennDOT CDL Öğrenci Ehliyeti SSS."},"30":{"q":"Bir Pennsylvania ticari öğrenci ehliyetine başvuran veya bir CDL'ye sahip olan her kişi, gerçekleştirdiği ticari operasyon türünü belirten hangi belgeyi doldurmalıdır?","options":["Bir Öz Sertifikasyon Formu (DL-11CD)","Bir REAL ID muafiyet formu","Bir IRP paylaştırılmış tescil formu","Bir Form I-9 istihdam yetkilendirmesi"],"explanation":"PennDOT, her CDL sahibinin ve her CLP başvuru sahibinin sürüş türünü belirten bir Öz Sertifikasyon Formu (DL-11CD) sunmasını şart koşar. Kaynak: PennDOT CDL Bilgi Formu (Haziran 2025) ve Öz Sertifikasyon/Tıbbi Muayene SSS."},"31":{"q":"Aşağıdakilerden hangisi, bir Pennsylvania CDL başvuru sahibinin seçmek zorunda olduğu dört tıbbi öz sertifikasyon kategorisinden biridir?","options":["Muaf Olmayan Eyaletler Arası","Muaf Eyalet Dışı","Plakartlı Eyaletler Arası","Kısıtlı Eyalet İçi"],"explanation":"Dört öz sertifikasyon kategorisi şunlardır: Muaf Olmayan Eyaletler Arası, Muaf Olmayan Eyalet İçi, Muaf Eyaletler Arası ve Muaf Eyalet İçi. Muaf Olmayan Eyaletler Arası bir sürücünün PennDOT'ta dosyada geçerli bir Tıbbi Muayene Sertifikası bulunmalıdır. Kaynak: PennDOT Öz Sertifikasyon/Tıbbi Muayene SSS."},"32":{"q":"'Muaf Olmayan Eyalet İçi' olarak öz sertifikasyon yapan bir Pennsylvania sürücüsü, yalnızca eyalet içinde sürerken federal fiziksel yeterlilik standartlarına tabidir. Bu durumda PennDOT hangi ehliyet kısıtlamasını ekler?","options":["Bir 'K' kısıtlaması (yalnızca eyalet içi ticaret)","Bir 'L' kısıtlaması (hava freni yok)","Bir 'E' kısıtlaması (manuel şanzıman yok)","Bir 'O' kısıtlaması (beşinci tekerlek kombinasyonu yok)"],"explanation":"PennDOT, sürücüyü yalnızca eyalet içi ticaretle sınırlayan K kısıtlamasını uygular. K kısıtlaması, yalnızca eyalet içi ticari operasyon için görünür. Kaynak: PennDOT CDL Bilgi Formu (Haziran 2025) ve Öz Sertifikasyon SSS."},"33":{"q":"7 Şubat 2022 tarihinden itibaren geçerli olmak üzere, Pennsylvania'da Giriş Seviyesi Sürücü Eğitimi (ELDT), hangi belge(ler) için ilk kez başvuranlardan istenmektedir?","options":["İlk Sınıf A veya B CDL ya da ilk P, S veya H onayı","Sınıfa bakılmaksızın herhangi bir CDL yenilemesi","Yalnızca bir HazMat (H) onayı","Yalnızca eyalet içi Sınıf C CDL'ler"],"explanation":"PennDOT tarafından benimsenen FMCSA kuralları uyarınca, ELDT (7 Şubat 2022'den itibaren geçerli) ilk kez bir Sınıf A veya B CDL almaya, Sınıf A veya B'ye yükseltmeye ya da ilk kez bir P, S veya H onayı almaya uygulanır. Geriye dönük değildir. Kaynak: PennDOT Giriş Seviyesi Sürücü Eğitimi sayfası / 49 CFR Part 380."},"34":{"q":"Bir Pennsylvania giriş seviyesi sürücü, beceri testini almadan önce gerekli ELDT eğitimini nereden almalıdır?","options":["FMCSA Eğitim Sağlayıcı Sicilinde (TPR) listelenen bir sağlayıcıdan","Herhangi bir PennDOT sürücü ehliyet merkezinden","Bir işverenin gayri resmi iş başı programından","Herhangi bir AAA bağlantılı sürüş okulundan"],"explanation":"PennDOT, ELDT'nin beceri testinden önce FMCSA Eğitim Sağlayıcı Sicilinde (tpr.fmcsa.dot.gov) listelenen bir sağlayıcı ile tamamlanmasını şart koşar. Kaynak: PennDOT CDL Bilgi Formu (Haziran 2025) / Giriş Seviyesi Sürücü Eğitimi sayfası."},"35":{"q":"Bir Pennsylvania HazMat (H) onayı almak için, bir başvuru sahibinin bir bilgi testini geçmesi ve hangi federal arka plan taramasını tamamlaması gerekir?","options":["Parmak izi alma dahil bir TSA Güvenlik Tehdit Değerlendirmesi","Bir E-Verify istihdam kontrolü","Yalnızca PennDOT'a özgü bir sürüş kaydı incelemesi","Bir FAA tıbbi sertifikasyonu"],"explanation":"PennDOT, HazMat başvuru sahiplerinin parmak izi alma dahil (Form DL-288, PUB 512) bir federal Ulaştırma Güvenliği İdaresi (TSA) Güvenlik Tehdit Değerlendirmesini tamamlamasını şart koşar. PennDOT, H onayını vermeden önce federal onay almalıdır. Kaynak: PennDOT Tehlikeli Maddeler Onayı Bilgi Formu (FS-HM) ve SSS."},"36":{"q":"Resmi PennDOT CDL bilgi testlerinde, Tehlikeli Maddeler (H) onayı testinde kaç soru bulunur?","options":["30 soru","20 soru","25 soru","50 soru"],"explanation":"PennDOT, Tehlikeli Maddeler Onayı bilgi testini 30 soru olarak listeler ve HazMat testi yalnızca İngilizce olarak sunulur. Kaynak: PennDOT CDL Bilgi Formu (Haziran 2025)."},"37":{"q":"Bir Pennsylvania Okul Otobüsü (S) onayı almadan önce, sürücünün ayrıca hangi onaya sahip olması gerekir?","options":["Yolcu (P) onayı","Tanker (N) onayı","Çiftler/Üçlüler (T) onayı","HazMat (H) onayı"],"explanation":"PennDOT, Okul Otobüsü (S) onayı için ön koşul olarak Yolcu (P) onayını şart koşar; S bilgi testi yolcu onayını gerektirir. Kaynak: PennDOT CDL Bilgi Formu (Haziran 2025) / Okul Taşımacılığı SSS."},"38":{"q":"PennDOT'a göre Pennsylvania Okul Otobüsü (S) onay kartı hakkında hangi ifade doğrudur?","options":["Bir Okul Otobüsü onay kartı yıllık olarak verilir","S onayı asla yenileme gerektirmez","S onayı yalnızca her sekiz yılda bir verilir","S onay kartı TSA tarafından postalanır"],"explanation":"PennDOT CDL Bilgi Formu, S onayının bir okul otobüsü kullanma yetkisi verdiğini ve bir Okul Otobüsü onay kartının yıllık olarak verildiğini belirtir. Kaynak: PennDOT CDL Bilgi Formu (Haziran 2025)."},"39":{"q":"Bir Pennsylvania CDL/CLP için şahsen başvururken, bir başvuru sahibinin genel olarak kimlik ve yasal statü kanıtı, Sosyal Güvenlik numarası kanıtı ve kaç adet Pennsylvania ikamet kanıtı sunması gerekir?","options":["İki adet Pennsylvania ikamet kanıtı","Bir adet Pennsylvania ikamet kanıtı","Üç adet Pennsylvania ikamet kanıtı","İkamet kanıtı gerekmez"],"explanation":"PennDOT, kimliği/yasal statüyü kanıtlayan bir belge, Sosyal Güvenlik numarasını kanıtlayan bir belge ve Pennsylvania ikametini kanıtlayan iki belge şart koşar. Kaynak: PennDOT Kimlik ve İkamet Kanıtı gereksinimleri (PUB 195US)."},"40":{"q":"Pennsylvania'da, bir sürücünün etki altında ticari motorlu araç (CMV) kullandığı kabul edilen kan alkol konsantrasyonu (BAC) için maksimum eşik değer (bu değer veya üzeri) nedir?","options":["yüzde 0.02","yüzde 0.04","yüzde 0.08","yüzde 0.10"],"explanation":"Pennsylvania, ticari olmayan sürücüler için olan yüzde 0.08 sınırının yarısı olan yüzde 0.04 veya daha yüksek bir BAC ile CMV kullanmayı yasaklar. Kaynak: PA CDL Kılavuzu; 75 Pa.C.S. ve 49 CFR 383.51."},"41":{"q":"Pennsylvania'nın zımni rıza kuralları uyarınca, uygun bir memur uyarısından sonra kimyasal teste tabi olmayı reddeden bir CMV sürücüsüne ne olur?","options":["Diskalifiye olmaksızın yalnızca yazılı bir uyarı","30 günlük bir CDL diskalifikasyonu","Bir DUI mahkumiyeti gibi muamele gören 1 yıllık bir CDL diskalifikasyonu","6 aylık bir CDL diskalifikasyonu"],"explanation":"Kimyasal testi reddeden bir CMV sürücüsü, büyük bir suç mahkumiyetiyle aynı şekilde en az 1 yıl süreyle diskalifiye edilir. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51."},"42":{"q":"Pennsylvania'da, ilk büyük suç (örneğin yüzde 0.04 veya daha yüksek bir BAC ile CMV kullanmak), en az ne kadar süreyle bir CDL diskalifikasyonuyla sonuçlanır?","options":["60 gün","6 ay","1 yıl","3 yıl"],"explanation":"İlk büyük suç, bir Pennsylvania CDL sahibini en az 1 yıl süreyle diskalifiye eder. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51."},"43":{"q":"Pennsylvania'da, bir sürücü tehlikeli maddeler için plakartlı bir CMV kullanırken ilk büyük suçu işlerse, diskalifikasyon süresi şuna yükselir:","options":["1 yıl","2 yıl","3 yıl","5 yıl"],"explanation":"Plakartlı tehlikeli madde taşırken işlenen ilk büyük suç, diskalifikasyonu 1 yıldan 3 yıla yükseltir. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51."},"44":{"q":"Pennsylvania'da ikinci bir büyük suç (örneğin bir CMV'de ikinci bir DUI) için CDL diskalifikasyon süresi nedir?","options":["3 yıl","5 yıl","10 yıl","Ömür boyu"],"explanation":"Herhangi bir araçta iki büyük suç, Pennsylvania'da ömür boyu CDL diskalifikasyonuyla sonuçlanır. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51."},"45":{"q":"Pennsylvania'da, 3 yıllık bir süre içinde ayrı olaylarda İKİ ciddi trafik ihlalinden mahkum olmak, şu süreyle bir CDL diskalifikasyonuyla sonuçlanır:","options":["30 gün","60 gün","120 gün","1 yıl"],"explanation":"3 yıl içinde iki ciddi trafik ihlali, bir Pennsylvania CDL sahibini 60 gün süreyle diskalifiye eder. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51."},"46":{"q":"Pennsylvania'da, 3 yıllık bir süre içinde ayrı olaylarda ÜÇ ciddi trafik ihlalinden mahkum olmak, şu süreyle bir CDL diskalifikasyonuyla sonuçlanır:","options":["60 gün","90 gün","120 gün","1 yıl"],"explanation":"3 yıl içinde üç ciddi trafik ihlali, herhangi bir 60 günlük diskalifikasyondan sonra ardışık olarak uygulanmak üzere, bir Pennsylvania CDL sahibini 120 gün süreyle diskalifiye eder. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51."},"47":{"q":"Aşağıdakilerden hangisi bir Pennsylvania CDL sahibi için CİDDİ bir trafik ihlali olarak sınıflandırılır?","options":["Yanmış bir arka stop lambası","Hız sınırını 15 mph veya daha fazla aşmak","Durma yasağı bölgesinde park etmek","Süresi dolmuş tescil ile araç kullanmak"],"explanation":"Sınırın 15 mph veya daha fazla üzerinde hız yapmak ciddi bir trafik ihlalidir; diğerleri arasında dikkatsiz sürüş, hatalı şerit değiştirme, çok yakın takip, mesaj yazma ve elde tutulan telefon kullanımı bulunur. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51."},"48":{"q":"Bir Pennsylvania CDL sürücüsü için, bir demir yolu-kara yolu hemzemin geçit yasasını ihlal etmenin İLK mahkumiyeti için diskalifikasyon nedir?","options":["30 gün","60 gün","120 gün","1 yıl"],"explanation":"İlk demir yolu hemzemin geçit ihlali, bir Pennsylvania CDL sahibini 60 gün süreyle diskalifiye eder. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51."},"49":{"q":"Bir Pennsylvania CDL sürücüsü için, 3 yıllık bir süre içinde İKİNCİ bir demir yolu-kara yolu hemzemin geçit ihlali, şu süreyle bir diskalifikasyonla sonuçlanır:","options":["60 gün","120 gün","1 yıl","3 yıl"],"explanation":"3 yıl içinde ikinci bir demir yolu hemzemin geçit ihlali, bir Pennsylvania CDL sahibini 120 gün süreyle diskalifiye eder. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51."},"50":{"q":"Bir Pennsylvania CDL sürücüsü için, 3 yıllık bir süre içinde ÜÇÜNCÜ veya sonraki bir demir yolu-kara yolu hemzemin geçit ihlali, şu süreyle bir diskalifikasyonla sonuçlanır:","options":["120 gün","180 gün","1 yıl","3 yıl"],"explanation":"3 yıl içinde üçüncü veya sonraki bir demir yolu hemzemin geçit ihlali, bir Pennsylvania CDL sahibini 1 yıl süreyle diskalifiye eder. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51."},"51":{"q":"Pennsylvania'da, tehlikeli OLMAYAN maddeler taşırken bir hizmet dışı (OOS) emrini ihlal etmenin İLK mahkumiyeti, bir CDL sürücüsünü şu süreyle diskalifiye eder:","options":["90 gün","180 gün","1 yıl","2 yıl"],"explanation":"İlk hizmet dışı emri ihlali (tehlikeli madde dışı), bir Pennsylvania CDL sahibini en az 1 yıl süreyle diskalifiye eder. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51."},"52":{"q":"Pennsylvania'da, 10 yıllık bir süre içinde İKİNCİ bir hizmet dışı emri ihlali (tehlikeli madde dışı), şu süreyle bir CDL diskalifikasyonuyla sonuçlanır:","options":["1 yıl","2 yıl","3 yıl","5 yıl"],"explanation":"10 yıl içinde ikinci bir hizmet dışı emri ihlali (tehlikeli madde dışı), bir Pennsylvania CDL sahibini en az 3 yıl süreyle diskalifiye eder. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51."},"53":{"q":"Pennsylvania'da, tehlikeli madde taşırken veya 16 ya da daha fazla yolcu taşırken İLK hizmet dışı emri ihlali, bir CDL sürücüsünü şu süreyle diskalifiye eder:","options":["1 yıl","2 yıl","3 yıl","5 yıl"],"explanation":"Tehlikeli madde taşırken veya 16+ yolcu taşırken işlenen ilk hizmet dışı emri ihlali, bir Pennsylvania CDL sahibini en az 2 yıl süreyle diskalifiye eder. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51."},"54":{"q":"Pennsylvania'da, tehlikeli madde taşırken veya 16 ya da daha fazla yolcu taşırken 10 yıl içinde İKİNCİ bir hizmet dışı emri ihlali, bir CDL sürücüsünü şu süreyle diskalifiye eder:","options":["2 yıl","3 yıl","5 yıl","Ömür boyu"],"explanation":"Tehlikeli madde taşırken veya 16+ yolcu taşırken 10 yıl içinde işlenen ikinci bir hizmet dışı emri ihlali, bir Pennsylvania CDL sahibini en az 5 yıl süreyle diskalifiye eder. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51."},"55":{"q":"Bir Pennsylvania CDL sahibi için, bir CMV kullanırken elde tutulan bir mobil telefon kullanmak şu şekilde ele alınır:","options":["Bildirime tabi olmayan bir ekipman ihlali","Diskalifikasyona yol açabilecek ciddi bir trafik ihlali","İlk suçta otomatik 1 yıllık bir diskalifikasyon","Ömür boyu diskalifikasyon suçu"],"explanation":"Bir CMV kullanırken elde tutulan bir telefon kullanmak ciddi bir trafik ihlalidir; 3 yıl içinde iki tanesi 60 günlük bir diskalifikasyona ve üç tanesi 120 güne neden olur. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51 ve 392.82."},"56":{"q":"Bir Pennsylvania CDL sahibi için, bir ticari motorlu araç kullanırken mesaj yazmak şudur:","options":["Araç bir ışıkta durdurulmuşsa izin verilir","Diskalifikasyona yol açabilecek ciddi bir trafik ihlali","Ehliyet üzerinde etkisi olmayan yalnızca park türü bir para cezası","Sevkiyat iletişimi için izin verilir"],"explanation":"Bir CMV kullanırken mesaj yazmak ciddi bir trafik ihlalidir; bunların 3 yıl içinde birikmesi 60 veya 120 günlük diskalifikasyonlara yol açar. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51 ve 392.80."},"57":{"q":"Pennsylvania'da, hangi mahkumiyet, 10 yıl sonra geri verme seçeneği OLMAKSIZIN ömür boyu bir CDL diskalifikasyonu taşır?","options":["Bir CMV'de ikinci bir DUI","Kontrollü bir madde üretimi veya dağıtımını içeren bir suç işlemek için bir CMV kullanmak","3 yıl içinde iki ciddi trafik ihlali","İlk hizmet dışı emri ihlali"],"explanation":"Kontrollü bir maddenin üretimi, dağıtımı veya temini içeren bir suçta bir CMV kullanmak, azaltılamayan ömür boyu bir diskalifikasyonla sonuçlanır. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51."},"58":{"q":"Bir CMV'nin ihmalkar veya suç teşkil eden kullanımı yoluyla ölümle sonuçlanan bir büyük suçtan mahkum olan bir Pennsylvania CDL sürücüsü en az şu süreyle diskalifiye edilir:","options":["60 gün","120 gün","1 yıl","5 yıl"],"explanation":"Bir CMV'nin ihmalkar veya suç teşkil eden kullanımı yoluyla ölüme neden olmak, minimum 1 yıllık bir diskalifikasyon taşıyan (tehlikeli madde için plakartlıysa 3 yıl) bir büyük suçtur. Kaynak: PennDOT Diskalifikasyonlar ve Trafik Suçları bilgi formu; 49 CFR 383.51."},"59":{"q":"Pennsylvania okul otobüsü yasasına göre, bir okul otobüsünün kırmızı sinyal lambaları yanıp sönerken ve dur kolu açıkken, otobüse karşıdan gelen veya onu geçen bir sürücü otobüse ulaşmadan ne kadar önce durmalıdır?","options":["En az 10 feet","En az 15 feet","En az 20 feet","En az 25 feet"],"explanation":"Pennsylvania, kırmızı sinyal lambaları yanıp sönen bir okul otobüsüne karşıdan gelen veya onu geçen sürücülerin otobüsten en az 10 feet mesafede durmasını ve lambalar yanıp sönmeyi bırakıp dur kolu geri çekilene kadar ilerlememesini gerektirir. Kaynak: 75 Pa.C.S. § 3345 (Okul otobüsüne karşıdan gelme veya onu geçme); PA Commercial Driver's Manual (PUB 223)."},"60":{"q":"Fiziksel bir bariyer veya açıkça belirtilmiş bir ayırıcı bölümle bölünmüş ayrı yollara sahip bir Pennsylvania karayolunda, kırmızı lambaları yanıp sönen duran bir okul otobüsünün KARŞI yolundaki bir sürücü ne yapmalıdır?","options":["Durmak zorunda değildir","Orta refüjden en az 10 feet mesafede durmalıdır","Yalnızca çocuklar görünürse durmalıdır","15 mph hıza yavaşlamalı ancak durmasına gerek yoktur"],"explanation":"Pennsylvania'nın bölünmüş yol istisnası, ayrı yollara sahip bir karayolundaki bir sürücünün, FARKLI bir yolda bulunan, kırmızı lambaları yanıp sönen bir okul otobüsü için durması gerekmediğini belirtir. 'Ayrı yol' için fiziksel bir bariyer veya açıkça belirtilmiş bir ayırıcı bölüm gerekir; yalnızca boyalı çizgiler veya tabelalar bunu oluşturmaz. Kaynak: 75 Pa.C.S. § 3345."},"61":{"q":"Pennsylvania'nın okul otobüsü 'ayrı yollar' istisnasının geçerli olması için (böylece karşı yöndeki trafiğin durması gerekmemesi için) hangi özellik GEREKLİDİR?","options":["Fiziksel bir bariyer veya açıkça belirtilmiş bir ayırıcı bölüm","Çift sarı orta çizgi","Ortada bir sola dönüş şeridi","'DIVIDED HIGHWAY' yazan bir tabela"],"explanation":"Pennsylvania'da istisna yalnızca yolların fiziksel bir bariyer veya açıkça belirtilmiş bir ayırıcı bölümle ayrıldığı yerlerde geçerlidir. Yalnızca yol işaretleri veya tabelalar ayrı bir yol oluşturmuş SAYILMAZ, bu nedenle yalnızca boya ile bölünmüş yollarda tüm yönlerin yine de durması gerekir. Kaynak: 75 Pa.C.S. § 3345."},"62":{"q":"Pennsylvania'da bir demiryolu hemzemin geçidinde durması gereken bir araç, en yakın raydan ne kadar mesafe içinde durmalıdır?","options":["50 feet içinde ancak 15 feet'ten az olmamak üzere","100 feet içinde ancak 25 feet'ten az olmamak üzere","30 feet içinde ancak 10 feet'ten az olmamak üzere","75 feet içinde ancak 20 feet'ten az olmamak üzere"],"explanation":"Pennsylvania yasası, demiryolu geçitlerinde durması gereken araçların (okul otobüsleri, yolcu otobüsleri ve belirli yakıtlar/patlayıcılar/radyoaktif maddeler taşıyan kamyonlar) en yakın raydan 50 feet içinde ancak 15 feet'ten az olmamak üzere durmasını, ardından bakıp dinlemesini gerektirir. Kaynak: 75 Pa.C.S. § 3342 (Demiryolu geçitlerinde durması gereken araçlar); PA CDL Manual."},"63":{"q":"Pennsylvania yasasına göre hangi araç her demiryolu hemzemin geçidinde durmak zorunda DEĞİLDİR?","options":["Tehlikeli madde taşımayan boş bir kapalı kasa çekici-römork","Yolcu taşısın veya taşımasın bir okul otobüsü","Yolcu taşıyan bir otobüs","Plakalanmış patlayıcı taşıyan bir kamyon"],"explanation":"Pennsylvania, okul otobüslerinin (dolu veya boş), yolcu taşıyan otobüslerin ve benzin, dizel/akaryakıt, patlayıcılar veya radyoaktif maddeler taşıyan kamyonların geçitlerde durmasını gerektirir. Tehlikeli yük taşımayan sıradan boş bir yük kamyonunun durması gerekmez. Kaynak: 75 Pa.C.S. § 3342."},"64":{"q":"Durmak zorunda olan bir Pennsylvania CMV'si demiryolu raylarını geçerken, sürücünün özellikle yapması yasaklanan şey nedir?","options":["Raylar üzerindeyken vites değiştirmek","Motor frenini kullanmak","Düşük viteste geçmek","Dörtlü flaşörleri yakmak"],"explanation":"Pennsylvania yasası, durmak zorunda olan bir sürücünün, geçiş sırasında vites değiştirmeyi gerektirmeyecek bir viteste geçmesini ve ray(lar) üzerindeyken vites değiştirmemesini öngörür. Kaynak: 75 Pa.C.S. § 3342; PA CDL Manual."},"65":{"q":"Pennsylvania'da 'EXEMPT' yazan bir tabela ile işaretlenmiş bir demiryolu geçidinde, plakalanmış bir tehlikeli madde kamyonu veya otobüsü:","options":["Durmak zorunda değildir","Yine de raydan 50 feet içinde durmalıdır","Durmalı ve korna çalmalıdır","Yalnızca bir bariyer varsa durmalıdır"],"explanation":"Pennsylvania, 'exempt' tabelası bulunan geçitleri (ve bu şekilde işaretlenmiş terk edilmiş geçitleri) zorunlu durma kuralından muaf tutar; aracı geçişe yönlendiren bir memur veya işaretçi ya da yeşil bir trafik sinyali de durma yükümlülüğünü ortadan kaldırır. Kaynak: 75 Pa.C.S. § 3342."},"66":{"q":"Pennsylvania'nın Move Over yasasına göre, bir sürücü bir acil müdahale alanı yakınında bitişik olmayan bir şeride güvenle geçemediğinde, bunun yerine geçerken hızını ilan edilen sınırın en fazla ne kadar altında tutmalıdır?","options":["İlan edilen hız sınırının 20 mph altında","İlan edilen hız sınırının 10 mph altında","İlan edilen hız sınırının 15 mph altında","İlan edilen hız sınırının 25 mph altında"],"explanation":"Pennsylvania'nın Move Over (Steer Clear) yasası, mümkün olduğunda acil müdahale alanına bitişik olmayan bir şeritte geçmeyi gerektirir; bu imkansız, yasadışı veya güvensizse, sürücü ilan edilen hız sınırının en fazla 20 mph altında ve güvenlik için makul bir hızda geçmelidir. Kaynak: 75 Pa.C.S. § 3327."},"67":{"q":"Pennsylvania'nın Move Over yasası (2020 Yılı 105 Sayılı Yasa), bir acil müdahale alanının yanında olmayan bir şeride geçmemek için kaç ceza puanı verir?","options":["2 puan","3 puan","4 puan","5 puan"],"explanation":"2020 Yılı 105 Sayılı Yasa, şerit değiştirmemek için 2 puanlık bir cezanın yanı sıra $500 (ilk), $1,000 (ikinci) ve 90 günlük ehliyet askısıyla birlikte $2,000 (üçüncü veya sonraki) artan para cezaları ekledi. Kaynak: 75 Pa.C.S. § 3327; PennDOT Move Over kampanyası."},"68":{"q":"Polis, itfaiye, ambulans ve çekici araçların yanı sıra, Pennsylvania'nın Move Over yasası aşağıdakilerden hangisini de korur?","options":["En az iki acil durum işareti gösteren arızalı bir araç (örneğin dörtlü flaşörler ve fişekler)","Banketin üzerine yasal olarak park etmiş herhangi bir araç","Yalnızca devlete ait araçlar","Kırmızı ışıkta duran araçlar"],"explanation":"Pennsylvania, Move Over yükümlülüğünü, dörtlü flaşörler, uyarı tabelaları/cihazları veya yol fişekleri gibi en az iki acil durum işareti gösteren arızalı araçlara genişletmiştir. Sürücüler şerit değiştirmeli veya hızlarını sınırın en fazla 20 mph altına düşürmelidir. Kaynak: 75 Pa.C.S. § 3327 (arızalı araçlarla ilgili yükümlülük)."},"69":{"q":"Tek yönde üç veya daha fazla şeride sahip kontrollü erişimli bir Pennsylvania karayolunda, 10,000 pound üzerindeki bir kamyon kombinasyonu hangi şeritte seyahat edebilir?","options":["Sol şerit hariç herhangi bir şerit (sol şerit, izin verilen bir sola dönüşe hazırlanma dışında yasaktır)","Her zaman yalnızca orta şerit","Her zaman yalnızca sağ şerit","Kısıtlama olmaksızın herhangi bir şerit"],"explanation":"Pennsylvania, 10,000 pound üzerindeki bir aracın veya kombinasyonun, aynı yönde üç veya daha fazla şeride sahip kontrollü erişimli bir karayolunun SOL şeridinde sürülmesini, bir kavşakta, çıkışta veya araç yolunda yasal olarak izin verilen bir sola dönüşe hazırlanma durumu hariç, yasaklar. Kaynak: 75 Pa.C.S. § 3313 (Kontrollü erişimli karayollarının kullanımına ilişkin kısıtlamalar)."},"70":{"q":"Tek yönde iki veya daha fazla şeride sahip kontrollü erişimli Pennsylvania karayollarında, tüm araçlar için genel kural sağ şeritlerde sürmektir, BUNUN İSTİSNASI:","options":["Sollama ve geçiş yapma, trafik akışından daha hızlı gitme veya izin verilen bir sola dönüşe hazırlanma","Gece seyahat etme","Yolun ıslak olması","Bir yolcunun sol şeridi talep etmesi"],"explanation":"Pennsylvania, araçların, bir aracı sollama ve geçme, trafik akışından daha yüksek bir hızda gitme veya yasal olarak izin verilen bir sola dönüşe hazırlanma durumları dışında, mevcut olduğunda sağ şeritleri kullanmasını gerektirir. Kaynak: 75 Pa.C.S. § 3313."},"71":{"q":"Bir tabela bulunmadığında, çoğu Pennsylvania karayolunda (kentsel bölgeler veya otoyollar hariç) varsayılan azami hız sınırı:","options":["55 mph","50 mph","60 mph","65 mph"],"explanation":"Pennsylvania, aksi belirtilmemiş yerlerde yasal azami 55 mph, herhangi bir kentsel bölgede 35 mph ve idarenin bu sınırı ilan ettiği otoyollarda 65 veya 70 mph'ye kadar belirler. Kaynak: 75 Pa.C.S. § 3362 (Azami hız sınırları)."},"72":{"q":"70 mph olarak ilan edilen bir Pennsylvania otoyolunda, ağır bir ticari kamyon için azami hız sınırı bir binek otomobilinkiyle nasıl karşılaştırılır?","options":["Aynıdır—70 mph tüm araçlar için geçerlidir","Kamyonlar 55 mph ile sınırlıdır","Kamyonlar 60 mph ile sınırlıdır","Kamyonlar 65 mph ile sınırlıdır"],"explanation":"Pennsylvania, kamyonlar için ayrı, daha düşük bir hız sınırı belirlemez; ilan edilen 65 veya 70 mph otoyol azami sınırı tüm araçlar için geçerlidir. (Belirli iniş eğimlerinde veya ilan edilen tabelalar yoluyla daha düşük sınırlar uygulanabilir.) Kaynak: 75 Pa.C.S. § 3362."},"73":{"q":"Pennsylvania Turnpike ana hattındaki (I-76) azami ilan edilen hız sınırı:","options":["70 mph","65 mph","75 mph","80 mph"],"explanation":"Pennsylvania Turnpike'ın azami ilan edilen hız sınırı 70 mph'dir ve ana hattın çoğunda (örneğin Blue Mountain ile Morgantown kavşakları arasında) ve birçok PennDOT otoyolunda geçerlidir. Hiçbir kesim 75 mph olarak ilan edilmemiştir. Kaynak: Pennsylvania Turnpike Commission / PennDOT; 75 Pa.C.S. § 3362."},"74":{"q":"Pennsylvania'nın başka bir sınır ilan edilmemiş yerlerde kentsel bölge yasal hız sınırı:","options":["35 mph","25 mph","30 mph","40 mph"],"explanation":"Herhangi bir kentsel bölgede, bir trafik etüdünün ardından farklı bir sınır ilan edilmedikçe Pennsylvania'nın yasal azami hızı 35 mph'dir. Kaynak: 75 Pa.C.S. § 3362."},"75":{"q":"CMV'si iki şeritli, çift yönlü bir Pennsylvania karayolunun seyrüsefer kısmında duran bir kamyon sürücüsü, uyarı cihazlarını hangi süre içinde ve nereye yerleştirmelidir?","options":["10 dakika içinde: 10 ft mesafeye, arkaya 100 ft ve öne 100 ft mesafeye","15 dakika içinde: 25 ft, 50 ft ve 100 ft mesafeye","30 dakika içinde: 10 ft, 200 ft ve 300 ft mesafeye","5 dakika içinde: üçü de 50 ft içinde"],"explanation":"Pennsylvania'nın uyguladığı federal standarda göre, duran bir CMV 10 dakika içinde uyarı cihazları yerleştirmelidir. Çift yönlü bir yolda, birini aracın yaklaşan trafiğe doğru 10 ft mesafesine, birini arkaya yaklaşık 100 ft mesafeye ve birini öne yaklaşık 100 ft mesafeye yerleştirin. Kaynak: PA CDL Manual (PUB 223); 49 CFR 392.22."},"76":{"q":"Bir CMV tek yönlü veya bölünmüş bir Pennsylvania karayolunda durduğunda, üç uyarı cihazı yaklaşan trafiğe doğru nereye yerleştirilir?","options":["Arkaya yaklaşık 10 ft, 100 ft ve 200 ft","Arkaya yaklaşık 10 ft, 50 ft ve 100 ft","Arkaya yaklaşık 25 ft, 100 ft ve 250 ft","Arkaya yaklaşık 10 ft, 100 ft ve 150 ft"],"explanation":"Tek yönlü veya bölünmüş bir karayolunda, durduktan sonra 10 dakika içinde uyarı cihazlarını yaklaşan trafiğe doğru (trafiğin geldiği taraf) yaklaşık 10 feet, 100 feet ve 200 feet mesafeye yerleştirin. Kaynak: PA CDL Manual (PUB 223); 49 CFR 392.22."},"77":{"q":"Hangi tehlikeli madde sınıfının Pennsylvania Turnpike tünellerinden taşınması YASAKTIR?","options":["Tüm patlayıcılar ve diğer Table 1 maddeleri (örneğin zehirli gaz, radyoaktif)","Yalnızca dökme halindeki yanıcı sıvılar","Yalnızca aşındırıcı maddeler","Yalnızca soğutulmuş gazlar"],"explanation":"Pennsylvania Turnpike, tüm patlayıcılar, zehirli gaz, ıslandığında tehlikeli, soluma yoluyla zehir tehlikesi ve radyoaktif maddeler dahil tüm Table 1 maddelerini tünellerinden yasaklar; diğer tehlikeli maddelerin belirli dökme olmayan sevkiyatlarına izin verilebilir. Kaynak: Pennsylvania Turnpike Commission Tehlikeli Maddeler Tünel Kısıtlamaları; 67 Pa. Code § 601.5."},"78":{"q":"Pennsylvania'da kırmızı lambaları yanıp sönen duran bir okul otobüsünü yasadışı şekilde geçtiği tespit edilen bir sürücü, temel para cezası artı ek ücret olarak şununla karşı karşıya kalır:","options":["$250 para cezası artı $35 ek ücret (ceza puanları ve ehliyet askısı ile birlikte)","Ek ücret olmaksızın $100 para cezası","$500 para cezası artı $50 ek ücret","$50 para cezası artı $25 ek ücret"],"explanation":"Pennsylvania, duran bir okul otobüsünü yasadışı şekilde geçmeyi $250 para cezası ve $35 ek ücret ile cezalandırır; bir memurun gözlemlediği bir ihlal ayrıca 5 puan ve 60 günlük ehliyet askısı getirir. Kaynak: 75 Pa.C.S. § 3345."},"79":{"q":"Pennsylvania'da ticari sürücü belgelerini (CDL) hangi kurum verir?","options":["Pennsylvania Eyalet Polisi, Ticari Araç Birimi","Pennsylvania Ulaştırma Bakanlığı (PennDOT), Sürücü ve Araç Hizmetleri Bürosu","Pennsylvania Kamu Hizmetleri Komisyonu (PUC)","Federal Motorlu Taşıyıcı Güvenliği İdaresi (FMCSA)"],"explanation":"Pennsylvania CDL'leri, Sürücü ve Araç Hizmetleri Bürosu aracılığıyla PennDOT tarafından verilir. FMCSA federal standartları belirler ancak eyalet belgesi vermez. Kaynak: PennDOT Ticari Sürücü Belgesi Bilgi Föyü (PUB 223 referansı) ve pa.gov Sürücü ve Araç Hizmetleri."},"80":{"q":"Pennsylvania'da, eyalet içi (Pennsylvania içinde) sürüş ile eyaletler arası sürüş için CDL almanın asgari yaşı nedir?","options":["Hem eyalet içi hem eyaletler arası için 21","Eyalet içi için 16 ve eyaletler arası için 18","Eyalet içi için 18 ve eyaletler arası için 21","Hem eyalet içi hem eyaletler arası için 18"],"explanation":"Pennsylvania yalnızca eyalet içi işletme için 18 yaşında CDL'ye izin verirken, eyaletler arası işletme (ve eyalet sınırlarını aşan tehlikeli madde veya yolcu taşımacılığı) sürücünün en az 21 yaşında olmasını gerektirir. Kaynak: PennDOT CDL belgelendirme gereklilikleri (pa.gov), 49 CFR 383.3 ile tutarlıdır."},"81":{"q":"Pennsylvania'da CDL beceri sınavına girmeden önce bir başvuru sahibinin önce hangi belgeyi alması gerekir?","options":["PennDOT'tan bir tıbbi muafiyet","Bir Ticari Öğrenci İzni (CLP)","REAL ID uyumlu fotoğraflı bir ehliyet","Class C ticari olmayan bir CDL"],"explanation":"Başvuru sahipleri, beceri sınavına girmeden önce gerekli bilgi sınav(lar)ını geçmeli ve kendilerine bir Ticari Öğrenci İzni verilmiş olmalıdır. Kaynak: PennDOT CDL Öğrenci İzni SSS ve CDL Bilgi Föyü (pa.gov)."},"82":{"q":"Bir Pennsylvania CDL veya CLP başvuru sahibi, yaptıkları ticari sürüş türünü kendi beyanıyla bildirmek için hangi formu kullanır?","options":["Sürücü Kayıt Talebi DL-503","Ticari Öğrenci İzni Başvurusu DL-31CD","Tıbbi Muayene Sertifikası DL-26","Kendi Beyan Formu DL-11CD"],"explanation":"Her CDL sahibi ve her CLP başvuru sahibi, işletme kategorilerini beyan eden Kendi Beyan Formu DL-11CD'yi sunmalıdır. DL-31CD, ayrı bir form olan CLP başvurusudur. Kaynak: PennDOT Kendi Beyan/Tıbbi Muayene Sertifikası SSS ve Form DL-11CD (pa.gov)."},"83":{"q":"Aşağıdakilerden hangisi bir Pennsylvania CDL başvuru sahibinin seçmesi gereken dört kendi beyan kategorisinden biri DEĞİLDİR?","options":["Muaf Tarımsal İşletmeci","İstisna Tutulan Eyalet İçi","İstisna Tutulmayan Eyalet İçi","İstisna Tutulmayan Eyaletler Arası"],"explanation":"Dört kendi beyan kategorisi şunlardır: İstisna Tutulmayan Eyaletler Arası, İstisna Tutulan Eyaletler Arası, İstisna Tutulmayan Eyalet İçi ve İstisna Tutulan Eyalet İçi. \"Muaf Tarımsal İşletmeci\" bir kendi beyan kategorisi değildir. Kaynak: PennDOT Kendi Beyan Formu DL-11CD ve CDL Bilgi Föyü (pa.gov)."},"84":{"q":"Hangi kendi beyan kategorisi, sürücünün PennDOT kayıtlarında geçerli bir Tıbbi Muayene Sertifikası (DOT fizik muayene kartı) bulundurmasını gerektirir?","options":["İstisna Tutulmayan Eyaletler Arası","İstisna Tutulan Eyalet İçi","İstisna Tutulan Eyaletler Arası ve İstisna Tutulan Eyalet İçi","İstisna Tutulan Eyaletler Arası"],"explanation":"Yalnızca İstisna Tutulmayan (Eyaletler Arası veya Eyalet İçi) olarak kendi beyanda bulunan sürücüler PennDOT kayıtlarında geçerli bir Tıbbi Muayene Sertifikası bulundurmalıdır. İstisna tutulan kategorilerin bir MEC sunması gerekmez. Kaynak: PennDOT Kendi Beyan/Tıbbi Muayene Sertifikası SSS (pa.gov)."},"85":{"q":"23 Haziran 2025 itibarıyla, bir Pennsylvania istisna tutulmayan CDL sahibinin Tıbbi Muayene Sertifikası (DOT fizik muayenesi) PennDOT'a nasıl sunulmalıdır?","options":["FMCSA National Registry'den doğrudan PennDOT'a elektronik olarak iletilir","Sürücü kağıt kartı herhangi bir PennDOT Sürücü Belgesi Merkezi'ndeki bir görevliye elden teslim eder","Sürücü taranmış bir kopyayı PennDOT'a e-postayla gönderir","Sürücü kağıt kartı Harrisburg'daki PennDOT CDL Birimi'ne postayla gönderir"],"explanation":"23 Haziran 2025'ten bu yana, PennDOT yalnızca FMCSA National Registry'den elektronik olarak iletilen Tıbbi Muayene Sertifikası bilgilerini kabul eder; artık MEC'leri şahsen, postayla veya e-postayla kabul etmemektedir. Kaynak: PennDOT Kendi Beyan/Tıbbi Muayene Sertifikası SSS (pa.gov)."},"86":{"q":"Pennsylvania CDL beceri sınavının üç bileşeni; sefer öncesi (araç) kontrolü, yolda sürüş sınavı ve hangi üçüncü bileşendir?","options":["Yazılı bir savunmacı sürüş sınavı","Temel araç kontrolü (yol dışı manevralar ve park etme)","Zamanlı bir fren-tepki refleks testi","Bir takma-ayırma laboratuvar simülasyonu"],"explanation":"Pennsylvania'nın CDL beceri sınavının üç bölümü vardır: sefer öncesi kontrol, temel araç kontrolü (yol dışı manevralar ve araç park etme egzersizi) ve yolda sürüş sınavı. Kaynak: PennDOT CDL Bilgi Föyü, \"Skills Tests\" bölümü (pa.gov)."},"87":{"q":"İlk kez Class A veya Class B belgesi için CDL beceri sınavına girmesine izin verilmeden önce bir Pennsylvania başvuru sahibinin hangi federal eğitim gerekliliğini tamamlaması gerekir?","options":["PennDOT tarafından yürütülen sınıf içi bir savunmacı sürüş kursu","Kayıtlı bir sağlayıcıdan Giriş Düzeyi Sürücü Eğitimi (ELDT)","40 saatlik bir OSHA güvenlik kursu","Eyalet tarafından verilen bir çıraklık tamamlama sertifikası"],"explanation":"İlk Class A veya B CDL için (ve ilk kez P, S veya H onayları için) beceri sınavına girmeden önce, FMCSA Eğitim Sağlayıcı Sicili'nde yer alan bir sağlayıcıdan Giriş Düzeyi Sürücü Eğitimi (ELDT) tamamlanmalıdır. Kaynak: PennDOT CDL Bilgi Föyü (pa.gov) ve FMCSA ELDT kuralı (49 CFR Part 380)."},"88":{"q":"PennDOT CDL Bilgi Föyü'ne göre, Pennsylvania'da Class A genel bilgi yazılı sınavında kaç soru vardır?","options":["50 soru","30 soru","70 soru","100 soru"],"explanation":"PennDOT'un CDL Bilgi Föyü, Class A yazılı bilgi sınavını 70 soru olarak listeler; Class B ve Class C ise her biri 50 sorudur. Kaynak: PennDOT CDL Bilgi Föyü, \"What Tests Do I Need to Take?\" (pa.gov)."},"89":{"q":"Pennsylvania Tehlikeli Maddeler (HazMat) onay bilgi sınavında kaç soru vardır ve hangi dilde sunulur?","options":["25 soru, yalnızca İngilizce","30 soru, yalnızca İngilizce","50 soru, birden çok dilde","20 soru, birden çok dilde"],"explanation":"PennDOT, HazMat onay bilgi sınavını 30 soru olarak listeler ve HazMat sınavı yalnızca İngilizce olarak sunulur (diğer CDL bilgi sınavları birden çok dilde mevcuttur). Kaynak: PennDOT CDL Bilgi Föyü (pa.gov)."},"90":{"q":"PennDOT CDL Bilgi Föyü'ne göre, bilgi sınavını geçip kendisine bir izin verildikten ne kadar sonra bir Pennsylvania başvuru sahibi beceri sınavına girebilir?","options":["Bilgi sınavı geçilip izin verildikten sonra 15 gün geçene kadar değil","İzin verildikten sonra 30 gün geçene kadar değil","İzin verildikten sonra 60 gün geçene kadar değil","Bilgi sınavını geçtikten hemen sonra"],"explanation":"PennDOT, beceri sınavının, bilgi sınavı geçilip bir izin verildikten 15 gün sonrasına kadar girilemeyeceğini belirtir (bir başvuru sahibi beceri sınavını hemen planlayabilir, ancak 15 günlük noktadan önce sınava giremez). Kaynak: PennDOT CDL Bilgi Föyü, \"Skills Tests\" notu (pa.gov)."},"91":{"q":"Bir Pennsylvania ticari sürücü belgesinin (65 yaş altı bir sürücü için) yenilenmesi gerekmeden önceki standart geçerlilik süresi nedir?","options":["5 yıl","8 yıl","2 yıl","4 yıl"],"explanation":"Bir Pennsylvania CDL genellikle 4 yıl geçerlidir; 65 yaş ve üzeri sürücülere 2 yıllık döngüyle verilir. Kaynak: PennDOT Sürücü ve Araç Hizmetleri belgelendirme bilgileri (pa.gov)."},"92":{"q":"65 yaş ve üzeri bir sürücüye verilen bir Pennsylvania CDL ne kadar süreyle geçerlidir?","options":["4 yıl","2 yıl","3 yıl","1 yıl"],"explanation":"Standart Pennsylvania CDL döngüsü 4 yıl olsa da, 65 yaş ve üzeri sürücüler 2 yıllık yenileme döngüsüne tabidir. Kaynak: PennDOT Sürücü ve Araç Hizmetleri belgelendirme bilgileri (pa.gov)."},"93":{"q":"Bir Pennsylvania istisna tutulmayan CDL sahibi Tıbbi Muayene Sertifikasının süresinin dolmasına izin verir ve yenisini sunmazsa, belgesine ne olur?","options":["Ticari (CDL) tanımı ticari olmayan bir belgeye düşürülür","$500 idari para cezası uygulanır ancak CDL geçerli kalır","Belge kalıcı olarak iptal edilir ve yeniden verilemez","Bir sonraki 4 yıllık yenilemeye kadar hiçbir şey değişmez"],"explanation":"İstisna tutulmayan bir sürücünün tıbbi belgelendirmesi sona ererse, PennDOT ticari tanımı kaldırır ve belgeyi ticari olmayan bir sürücü belgesine düşürür; sürücü ticari ayrıcalıkları geri kazanmak için yeniden bir CLP başvurusu yapmalıdır. Kaynak: PennDOT Kendi Beyan/Tıbbi Muayene Sertifikası SSS (pa.gov)."},"94":{"q":"Pennsylvania'da Ticari Öğrenci İzni'nin kendisine başvurmak için hangi belge kullanılır?","options":["Araç tescil başvurusu olan Form MV-1","Ticari olmayan öğrenci izni başvurusu olan Form DL-180","Kendi Beyan Formu olan Form DL-11CD","Ticari Öğrenci İzni Başvurusu olan Form DL-31CD"],"explanation":"Ticari Öğrenci İzni Başvurusu Form DL-31CD'dir. Form DL-11CD ayrı bir kendi beyan formudur ve bir CLP başvuru sahibi tipik olarak her ikisini de sunar. Kaynak: PennDOT CDL Öğrenci İzni SSS (pa.gov)."},"95":{"q":"PennDOT kurallarına göre, bir Pennsylvania CDL başvuru sahibi süreci başlattıktan sonra, yeniden başlamak zorunda kalmadan önce gerekli tüm bilgi ve beceri sınavlarını geçmek için ne kadar süresi vardır?","options":["Altı ay","90 gün","Bir yıl","İki yıl"],"explanation":"PennDOT, başvuru sahibine CDL almak için tüm bilgi ve beceri sınavlarını geçmesi için bir yıl tanır; testler zamanında tamamlanmazsa, izin yeni bir DL-31CD başvurusuyla uzatılabilir. Kaynak: PennDOT CDL Öğrenci İzni SSS (pa.gov)."},"96":{"q":"Bir sürücü yalnızca 20 yolcu kapasiteli bir aracı kullanmak için Class C CDL istiyor. PennDOT CDL Bilgi Föyü'ne göre, bir Class C CDL neyi içermelidir?","options":["Bir S, P veya H onayı","Hiçbir türde onay içermez","Bir çift/üçlü römork onayı","Yalnızca bir hava freni kısıtlama kodu"],"explanation":"PennDOT, Class C'yi 26,001 lbs altında olup plakalama gerektiren tehlikeli madde taşıyan, 16+ yolcu taşıyan veya okul otobüsü olan tek araçlar olarak tanımlar; Bilgi Föyü bir Class C CDL'nin bir S, P veya H onayı içermesi gerektiğini belirtir. Kaynak: PennDOT CDL Bilgi Föyü, belge sınıfları (pa.gov)."},"97":{"q":"PennDOT CDL Bilgi Föyü'ne göre, hangi onay ilk kez alındığında ayrıca Giriş Düzeyi Sürücü Eğitimi gerektirir?","options":["Tehlikeli Maddeler (H) onayı","Çift/Üçlü (T) onayı","Tank Aracı (N) onayı","Hava freni kısıtlamasının kaldırılması"],"explanation":"PennDOT'un Bilgi Föyü, ELDT'nin (yalnızca ilk kez için) Yolcu, Okul Otobüsü ve Tehlikeli Maddeler (H) onayları için gerekli olduğunu gösterir; Çift/Üçlü ve Tank onayları ELDT gerektirmeyen olarak listelenmiştir. Kaynak: PennDOT CDL Bilgi Föyü onay/test tablosu (pa.gov)."},"98":{"q":"Bir Pennsylvania başvuru sahibi CDL beceri sınavına geldiğinde, hangi aracı getirmelidir?","options":["Geçerli tescili olan herhangi bir binek otomobili","Merkezde atanan PennDOT'a ait bir test aracı","Alınmak istenen CDL'den bir sınıf küçük bir araç","Kullanmayı amaçladıkları sınıf ve türü temsil eden bir araç"],"explanation":"Beceri sınavı, başvuru sahibinin kullanmayı amaçladığı sınıf ve türde bir araçta yapılmalıdır (örneğin, bir okul otobüsü onayı beceri sınavı bir okul otobüsünde yapılmalıdır). Kaynak: PennDOT CDL Bilgi Föyü, \"Skills Tests\" bölümü (pa.gov)."}},"es":{"0":{"q":"En las carreteras de Pensilvania, ¿cuál es el ancho exterior total máximo de un vehículo, incluyendo cualquier carga?","options":["8 pies 6 pulgadas","8 pies 0 pulgadas","9 pies 0 pulgadas","10 pies 0 pulgadas"],"explanation":"Según 75 Pa.C.S. § 4921 (Ancho de los vehículos), el ancho exterior total de un vehículo, incluyendo cualquier carga, no puede exceder de 8 pies 6 pulgadas. La página de Limitaciones de Tamaño y Peso de Pennsylvania DMV (Driver and Vehicle Services) indica la misma cifra."},"1":{"q":"¿Cuál es la altura máxima de un vehículo, incluyendo cualquier carga, permitida generalmente en las carreteras de Pensilvania?","options":["13 pies 6 pulgadas","13 pies 0 pulgadas","14 pies 0 pulgadas","12 pies 6 pulgadas"],"explanation":"Según 75 Pa.C.S. § 4922 (Altura de los vehículos), ningún vehículo, incluyendo su carga, puede exceder una altura de 13 pies 6 pulgadas. Esto se confirma en la página de Limitaciones de Tamaño y Peso de Pennsylvania DMV."},"2":{"q":"¿Cuál es la longitud total máxima de un solo vehículo automotor (individual), incluyendo la carga y los parachoques, en las carreteras de Pensilvania?","options":["40 pies","45 pies","53 pies","35 pies"],"explanation":"Según 75 Pa.C.S. § 4923 (Longitud de los vehículos), un solo vehículo automotor, incluyendo cualquier carga y los parachoques, no puede exceder de 40 pies en total. Ciertos tipos especiales de vehículos (autobuses, casas rodantes, vehículos equipados con grúa) tienen límites separados y más altos."},"3":{"q":"¿Cuál es el peso bruto máximo de cualquier vehículo individual o combinación en las carreteras de Pensilvania según el Código de Vehículos?","options":["80,000 libras","73,280 libras","90,000 libras","100,000 libras"],"explanation":"Según 75 Pa.C.S. § 4941, y como se indica en la página de Limitaciones de Tamaño y Peso de Pennsylvania DMV, el peso bruto máximo de cualquier vehículo individual o cualquier combinación es de 80,000 libras, sujeto también a los límites de peso registrado y de peso por eje."},"4":{"q":"¿Cuál es la longitud máxima de un solo semirremolque en una combinación de tractor con remolque que opera en Pensilvania?","options":["53 pies","48 pies","57 pies","40 pies"],"explanation":"Pensilvania permite que un solo remolque en una combinación de tractor con semirremolque tenga hasta 53 pies de longitud, siempre que la distancia del pivote (kingpin) al eje trasero no exceda de 41 pies. Esto se refleja en 75 Pa.C.S. Capítulo 49 y en la página de Limitaciones de Tamaño y Peso de Pennsylvania DMV."},"5":{"q":"En una combinación de doble remolque (gemelos) en Pensilvania, ¿cuál es la longitud máxima de cada remolque?","options":["28 pies 6 pulgadas","28 pies 0 pulgadas","33 pies 0 pulgadas","30 pies 0 pulgadas"],"explanation":"La página de Limitaciones de Tamaño y Peso de Pennsylvania DMV indica que en una combinación de doble remolque, cada remolque está limitado a 28 pies 6 pulgadas, en consonancia con las disposiciones de longitud del Capítulo 49 de 75 Pa.C.S."},"6":{"q":"En el sistema de carreteras interestatales de Pensilvania, ¿cuál es el peso bruto vehicular máximo, incluso cuando la fórmula federal de puentes permitiría más?","options":["80,000 libras","85,500 libras","90,000 libras","73,280 libras"],"explanation":"Pensilvania sigue el estándar federal: en el Sistema Interestatal, el peso bruto vehicular tiene un tope de 80,000 libras, incluso si el resultado de la Fórmula Federal de Puentes es mayor. Este límite federal se aplica a las interestatales de Pensilvania según 23 U.S.C. § 127 y 75 Pa.C.S. § 4941."},"7":{"q":"¿Cuál es el peso máximo permitido en un solo eje (que no sea el eje de dirección) para una combinación pesada en Pensilvania?","options":["20,000 libras","18,000 libras","22,400 libras","34,000 libras"],"explanation":"Según 75 Pa.C.S. § 4943 (y el estándar federal que sigue Pensilvania), el peso máximo en un solo eje es de 20,000 libras. Esto coincide con el límite federal de eje simple aplicado en el Sistema Interestatal."},"8":{"q":"Según el estándar federal de peso que aplica Pensilvania, ¿cuál es el peso máximo en un eje tándem (un grupo de dos ejes consecutivos)?","options":["34,000 libras","36,000 libras","40,000 libras","20,000 libras"],"explanation":"Pensilvania aplica el límite federal de eje tándem de 34,000 libras. 75 Pa.C.S. § 4943 permite que dos pares consecutivos de ejes carguen 34,000 libras cada uno cuando la distancia entre el primero y el último eje de los pares es de 36 pies o más."},"9":{"q":"¿Cuál es el propósito principal de la Fórmula Federal de Puentes tal como se aplica en Pensilvania?","options":["Limitar el peso en grupos de ejes para reducir el riesgo de daños a los puentes de las carreteras","Establecer la altura máxima de las cargas que pasan por debajo de los puentes","Calcular el peaje adeudado en la Pennsylvania Turnpike","Determinar la distancia mínima de seguimiento para los camiones pesados"],"explanation":"La Fórmula Federal de Puentes (Bridge Gross Weight Formula) limita el peso permitido en cualquier grupo de ejes consecutivos según la cantidad de ejes y la distancia entre ellos, para proteger los puentes. Se aplica al Sistema Interestatal de Pensilvania según 23 U.S.C. § 127."},"10":{"q":"¿Cuándo se requiere un permiso de transporte de Pennsylvania DMV para operar un vehículo en Pensilvania?","options":["Cuando el vehículo o la carga exceden los límites legales de tamaño o peso del Código de Vehículos","Solo al cruzar a otro estado","Siempre que se transporte cualquier carga comercial","Solo cuando el conductor no tiene una CDL"],"explanation":"Según la página de Limitaciones de Tamaño y Peso de Pennsylvania DMV, un vehículo solo puede operarse fuera de los límites legales de tamaño/peso con un permiso de Pennsylvania DMV. Los permisos de transporte de carga sobredimensionada/sobrepeso autorizan el movimiento que excede los límites del Capítulo 49 de 75 Pa.C.S."},"11":{"q":"¿A través de qué sistema de Pennsylvania DMV se solicitan y emiten principalmente los permisos especiales de transporte de carga sobredimensionada/sobrepeso en Pensilvania?","options":["APRAS (Sistema Automatizado de Enrutamiento y Análisis de Permisos)","CDLIS (Sistema de Información de Licencias de Conducir Comerciales)","El portal IRP (Plan Internacional de Registro)","SAFER (Registros Electrónicos de Seguridad e Idoneidad)"],"explanation":"Pennsylvania DMV emite permisos especiales de transporte de carga sobredimensionada/sobrepeso a través de APRAS, el Sistema Automatizado de Enrutamiento y Análisis de Permisos (Automated Permit Routing and Analysis System), que procesa cientos de miles de permisos al año, muchos de forma automática. Fuente: APRAS de Pennsylvania DMV / Solicitud de un permiso de transporte de Pennsylvania DMV."},"12":{"q":"Un vehículo y carga que midan más de qué ancho se considera sobredimensionado y requiere un permiso de Pennsylvania DMV?","options":["Más de 8 pies 6 pulgadas","Más de 8 pies 0 pulgadas","Más de 9 pies 0 pulgadas","Más de 10 pies 0 pulgadas"],"explanation":"Dado que el ancho legal según 75 Pa.C.S. § 4921 es de 8 pies 6 pulgadas, cualquier vehículo y carga más ancho que 8 pies 6 pulgadas se considera sobredimensionado y requiere un permiso de transporte de Pennsylvania DMV. Fuente: orientación sobre permisos de transporte / Tipo de carga de Pennsylvania DMV."},"13":{"q":"¿Una carga más alta que qué altura se considera sobredimensionada y requiere un permiso de Pennsylvania DMV?","options":["Más de 13 pies 6 pulgadas","Más de 13 pies 0 pulgadas","Más de 14 pies 0 pulgadas","Más de 12 pies 6 pulgadas"],"explanation":"Dado que el límite legal de altura según 75 Pa.C.S. § 4922 es de 13 pies 6 pulgadas, una carga que exceda los 13 pies 6 pulgadas se considera sobredimensionada y requiere un permiso de transporte de Pennsylvania DMV. Fuente: Limitaciones de Tamaño y Peso de Pennsylvania DMV / orientación sobre permisos de transporte."},"14":{"q":"¿Cuál es el peso máximo permitido en un eje de dirección antes de que un vehículo se considere con sobrepeso en Pensilvania?","options":["20,000 libras","12,000 libras","18,000 libras","22,400 libras"],"explanation":"Según la orientación sobre permisos de Pennsylvania DMV conforme a 75 Pa.C.S. § 4943, un vehículo tiene sobrepeso si el peso en el eje de dirección excede de 20,000 libras. Por encima de eso, se requiere un permiso de sobrepeso de Pennsylvania DMV."},"15":{"q":"Bajo el permiso anual de Pensilvania de 'movimiento durante el proceso de fabricación' (75 Pa.C.S. § 4968), ¿qué producto básico de materias primas forestales puede transportarse por encima del peso máximo?","options":["Madera para pulpa y astillas de madera","Muebles terminados","Mantillo embolsado para venta al por menor","Madera de construcción a un distribuidor minorista"],"explanation":"75 Pa.C.S. § 4968 permite el movimiento con permiso anual por encima del peso máximo para productos básicos como leche cruda, carbón crudo, madera para pulpa y astillas de madera mientras estén en proceso de fabricación y bajo el control del fabricante. No se emite ningún permiso para mercancías en tránsito hacia un comprador o distribuidor."},"16":{"q":"En la Pennsylvania Turnpike, ciertas cargas con permiso pueden exceder el límite general de 80,000 libras hasta qué peso bruto máximo?","options":["100,000 libras","80,000 libras","90,000 libras","120,000 libras"],"explanation":"La Pennsylvania Turnpike establece sus propios límites de permisos comerciales, permitiendo un peso bruto con permiso de hasta 100,000 libras (con un peso por eje de hasta 22,400 libras). Fuente: Permisos y Restricciones Comerciales de la PA Turnpike. Las carreteras de Pennsylvania DMV siguen con un tope de 80,000 lb."},"17":{"q":"Según 75 Pa.C.S. § 4943, ¿cuál es el peso máximo en un par de ejes separados por más de 8 pies en una combinación pesada?","options":["22,400 libras cada uno","18,000 libras cada uno","20,000 libras cada uno","34,000 libras cada uno"],"explanation":"Según las reglas de espaciamiento de ejes de 75 Pa.C.S. § 4943, los ejes separados por más de 8 pies pueden cargar hasta 22,400 libras cada uno, mientras que los ejes separados por menos de 6 pies están limitados a 18,000 libras cada uno."},"18":{"q":"¿Por qué la Fórmula Federal de Puentes a veces limita un camión a MENOS de 80,000 libras incluso cuando ningún grupo de ejes individual está sobrecargado?","options":["Porque los grupos de ejes muy juntos concentran el peso, por lo que la fórmula reduce el peso bruto permitido para proteger los puentes","Porque el eje de dirección siempre se excluye del peso bruto","Porque Pensilvania limita todos los camiones a 73,280 libras","Porque los peajes aumentan con el espaciamiento de los ejes"],"explanation":"La Fórmula Federal de Puentes vincula el peso permitido con la cantidad de ejes y la distancia abarcada. Cuando los ejes están muy juntos, la fórmula produce un valor por debajo de 80,000 libras para limitar el esfuerzo sobre los tramos del puente. Pensilvania aplica esto en el Sistema Interestatal según 23 U.S.C. § 127."},"19":{"q":"Un movimiento de carga sobredimensionada/sobrepeso que excede los umbrales del permiso estándar más grande en Pensilvania (una 'supercarga') ¿cómo debe gestionarse?","options":["Presentarse a través de APRAS para su revisión, lo que a menudo requiere análisis manual y enrutamiento antes de la aprobación","Conducirse sin permiso si se transporta de noche","Aprobarse automáticamente en cualquier centro de licencias con foto de Pennsylvania DMV","Estar exento de todo enrutamiento porque paga un peaje más alto"],"explanation":"Las solicitudes de supercargas deben presentarse a través del sistema APRAS de Pennsylvania DMV; aunque la mayoría de los permisos de rutina se aprueban automáticamente en aproximadamente un minuto, las supercargas y aproximadamente una de cada cinco solicitudes requieren revisión manual y análisis de ruta. Fuente: APRAS de Pennsylvania DMV."},"20":{"q":"En Pensilvania, ¿qué clase de CDL se requiere para operar una combinación de vehículos con una Calificación de Peso Bruto Combinado (GCWR) de 26,001 libras o más, cuando el vehículo remolcado tiene un GVWR que excede las 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Según la Hoja Informativa de la Licencia de Conducir Comercial de Pennsylvania DMV (junio de 2025) y la PUB 223, una CDL Clase A cubre un vehículo combinado con un GCWR de 26,001 libras o más, siempre que el GVWR del vehículo remolcado exceda las 10,000 libras. Fuente: Hoja Informativa de CDL de Pennsylvania DMV / Manual del Conductor Comercial (PUB 223)."},"21":{"q":"Según las reglas de CDL de Pensilvania, un solo vehículo con una Calificación de Peso Bruto Vehicular (GVWR) de 26,001 libras o más (o tal vehículo remolcando una unidad de no más de 10,000 libras) requiere qué clase de licencia?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"Pennsylvania DMV define la Clase B como un solo vehículo con un GVWR de 26,001 libras o más, o cualquier vehículo de ese tipo que remolque un vehículo de no más de 10,000 libras. Fuente: Hoja Informativa de CDL de Pennsylvania DMV (junio de 2025) / PUB 223."},"22":{"q":"Según Pennsylvania DMV, una CDL Clase C de Pensilvania se usa para un solo vehículo de menos de 26,001 libras de GVWR que transporta materiales peligrosos con placa, lleva 16 o más personas, o es un autobús escolar. ¿Qué debe incluir además una CDL Clase C?","options":["Un endoso S, P o H","Un endoso de motocicleta (M)","Una certificación de frenos de aire Clase A","Una exención de vehículo agrícola"],"explanation":"La Hoja Informativa de CDL de Pennsylvania DMV establece que una CDL Clase C cubre vehículos individuales de menos de 26,001 lbs de GVWR que transportan materiales peligrosos con placa, están diseñados para llevar 16 o más personas incluyendo al conductor, o son un autobús escolar, y que una CDL Clase C debe incluir un endoso S, P o H. Fuente: Hoja Informativa de CDL de Pennsylvania DMV (junio de 2025)."},"23":{"q":"En Pensilvania, ¿qué autoriza hacer el endoso 'N' a un titular de CDL?","options":["Operar vehículos cisterna","Operar dobles y triples remolques","Llevar pasajeros en un autobús","Transportar materiales peligrosos con placa"],"explanation":"Pennsylvania DMV establece que el endoso N autoriza al conductor a operar vehículos cisterna. (El endoso T es para dobles/triples, el P para pasajeros y el H para materiales peligrosos con placa.) Fuente: Hoja Informativa de CDL de Pennsylvania DMV (junio de 2025) / PUB 223."},"24":{"q":"¿Qué endoso de CDL de Pensilvania se requiere para conducir dobles y triples remolques?","options":["Endoso T","Endoso N","Endoso X","Endoso H"],"explanation":"Pennsylvania DMV establece que el endoso T autoriza la conducción de dobles y triples remolques. Fuente: Hoja Informativa de CDL de Pennsylvania DMV (junio de 2025) / PUB 223."},"25":{"q":"En una CDL de Pensilvania, ¿qué representa el endoso combinado 'X'?","options":["Tanto materiales peligrosos como vehículo cisterna (H y N)","Tanto pasajeros como autobús escolar (P y S)","Tanto dobles/triples como cisterna (T y N)","Un endoso vencido pendiente de renovación"],"explanation":"Pennsylvania DMV enumera el endoso X como materiales peligrosos y vehículo cisterna combinados (H,N). Fuente: Hoja Informativa de CDL de Pennsylvania DMV (junio de 2025)."},"26":{"q":"¿Cuál es la edad mínima para obtener una CDL de Pensilvania para conducir dentro del estado (operar un vehículo comercial únicamente dentro de Pensilvania)?","options":["18 años","16 años","19 años","21 años"],"explanation":"Pensilvania requiere una edad mínima de 18 años para tener una CDL para conducción comercial dentro del estado (solo intraestatal). Fuente: Driver and Vehicle Services de Pennsylvania DMV, Conductores Comerciales / Tipos de Licencia y Restricciones."},"27":{"q":"¿Cuál es la edad mínima requerida para operar un vehículo comercial motorizado en comercio interestatal (cruzando líneas estatales) con una CDL de Pensilvania?","options":["21 años","18 años","19 años","25 años"],"explanation":"Para operar un CMV en comercio interestatal, un conductor debe tener al menos 21 años. Los conductores de 18 a 20 años solo pueden operar dentro de Pensilvania (intraestatal). Fuente: Conductores Comerciales de Pennsylvania DMV / 49 CFR 391.11 según se aplica en Pensilvania."},"28":{"q":"Después de aprobar el examen de conocimientos requerido y de que se le emita un permiso de aprendiz comercial de Pensilvania, ¿cuál es el período mínimo de espera antes de que se pueda programar un examen de habilidades de Clase A, B o C?","options":["15 días","10 días","30 días","7 días"],"explanation":"Según Pennsylvania DMV, el examen de habilidades no se puede tomar hasta 15 días después de aprobar el examen de conocimientos y que se emita el permiso. Esto satisface el requisito federal de retención de 14 días del CLP. Fuente: Hoja Informativa de CDL de Pennsylvania DMV (junio de 2025) y Preguntas Frecuentes sobre el Permiso de Aprendiz de CDL."},"29":{"q":"¿Por cuánto tiempo es válida una Autorización para el Examen de Conocimientos (KTA) / permiso de aprendiz comercial de Pensilvania, dando al solicitante tiempo para aprobar todos los exámenes de conocimientos y habilidades?","options":["Un año a partir de la fecha de emisión","90 días a partir de la fecha de emisión","Seis meses a partir de la fecha de emisión","Dos años a partir de la fecha de emisión"],"explanation":"Pennsylvania DMV establece que la KTA es válida por un año a partir de la fecha de emisión, y los solicitantes tienen un año para aprobar todos los exámenes de conocimientos y habilidades para obtener su CDL. Fuente: Preguntas Frecuentes sobre el Permiso de Aprendiz de CDL de Pennsylvania DMV."},"30":{"q":"Toda persona que solicite un permiso de aprendiz comercial de Pensilvania o que tenga una CDL debe completar qué documento que identifique el tipo de operación comercial que realiza?","options":["Un Formulario de Autocertificación (DL-11CD)","Un formulario de exención de REAL ID","Un formulario de registro prorrateado de IRP","Un Formulario I-9 de autorización de empleo"],"explanation":"Pennsylvania DMV requiere que todo titular de CDL y todo solicitante de CLP presente un Formulario de Autocertificación (DL-11CD) que identifique su tipo de conducción. Fuente: Hoja Informativa de CDL de Pennsylvania DMV (junio de 2025) y Preguntas Frecuentes sobre Autocertificación/Examinador Médico."},"31":{"q":"¿Cuál de las siguientes es una de las cuatro categorías de autocertificación médica que un solicitante de CDL de Pensilvania debe elegir?","options":["Interestatal no exento (Non-excepted Interstate)","Fuera del estado exento (Excepted Out-of-State)","Interestatal con placa (Placarded Interstate)","Intraestatal restringido (Restricted Intrastate)"],"explanation":"Las cuatro categorías de autocertificación son Interestatal no exento, Intraestatal no exento, Interestatal exento e Intraestatal exento. Un conductor Interestatal no exento debe tener un Certificado de Examinador Médico válido en archivo con Pennsylvania DMV. Fuente: Preguntas Frecuentes sobre Autocertificación/Examinador Médico de Pennsylvania DMV."},"32":{"q":"Un conductor de Pensilvania que se autocertifica como 'Intraestatal no exento' está sujeto a las normas federales de aptitud física mientras conduce únicamente dentro del estado. ¿Qué restricción de licencia agrega Pennsylvania DMV en este caso?","options":["Una restricción 'K' (solo comercio intraestatal)","Una restricción 'L' (sin frenos de aire)","Una restricción 'E' (sin transmisión manual)","Una restricción 'O' (sin combinación de quinta rueda)"],"explanation":"Pennsylvania DMV aplica la restricción K que limita al conductor solo al comercio intraestatal. La restricción K aparece para la operación comercial solo dentro del estado. Fuente: Hoja Informativa de CDL de Pennsylvania DMV (junio de 2025) y Preguntas Frecuentes sobre Autocertificación."},"33":{"q":"A partir del 7 de febrero de 2022, la Capacitación para Conductores de Nivel Inicial (ELDT) es requerida en Pensilvania para los solicitantes por primera vez de qué credencial(es)?","options":["Una primera CDL Clase A o B, o un primer endoso P, S o H","Cualquier renovación de CDL sin importar la clase","Solo un endoso de HazMat (H)","Solo las CDL Clase C intraestatales"],"explanation":"Según las reglas de la FMCSA adoptadas por Pennsylvania DMV, la ELDT (vigente desde el 7 de febrero de 2022) se aplica a la obtención de una CDL Clase A o B por primera vez, a la actualización a Clase A o B, o a la obtención de un endoso P, S o H por primera vez. No es retroactiva. Fuente: página de Capacitación para Conductores de Nivel Inicial de Pennsylvania DMV / 49 CFR Parte 380."},"34":{"q":"¿Dónde debe obtener un conductor de nivel inicial de Pensilvania su capacitación ELDT requerida antes de tomar el examen de habilidades?","options":["De un proveedor incluido en el Registro de Proveedores de Capacitación (TPR) de la FMCSA","De cualquier centro de licencias de conducir de Pennsylvania DMV","De un programa informal de capacitación en el trabajo del empleador","De cualquier escuela de manejo afiliada a AAA"],"explanation":"Pennsylvania DMV requiere que la ELDT se complete con un proveedor incluido en el Registro de Proveedores de Capacitación (TPR) de la FMCSA (tpr.fmcsa.dot.gov) antes del examen de habilidades. Fuente: Hoja Informativa de CDL de Pennsylvania DMV (junio de 2025) / página de Capacitación para Conductores de Nivel Inicial."},"35":{"q":"Para obtener un endoso de HazMat (H) de Pensilvania, el solicitante debe aprobar un examen de conocimientos y completar qué verificación federal de antecedentes?","options":["Una Evaluación de Amenazas a la Seguridad de la TSA con toma de huellas dactilares","Una verificación de empleo E-Verify","Una revisión del historial de conducción solo de Pennsylvania DMV","Una certificación médica de la FAA"],"explanation":"Pennsylvania DMV requiere que los solicitantes de HazMat completen una Evaluación de Amenazas a la Seguridad de la Administración de Seguridad en el Transporte (TSA) federal, incluyendo la toma de huellas dactilares (Formulario DL-288, PUB 512). Pennsylvania DMV debe recibir la aprobación federal antes de emitir el endoso H. Fuente: Hoja Informativa del Endoso de Materiales Peligrosos de Pennsylvania DMV (FS-HM) y Preguntas Frecuentes."},"36":{"q":"En los exámenes de conocimientos oficiales de CDL de Pennsylvania DMV, ¿cuántas preguntas tiene el examen del endoso de Materiales Peligrosos (H)?","options":["30 preguntas","20 preguntas","25 preguntas","50 preguntas"],"explanation":"Pennsylvania DMV indica que el examen de conocimientos del Endoso de Materiales Peligrosos tiene 30 preguntas, y el examen de HazMat se ofrece únicamente en inglés. Fuente: Hoja Informativa de CDL de Pennsylvania DMV (junio de 2025)."},"37":{"q":"Antes de obtener un endoso de Autobús Escolar (S) de Pensilvania, ¿qué endoso debe tener también el conductor?","options":["El endoso de Pasajeros (P)","El endoso de Cisterna (N)","El endoso de Dobles/Triples (T)","El endoso de HazMat (H)"],"explanation":"Pennsylvania DMV requiere el endoso de Pasajeros (P) como requisito previo para el endoso de Autobús Escolar (S); el examen de conocimientos S requiere el endoso de pasajeros. Fuente: Hoja Informativa de CDL de Pennsylvania DMV (junio de 2025) / Preguntas Frecuentes sobre Transporte Escolar."},"38":{"q":"¿Cuál de las siguientes afirmaciones sobre la tarjeta de endoso de Autobús Escolar (S) de Pensilvania es correcta según Pennsylvania DMV?","options":["Una tarjeta de endoso de Autobús Escolar se emite anualmente","El endoso S nunca requiere renovación","El endoso S se emite solo cada ocho años","La tarjeta de endoso S la envía por correo la TSA"],"explanation":"La Hoja Informativa de CDL de Pennsylvania DMV señala que el endoso S autoriza operar un autobús escolar y que una tarjeta de endoso de Autobús Escolar se emite anualmente. Fuente: Hoja Informativa de CDL de Pennsylvania DMV (junio de 2025)."},"39":{"q":"Al solicitar en persona una CDL/CLP de Pensilvania, un solicitante generalmente debe presentar prueba de identidad y estatus legal, prueba del número de Seguro Social, y ¿cuántas pruebas de residencia en Pensilvania?","options":["Dos pruebas de residencia en Pensilvania","Una prueba de residencia en Pensilvania","Tres pruebas de residencia en Pensilvania","No se requiere prueba de residencia"],"explanation":"Pennsylvania DMV requiere un documento que pruebe la identidad/estatus legal, un documento que pruebe el número de Seguro Social y dos documentos que prueben la residencia en Pensilvania. Fuente: requisitos de Prueba de Identidad y Residencia de Pennsylvania DMV (PUB 195US)."},"40":{"q":"En Pensilvania, ¿cuál es la concentración máxima de alcohol en sangre (BAC) igual o superior a la cual se considera que un conductor está operando un vehículo comercial motorizado (CMV) bajo los efectos del alcohol?","options":["0.02 por ciento","0.04 por ciento","0.08 por ciento","0.10 por ciento"],"explanation":"Pensilvania prohíbe operar un CMV con un BAC de 0.04 por ciento o más, la mitad del límite de 0.08 por ciento para conductores no comerciales. Fuente: Manual de CDL de PA; 75 Pa.C.S. y 49 CFR 383.51."},"41":{"q":"Según las reglas de consentimiento implícito de Pensilvania, ¿qué le sucede a un conductor de CMV que se niega a someterse a una prueba química después de una advertencia adecuada del oficial?","options":["Solo una advertencia por escrito sin descalificación","Una descalificación de la CDL de 30 días","Una descalificación de la CDL de 1 año, tratada como una condena por DUI","Una descalificación de la CDL de 6 meses"],"explanation":"Un conductor de CMV que se niega a la prueba química es descalificado por al menos 1 año, lo mismo que una condena por una infracción mayor. Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51."},"42":{"q":"En Pensilvania, una primera infracción mayor (como operar un CMV con un BAC de 0.04 por ciento o más) resulta en una descalificación de la CDL de al menos cuánto tiempo?","options":["60 días","6 meses","1 año","3 años"],"explanation":"Una primera infracción mayor descalifica a un titular de CDL de Pensilvania por un mínimo de 1 año. Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51."},"43":{"q":"En Pensilvania, si un conductor comete una primera infracción mayor mientras opera un CMV que lleva placa de materiales peligrosos, el período de descalificación aumenta a:","options":["1 año","2 años","3 años","5 años"],"explanation":"Una primera infracción mayor cometida mientras se transportan materiales peligrosos con placa aumenta la descalificación de 1 año a 3 años. Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51."},"44":{"q":"¿Cuál es el período de descalificación de la CDL en Pensilvania por una segunda infracción mayor (por ejemplo, un segundo DUI en un CMV)?","options":["3 años","5 años","10 años","De por vida"],"explanation":"Dos infracciones mayores en cualquier vehículo resultan en una descalificación de la CDL de por vida en Pensilvania. Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51."},"45":{"q":"En Pensilvania, ser condenado por DOS infracciones graves de tránsito en incidentes separados dentro de un período de 3 años resulta en una descalificación de la CDL de:","options":["30 días","60 días","120 días","1 año"],"explanation":"Dos infracciones graves de tránsito dentro de 3 años descalifican a un titular de CDL de Pensilvania por 60 días. Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51."},"46":{"q":"En Pensilvania, ser condenado por TRES infracciones graves de tránsito en incidentes separados dentro de un período de 3 años resulta en una descalificación de la CDL de:","options":["60 días","90 días","120 días","1 año"],"explanation":"Tres infracciones graves de tránsito dentro de 3 años descalifican a un titular de CDL de Pensilvania por 120 días, cumplidos de forma consecutiva después de cualquier descalificación de 60 días. Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51."},"47":{"q":"¿Cuál de las siguientes se clasifica como una infracción GRAVE de tránsito para un titular de CDL de Pensilvania?","options":["Una luz trasera fundida","Exceder el límite de velocidad por 15 mph o más","Estacionar en una zona de no detenerse","Conducir con un registro vencido"],"explanation":"Exceder la velocidad en 15 mph o más sobre el límite es una infracción grave de tránsito; otras incluyen conducción imprudente, cambio de carril indebido, seguir demasiado de cerca, enviar mensajes de texto y uso de teléfono de mano. Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51."},"48":{"q":"Para un conductor con CDL de Pensilvania, ¿cuál es la descalificación por una PRIMERA condena por violar una ley de cruce a nivel de ferrocarril y carretera?","options":["30 días","60 días","120 días","1 año"],"explanation":"Una primera infracción de cruce a nivel de ferrocarril descalifica a un titular de CDL de Pensilvania por 60 días. Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51."},"49":{"q":"Para un conductor con CDL de Pensilvania, una SEGUNDA infracción de cruce a nivel de ferrocarril y carretera dentro de un período de 3 años resulta en una descalificación de:","options":["60 días","120 días","1 año","3 años"],"explanation":"Una segunda infracción de cruce a nivel de ferrocarril dentro de 3 años descalifica a un titular de CDL de Pensilvania por 120 días. Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51."},"50":{"q":"Para un conductor con CDL de Pensilvania, una TERCERA infracción o subsiguiente de cruce a nivel de ferrocarril y carretera dentro de un período de 3 años resulta en una descalificación de:","options":["120 días","180 días","1 año","3 años"],"explanation":"Una tercera infracción o subsiguiente de cruce a nivel de ferrocarril dentro de 3 años descalifica a un titular de CDL de Pensilvania por 1 año. Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51."},"51":{"q":"En Pensilvania, una PRIMERA condena por violar una orden de fuera de servicio (OOS) mientras se transportan materiales NO peligrosos descalifica a un conductor con CDL por:","options":["90 días","180 días","1 año","2 años"],"explanation":"Una primera infracción de una orden de fuera de servicio (sin materiales peligrosos) descalifica a un titular de CDL de Pensilvania por al menos 1 año. Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51."},"52":{"q":"En Pensilvania, una SEGUNDA infracción de una orden de fuera de servicio dentro de un período de 10 años (sin materiales peligrosos) resulta en una descalificación de la CDL de:","options":["1 año","2 años","3 años","5 años"],"explanation":"Una segunda infracción de una orden de fuera de servicio dentro de 10 años (sin materiales peligrosos) descalifica a un titular de CDL de Pensilvania por al menos 3 años. Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51."},"53":{"q":"En Pensilvania, una PRIMERA infracción de una orden de fuera de servicio mientras se transportan materiales peligrosos o se llevan 16 o más pasajeros descalifica a un conductor con CDL por:","options":["1 año","2 años","3 años","5 años"],"explanation":"Una primera infracción de una orden de fuera de servicio mientras se transportan materiales peligrosos o se llevan 16 o más pasajeros descalifica a un titular de CDL de Pensilvania por al menos 2 años. Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51."},"54":{"q":"En Pensilvania, una SEGUNDA infracción de una orden de fuera de servicio dentro de 10 años mientras se transportan materiales peligrosos o se llevan 16 o más pasajeros descalifica a un conductor con CDL por:","options":["2 años","3 años","5 años","De por vida"],"explanation":"Una segunda infracción de una orden de fuera de servicio dentro de 10 años mientras se transportan materiales peligrosos o se llevan 16 o más pasajeros descalifica a un titular de CDL de Pensilvania por al menos 5 años. Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51."},"55":{"q":"Para un titular de CDL de Pensilvania, usar un teléfono móvil de mano mientras conduce un CMV se trata como:","options":["Una infracción de equipo no reportable","Una infracción grave de tránsito que puede llevar a la descalificación","Una descalificación automática de 1 año en la primera infracción","Una infracción de descalificación de por vida"],"explanation":"Usar un teléfono de mano mientras se opera un CMV es una infracción grave de tránsito; dos dentro de 3 años causan una descalificación de 60 días y tres causan 120 días. Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51 y 392.82."},"56":{"q":"Para un titular de CDL de Pensilvania, enviar mensajes de texto mientras conduce un vehículo comercial motorizado es:","options":["Permitido si el vehículo está detenido en un semáforo","Una infracción grave de tránsito que puede llevar a la descalificación","Solo una multa tipo estacionamiento sin efecto en la licencia","Permitido para la comunicación con el despacho"],"explanation":"Enviar mensajes de texto mientras se opera un CMV es una infracción grave de tránsito; acumular estas dentro de 3 años lleva a descalificaciones de 60 o 120 días. Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51 y 392.80."},"57":{"q":"En Pensilvania, ¿qué condena conlleva una descalificación de la CDL DE POR VIDA SIN opción de restablecimiento después de 10 años?","options":["Un segundo DUI en un CMV","Usar un CMV para cometer un delito grave que involucre la fabricación o distribución de una sustancia controlada","Dos infracciones graves de tránsito dentro de 3 años","Una primera infracción de una orden de fuera de servicio"],"explanation":"Usar un CMV en un delito grave que involucre la fabricación, distribución o dispensación de una sustancia controlada resulta en una descalificación de por vida que no puede reducirse. Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51."},"58":{"q":"Un conductor con CDL de Pensilvania condenado por una infracción mayor que resulta en una muerte debido a la operación negligente o criminal de un CMV es descalificado por al menos:","options":["60 días","120 días","1 año","5 años"],"explanation":"Causar una muerte mediante la operación negligente o criminal de un CMV es una infracción mayor que conlleva una descalificación mínima de 1 año (3 años si lleva placa de materiales peligrosos). Fuente: hoja informativa de Descalificaciones e Infracciones de Tránsito de Pennsylvania DMV; 49 CFR 383.51."},"59":{"q":"Según la ley de autobuses escolares de Pensilvania, cuando un autobús escolar tiene sus luces de señal rojas intermitentes encendidas y el brazo de pare extendido, ¿a qué distancia antes de llegar al autobús debe detenerse un conductor que se aproxima de frente o que lo va a rebasar?","options":["Al menos 10 feet","Al menos 15 feet","Al menos 20 feet","Al menos 25 feet"],"explanation":"Pensilvania exige que los conductores que se aproximan de frente o que van a rebasar a un autobús escolar con luces de señal rojas intermitentes se detengan al menos a 10 feet del autobús y no avancen hasta que las luces dejen de parpadear y el brazo de pare se retraiga. Fuente: 75 Pa.C.S. § 3345 (Encuentro o rebase de un autobús escolar); Manual de Conductor Comercial de PA (PUB 223)."},"60":{"q":"En una carretera de Pensilvania con calzadas separadas divididas por una barrera física o una sección divisoria claramente indicada, un conductor que circula por la calzada OPUESTA a la de un autobús escolar detenido con luces rojas intermitentes debe:","options":["No estar obligado a detenerse","Detenerse al menos a 10 feet de la mediana","Detenerse solo si hay niños visibles","Reducir a 15 mph pero no necesita detenerse"],"explanation":"La excepción de carretera dividida de Pensilvania establece que un conductor en una carretera con calzadas separadas no necesita detenerse por un autobús escolar con luces rojas intermitentes que está en una calzada DIFERENTE. Una 'calzada separada' requiere una barrera física o una sección divisoria claramente indicada; las líneas pintadas o las señales por sí solas no la crean. Fuente: 75 Pa.C.S. § 3345."},"61":{"q":"¿Qué característica se REQUIERE para que aplique la excepción de 'calzadas separadas' de autobuses escolares de Pensilvania (de modo que el tránsito en sentido contrario no necesite detenerse)?","options":["Una barrera física o una sección divisoria claramente indicada","Una línea central doble amarilla","Un carril central para giro a la izquierda","Una señal instalada que diga 'DIVIDED HIGHWAY'"],"explanation":"En Pensilvania la excepción aplica únicamente donde las calzadas están separadas por una barrera física o una sección divisoria claramente indicada. Las marcas en el pavimento o las señales por sí solas NO se interpretan como creadoras de una calzada separada, por lo que en vías divididas solo por pintura, todas las direcciones deben detenerse de todos modos. Fuente: 75 Pa.C.S. § 3345."},"62":{"q":"Un vehículo obligado a detenerse en un cruce a nivel de ferrocarril en Pensilvania debe detenerse dentro de qué distancia del riel más cercano?","options":["Dentro de 50 feet pero no menos de 15 feet","Dentro de 100 feet pero no menos de 25 feet","Dentro de 30 feet pero no menos de 10 feet","Dentro de 75 feet pero no menos de 20 feet"],"explanation":"La ley de Pensilvania exige que los vehículos que deben detenerse en cruces de ferrocarril (autobuses escolares, autobuses de pasajeros y camiones que transportan ciertos combustibles/explosivos/materiales radiactivos) se detengan dentro de 50 feet pero no menos de 15 feet del riel más cercano, y luego miren y escuchen. Fuente: 75 Pa.C.S. § 3342 (Vehículos obligados a detenerse en cruces de ferrocarril); Manual CDL de PA."},"63":{"q":"¿Cuál vehículo NO está obligado a detenerse en todo cruce a nivel de ferrocarril según la ley de Pensilvania?","options":["Un tractocamión con caja seca vacía que no transporta materiales peligrosos","Un autobús escolar, lleve o no pasajeros","Un autobús que transporta pasajeros","Un camión que transporta explosivos con placard"],"explanation":"Pensilvania exige que los autobuses escolares (cargados o vacíos), los autobuses que transportan pasajeros y los camiones que transportan gasolina, diésel/fuel oil, explosivos o materiales radiactivos se detengan en los cruces. Una caja de carga vacía común sin carga peligrosa no está obligada a detenerse. Fuente: 75 Pa.C.S. § 3342."},"64":{"q":"Cuando un CMV de Pensilvania que debe detenerse está cruzando vías de ferrocarril, ¿qué se le prohíbe específicamente hacer al conductor?","options":["Cambiar de marcha manualmente mientras está sobre las vías","Usar el freno motor","Cruzar en marcha baja","Activar las luces intermitentes de cuatro vías"],"explanation":"La ley de Pensilvania ordena que un conductor obligado a detenerse cruce en una marcha que no requiera cambiar de velocidad mientras cruza, y no debe cambiar de marcha manualmente mientras está sobre la(s) vía(s). Fuente: 75 Pa.C.S. § 3342; Manual CDL de PA."},"65":{"q":"En un cruce de ferrocarril de Pensilvania señalizado con un letrero que dice 'EXEMPT', un camión de materiales peligrosos con placard o un autobús:","options":["No está obligado a detenerse","Aún debe detenerse dentro de 50 feet del riel","Debe detenerse y tocar el claxon","Debe detenerse solo si hay una barrera"],"explanation":"Pensilvania exime de la regla de parada obligatoria a los cruces señalizados con un letrero 'exempt' (y a los cruces abandonados señalizados como tales); un oficial o señalero que dirija al vehículo a pasar, o un semáforo en verde, también eximen del deber de detenerse. Fuente: 75 Pa.C.S. § 3342."},"66":{"q":"Según la ley Move Over de Pensilvania, cuando un conductor NO PUEDE cambiarse con seguridad a un carril no adyacente cerca de una zona de respuesta de emergencia, el conductor debe en su lugar pasar a una velocidad no mayor de cuánto por debajo del límite indicado?","options":["20 mph por debajo del límite de velocidad indicado","10 mph por debajo del límite de velocidad indicado","15 mph por debajo del límite de velocidad indicado","25 mph por debajo del límite de velocidad indicado"],"explanation":"La ley Move Over (Steer Clear) de Pensilvania exige pasar por un carril no adyacente a la zona de respuesta de emergencia cuando sea posible; si eso es imposible, ilegal o inseguro, el conductor debe pasar a no más de 20 mph por debajo del límite de velocidad indicado y a una velocidad razonable para la seguridad. Fuente: 75 Pa.C.S. § 3327."},"67":{"q":"La ley Move Over de Pensilvania (Act 105 of 2020) asigna cuántos puntos por no incorporarse a un carril no adyacente a una zona de respuesta de emergencia?","options":["2 puntos","3 puntos","4 puntos","5 puntos"],"explanation":"El Act 105 of 2020 agregó una penalización de 2 puntos por no cambiarse de carril, además de multas crecientes de $500 (primera), $1,000 (segunda) y $2,000 con una suspensión de 90 días (tercera o subsiguiente). Fuente: 75 Pa.C.S. § 3327; campaña Move Over de PennDOT."},"68":{"q":"Además de la policía, los bomberos, las ambulancias y las grúas, ¿a cuál de los siguientes también protege la ley Move Over de Pensilvania?","options":["Un vehículo averiado que muestra al menos dos señalizaciones de emergencia (por ejemplo, luces de emergencia y bengalas)","Cualquier vehículo estacionado legalmente en el acotamiento","Solo los vehículos propiedad del gobierno","Vehículos detenidos en un semáforo en rojo"],"explanation":"Pensilvania extendió el deber Move Over a los vehículos averiados que muestran al menos dos señalizaciones de emergencia, tales como luces de emergencia, señales/dispositivos de precaución o bengalas de carretera. Los conductores deben cambiar de carril o reducir a no más de 20 mph por debajo del límite. Fuente: 75 Pa.C.S. § 3327 (deber en relación con vehículos averiados)."},"69":{"q":"En una carretera de acceso limitado de Pensilvania con tres o más carriles en un sentido, ¿por dónde puede circular una combinación de camión de más de 10,000 pounds?","options":["Cualquier carril excepto el carril izquierdo (que está prohibido salvo para prepararse para un giro a la izquierda permitido)","Solo el carril central en todo momento","Solo el carril derecho en todo momento","Cualquier carril, sin restricción"],"explanation":"Pensilvania prohíbe que un vehículo o combinación de más de 10,000 pounds circule en el carril IZQUIERDO de una carretera de acceso limitado que tenga tres o más carriles en el mismo sentido, excepto cuando se prepara para un giro a la izquierda legalmente permitido en una intersección, salida o entrada de vehículos. Fuente: 75 Pa.C.S. § 3313 (Restricciones sobre el uso de carreteras de acceso limitado)."},"70":{"q":"En las carreteras de acceso limitado de Pensilvania con dos o más carriles en un sentido, la regla general para todos los vehículos es circular por los carriles derechos EXCEPTO cuando:","options":["Se rebasa y adelanta, se circula más rápido que el flujo del tránsito o se prepara para un giro a la izquierda permitido","Se conduce de noche","El camino está mojado","Un pasajero solicita el carril izquierdo"],"explanation":"Pensilvania exige que los vehículos usen los carriles derechos cuando estén disponibles, excepto cuando rebasan y adelantan a un vehículo, circulan a una velocidad mayor que el flujo del tránsito o se preparan para un giro a la izquierda legalmente permitido. Fuente: 75 Pa.C.S. § 3313."},"71":{"q":"En ausencia de un letrero instalado, el límite de velocidad máximo predeterminado en la mayoría de las carreteras de Pensilvania (que no sean distritos urbanos ni autopistas) es:","options":["55 mph","50 mph","60 mph","65 mph"],"explanation":"Pensilvania establece un máximo legal de 55 mph en lugares no señalizados de otra manera, 35 mph en cualquier distrito urbano, y hasta 65 o 70 mph en autopistas donde el departamento instale ese límite. Fuente: 75 Pa.C.S. § 3362 (Límites de velocidad máximos)."},"72":{"q":"En una autopista de Pensilvania señalizada a 70 mph, ¿cómo se compara el límite de velocidad máximo para un camión comercial pesado con el de un automóvil de pasajeros?","options":["Es el mismo: 70 mph aplica a todos los vehículos","Los camiones están limitados a 55 mph","Los camiones están limitados a 60 mph","Los camiones están limitados a 65 mph"],"explanation":"Pensilvania no establece un límite de velocidad separado y más bajo para camiones; el máximo señalizado de 65 o 70 mph en la autopista aplica a todos los vehículos. (Pueden aplicar límites más bajos en bajadas específicas o mediante letreros instalados). Fuente: 75 Pa.C.S. § 3362."},"73":{"q":"El límite de velocidad máximo señalizado en la vía principal de la Pennsylvania Turnpike (I-76) es:","options":["70 mph","65 mph","75 mph","80 mph"],"explanation":"El límite de velocidad máximo señalizado de la Pennsylvania Turnpike es 70 mph, vigente en la mayor parte de la vía principal (por ejemplo, entre los intercambiadores de Blue Mountain y Morgantown) y en muchas autopistas de PennDOT. Ningún tramo está señalizado a 75 mph. Fuente: Pennsylvania Turnpike Commission / PennDOT; 75 Pa.C.S. § 3362."},"74":{"q":"El límite de velocidad legal en distrito urbano de Pensilvania, donde no se haya instalado otro límite, es:","options":["35 mph","25 mph","30 mph","40 mph"],"explanation":"En cualquier distrito urbano, la velocidad máxima legal de Pensilvania es 35 mph a menos que se instale un límite diferente tras un estudio de tránsito. Fuente: 75 Pa.C.S. § 3362."},"75":{"q":"Un conductor de camión cuyo CMV está detenido sobre la parte transitada de una carretera de Pensilvania de dos carriles y doble sentido debe colocar dispositivos de advertencia dentro de qué tiempo, y dónde?","options":["Dentro de 10 minutos: a 10 ft, 100 ft hacia atrás y 100 ft hacia adelante","Dentro de 15 minutos: a 25 ft, 50 ft y 100 ft","Dentro de 30 minutos: a 10 ft, 200 ft y 300 ft","Dentro de 5 minutos: los tres dentro de 50 ft"],"explanation":"Siguiendo la norma federal que Pensilvania aplica, un CMV detenido debe colocar dispositivos de advertencia dentro de 10 minutos. En una vía de doble sentido, coloque uno a 10 ft del vehículo hacia el tránsito que se aproxima, uno a unos 100 ft hacia atrás y uno a unos 100 ft hacia adelante. Fuente: Manual CDL de PA (PUB 223); 49 CFR 392.22."},"76":{"q":"Cuando un CMV está detenido en una carretera de Pensilvania de un solo sentido o dividida, ¿dónde se colocan los tres dispositivos de advertencia hacia el tránsito que se aproxima?","options":["A unos 10 ft, 100 ft y 200 ft hacia atrás","A unos 10 ft, 50 ft y 100 ft hacia atrás","A unos 25 ft, 100 ft y 250 ft hacia atrás","A unos 10 ft, 100 ft y 150 ft hacia atrás"],"explanation":"En una carretera de un solo sentido o dividida, coloque los dispositivos de advertencia a unos 10 feet, 100 feet y 200 feet hacia el tránsito que se aproxima (el lado por donde viene el tránsito), dentro de 10 minutos de haberse detenido. Fuente: Manual CDL de PA (PUB 223); 49 CFR 392.22."},"77":{"q":"¿Qué clase de materiales peligrosos tiene PROHIBIDO ser transportada a través de los túneles de la Pennsylvania Turnpike?","options":["Todos los explosivos y otros materiales de la Table 1 (por ejemplo, gas venenoso, radiactivos)","Solo líquidos inflamables a granel","Solo materiales corrosivos","Solo gases refrigerados"],"explanation":"La Pennsylvania Turnpike prohíbe todos los materiales de la Table 1 —incluidos todos los explosivos, gas venenoso, peligrosos al contacto con agua, peligro de inhalación venenosa y materiales radiactivos— en sus túneles; ciertos envíos no a granel de otros materiales peligrosos pueden permitirse. Fuente: Restricciones de Materiales Peligrosos en Túneles de la Pennsylvania Turnpike Commission; 67 Pa. Code § 601.5."},"78":{"q":"Un conductor condenado por rebasar ilegalmente un autobús escolar detenido con luces rojas intermitentes en Pensilvania enfrenta una multa base más un recargo de:","options":["$250 de multa más un recargo de $35 (con puntos y una suspensión de licencia)","$100 de multa sin recargo","$500 de multa más un recargo de $50","$50 de multa más un recargo de $25"],"explanation":"Pensilvania penaliza el rebase ilegal de un autobús escolar detenido con una multa de $250 y un recargo de $35; una infracción observada por un oficial también conlleva 5 puntos y una suspensión de licencia de 60 días. Fuente: 75 Pa.C.S. § 3345."},"79":{"q":"¿Qué agencia emite las licencias de conducir comerciales (CDL) en Pensilvania?","options":["La Pennsylvania State Police, Commercial Vehicle Unit","El Pennsylvania Department of Transportation (PennDOT), Bureau of Driver and Vehicle Services","La Pennsylvania Public Utility Commission (PUC)","La Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"Las CDL de Pensilvania son emitidas por PennDOT a través de su Bureau of Driver and Vehicle Services. La FMCSA establece las normas federales pero no emite licencias estatales. Fuente: Hoja Informativa de la Licencia de Conducir Comercial de PennDOT (referencia PUB 223) y pa.gov Driver and Vehicle Services."},"80":{"q":"En Pensilvania, ¿cuál es la edad mínima para obtener una CDL para conducción intraestatal (dentro de Pensilvania) frente a la conducción interestatal?","options":["21 tanto para intraestatal como interestatal","16 para intraestatal y 18 para interestatal","18 para intraestatal y 21 para interestatal","18 tanto para intraestatal como interestatal"],"explanation":"Pensilvania permite una CDL a los 18 años solo para operación intraestatal, mientras que la operación interestatal (y el transporte de materiales peligrosos o de pasajeros a través de las fronteras estatales) requiere que el conductor tenga al menos 21 años. Fuente: requisitos de licenciamiento CDL de PennDOT (pa.gov) consistentes con 49 CFR 383.3."},"81":{"q":"Antes de presentar el examen de habilidades de la CDL en Pensilvania, un solicitante primero debe obtener qué credencial?","options":["Una exención médica de PennDOT","Un Commercial Learner's Permit (CLP)","Una licencia con fotografía conforme a REAL ID","Una CDL Class C no comercial"],"explanation":"Los solicitantes deben aprobar el/los examen(es) de conocimientos requeridos y obtener un Commercial Learner's Permit antes de poder presentar el examen de habilidades. Fuente: Preguntas Frecuentes del Permiso de Aprendizaje CDL de PennDOT y Hoja Informativa CDL (pa.gov)."},"82":{"q":"¿Qué formulario usa un solicitante de CDL o CLP de Pensilvania para autocertificar el tipo de conducción comercial que realiza?","options":["Solicitud de Registro del Conductor DL-503","Solicitud de Commercial Learner's Permit DL-31CD","Certificado del Examinador Médico DL-26","Formulario de Autocertificación DL-11CD"],"explanation":"Todo titular de CDL y todo solicitante de CLP debe presentar el Formulario de Autocertificación DL-11CD declarando su categoría de operación. El DL-31CD es la solicitud del CLP, un formulario distinto. Fuente: Preguntas Frecuentes de Autocertificación/Certificación del Examinador Médico de PennDOT y Formulario DL-11CD (pa.gov)."},"83":{"q":"¿Cuál de las siguientes NO es una de las cuatro categorías de autocertificación entre las que debe elegir un solicitante de CDL de Pensilvania?","options":["Operador Agrícola Exento","Intraestatal con Excepción (Excepted Intrastate)","Intraestatal sin Excepción (Non-excepted Intrastate)","Interestatal sin Excepción (Non-excepted Interstate)"],"explanation":"Las cuatro categorías de autocertificación son Interestatal sin Excepción, Interestatal con Excepción, Intraestatal sin Excepción e Intraestatal con Excepción. \"Operador Agrícola Exento\" no es una categoría de autocertificación. Fuente: Formulario de Autocertificación DL-11CD de PennDOT y Hoja Informativa CDL (pa.gov)."},"84":{"q":"¿Cuál categoría de autocertificación requiere que el conductor tenga un Certificado del Examinador Médico válido (tarjeta del examen físico DOT) registrado en PennDOT?","options":["Interestatal sin Excepción (Non-excepted Interstate)","Intraestatal con Excepción (Excepted Intrastate)","Interestatal con Excepción e Intraestatal con Excepción","Interestatal con Excepción (Excepted Interstate)"],"explanation":"Solo los conductores que se autocertifican como Sin Excepción (Interestatal o Intraestatal) deben mantener un Certificado del Examinador Médico válido registrado en PennDOT. Las categorías con Excepción no están obligadas a proporcionar un MEC. Fuente: Preguntas Frecuentes de Autocertificación/Certificación del Examinador Médico de PennDOT (pa.gov)."},"85":{"q":"A partir del June 23, 2025, ¿cómo debe presentarse a PennDOT el Certificado del Examinador Médico (examen físico DOT) de un titular de CDL sin excepción de Pensilvania?","options":["Se transmite electrónicamente desde el FMCSA National Registry directamente a PennDOT","El conductor entrega la tarjeta de papel a un empleado en cualquier PennDOT Driver License Center","El conductor envía por correo electrónico una copia escaneada a PennDOT","El conductor envía la tarjeta de papel por correo a la PennDOT CDL Unit en Harrisburg"],"explanation":"Desde el June 23, 2025, PennDOT solo acepta la información del Certificado del Examinador Médico transmitida electrónicamente desde el FMCSA National Registry; ya no acepta MECs en persona, por correo postal ni por correo electrónico. Fuente: Preguntas Frecuentes de Autocertificación/Certificación del Examinador Médico de PennDOT (pa.gov)."},"86":{"q":"Los tres componentes del examen de habilidades de la CDL de Pensilvania son la inspección previa al viaje (del vehículo), el examen de conducción en carretera y ¿cuál tercer componente?","options":["Un examen escrito de conducción defensiva","Control básico del vehículo (maniobras fuera de la vía y estacionamiento)","Una prueba cronometrada de reflejos de reacción de frenado","Una simulación de laboratorio de acoplamiento y desacoplamiento"],"explanation":"El examen de habilidades de la CDL de Pensilvania tiene tres partes: inspección previa al viaje, control básico del vehículo (maniobras fuera de la vía y ejercicio de estacionamiento del vehículo) y el examen de conducción en carretera. Fuente: Hoja Informativa CDL de PennDOT, sección \"Skills Tests\" (pa.gov)."},"87":{"q":"¿Qué requisito de capacitación federal debe completar un solicitante de Pensilvania antes de que se le permita presentar el examen de habilidades de la CDL para una licencia Class A o Class B por primera vez?","options":["Un curso de conducción defensiva en aula administrado por PennDOT","Entry-Level Driver Training (ELDT) de un proveedor registrado","Un curso de seguridad OSHA de 40 horas","Un certificado de finalización de aprendizaje emitido por el estado"],"explanation":"El Entry-Level Driver Training (ELDT) de un proveedor en el FMCSA Training Provider Registry debe completarse antes de presentar el examen de habilidades para una CDL inicial Class A o B (y para las primeras endosos P, S o H). Fuente: Hoja Informativa CDL de PennDOT (pa.gov) y regla ELDT de la FMCSA (49 CFR Part 380)."},"88":{"q":"Según la Hoja Informativa CDL de PennDOT, ¿cuántas preguntas tiene el examen escrito de conocimientos generales de la Class A en Pensilvania?","options":["50 preguntas","30 preguntas","70 preguntas","100 preguntas"],"explanation":"La Hoja Informativa CDL de PennDOT indica que el examen escrito de conocimientos de la Class A tiene 70 preguntas, mientras que la Class B y la Class C tienen 50 preguntas cada una. Fuente: Hoja Informativa CDL de PennDOT, \"What Tests Do I Need to Take?\" (pa.gov)."},"89":{"q":"¿Cuántas preguntas tiene el examen de conocimientos del endoso de Materiales Peligrosos (HazMat) de Pensilvania, y en qué idioma se ofrece?","options":["25 preguntas, solo en inglés","30 preguntas, solo en inglés","50 preguntas, en varios idiomas","20 preguntas, en varios idiomas"],"explanation":"PennDOT indica que el examen de conocimientos del endoso HazMat tiene 30 preguntas, y el examen HazMat se ofrece solo en inglés (otros exámenes de conocimientos de la CDL están disponibles en varios idiomas). Fuente: Hoja Informativa CDL de PennDOT (pa.gov)."},"90":{"q":"Según la Hoja Informativa CDL de PennDOT, ¿qué tan pronto después de aprobar el examen de conocimientos y de que se emita un permiso puede un solicitante de Pensilvania presentar el examen de habilidades?","options":["No hasta 15 days después de aprobar el examen de conocimientos y de que se emita el permiso","No hasta 30 days después de que se emita el permiso","No hasta 60 days después de que se emita el permiso","Inmediatamente después de aprobar el examen de conocimientos"],"explanation":"PennDOT establece que el examen de habilidades no puede presentarse hasta 15 days después de aprobar el examen de conocimientos y de que se emita un permiso (un solicitante puede programar el examen de habilidades de inmediato, pero no puede presentarlo antes del punto de los 15 days). Fuente: Hoja Informativa CDL de PennDOT, nota de \"Skills Tests\" (pa.gov)."},"91":{"q":"¿Cuál es el período de vigencia estándar de una licencia de conducir comercial de Pensilvania antes de que deba renovarse (para un conductor menor de 65 años)?","options":["5 años","8 años","2 años","4 años"],"explanation":"Una CDL de Pensilvania generalmente es válida por 4 años; a los conductores de 65 años y mayores se les emite en un ciclo de 2 años. Fuente: información de licenciamiento de Driver and Vehicle Services de PennDOT (pa.gov)."},"92":{"q":"¿Por cuánto tiempo se emite una CDL de Pensilvania a un conductor que tiene 65 años de edad o más?","options":["4 años","2 años","3 años","1 año"],"explanation":"Si bien el ciclo estándar de la CDL de Pensilvania es de 4 años, los conductores de 65 años y mayores se colocan en un ciclo de renovación de 2 años. Fuente: información de licenciamiento de Driver and Vehicle Services de PennDOT (pa.gov)."},"93":{"q":"Si un titular de CDL sin excepción de Pensilvania deja que su Certificado del Examinador Médico expire y no proporciona uno nuevo, ¿qué le sucede a su licencia?","options":["La designación comercial (CDL) se degrada a una licencia no comercial","Se impone una penalización civil de $500 pero la CDL sigue siendo válida","La licencia se revoca permanentemente y no puede ser reinstalada","Nada cambia hasta la siguiente renovación de 4 años"],"explanation":"Si la certificación médica de un conductor sin excepción caduca, PennDOT retira la designación comercial y degrada la credencial a una licencia de conducir no comercial; el conductor debe volver a solicitar un CLP para recuperar los privilegios comerciales. Fuente: Preguntas Frecuentes de Autocertificación/Certificación del Examinador Médico de PennDOT (pa.gov)."},"94":{"q":"En Pensilvania, ¿qué documento se usa para solicitar el Commercial Learner's Permit en sí?","options":["Formulario MV-1, la solicitud de título del vehículo","Formulario DL-180, la solicitud de permiso de aprendizaje no comercial","Formulario DL-11CD, el Formulario de Autocertificación","Formulario DL-31CD, la Solicitud de Commercial Learner's Permit"],"explanation":"La Solicitud de Commercial Learner's Permit es el Formulario DL-31CD. El Formulario DL-11CD es el formulario de autocertificación distinto, y un solicitante de CLP normalmente presenta ambos. Fuente: Preguntas Frecuentes del Permiso de Aprendizaje CDL de PennDOT (pa.gov)."},"95":{"q":"Según las reglas de PennDOT, una vez que un solicitante de CDL de Pensilvania inicia el proceso, ¿cuánto tiempo tiene para aprobar todos los exámenes de conocimientos y de habilidades requeridos antes de tener que reiniciar?","options":["Seis meses","90 días","Un año","Dos años"],"explanation":"PennDOT le da al solicitante un año para aprobar todos los exámenes de conocimientos y de habilidades para obtener la CDL; el permiso puede extenderse con una nueva solicitud DL-31CD si las pruebas no se completan a tiempo. Fuente: Preguntas Frecuentes del Permiso de Aprendizaje CDL de PennDOT (pa.gov)."},"96":{"q":"Un conductor quiere una CDL Class C únicamente para operar un vehículo de 20 pasajeros. Según la Hoja Informativa CDL de PennDOT, ¿qué debe incluir una CDL Class C?","options":["Un endoso S, P o H","Ningún endoso de ningún tipo","Un endoso de doble/triple remolque","Solo un código de restricción de frenos de aire"],"explanation":"PennDOT define la Class C como vehículos individuales de menos de 26,001 lbs que transportan materiales peligrosos que requieren placard, llevan 16 o más pasajeros, o son autobuses escolares; la Hoja Informativa establece que una CDL Class C debe incluir un endoso S, P o H. Fuente: Hoja Informativa CDL de PennDOT, clases de licencia (pa.gov)."},"97":{"q":"Según la Hoja Informativa CDL de PennDOT, ¿cuál endoso requiere por separado el Entry-Level Driver Training la primera vez que se obtiene?","options":["El endoso de Materiales Peligrosos (H)","El endoso de Dobles/Triples (T)","El endoso de Vehículo Cisterna (N)","La eliminación de la restricción de frenos de aire"],"explanation":"La Hoja Informativa de PennDOT muestra que el ELDT se requiere (solo para el inicial) para los endosos de Pasajeros, Autobús Escolar y Materiales Peligrosos (H); los endosos de Dobles/Triples y Cisterna figuran como que no requieren ELDT. Fuente: tabla de endosos/exámenes de la Hoja Informativa CDL de PennDOT (pa.gov)."},"98":{"q":"Cuando un solicitante de Pensilvania se presenta para el examen de habilidades de la CDL, ¿qué vehículo debe llevar?","options":["Cualquier automóvil de pasajeros con un registro válido","Un vehículo de prueba propiedad de PennDOT asignado en el centro","Un vehículo de una clase menor que la CDL que se busca","Un vehículo representativo de la clase y el tipo que pretende conducir"],"explanation":"El examen de habilidades debe presentarse en un vehículo de la clase y el tipo que el solicitante pretende conducir (por ejemplo, el examen de habilidades del endoso de autobús escolar debe presentarse en un autobús escolar). Fuente: Hoja Informativa CDL de PennDOT, sección \"Skills Tests\" (pa.gov)."}},"hi":{"0":{"q":"पेंसिल्वेनिया के राजमार्गों पर, किसी वाहन की, उसके भार सहित, अधिकतम कुल बाहरी चौड़ाई क्या है?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"75 Pa.C.S. § 4921 (वाहनों की चौड़ाई) के अंतर्गत, किसी वाहन की कुल बाहरी चौड़ाई, उसके भार सहित, 8 feet 6 inches से अधिक नहीं हो सकती। PennDOT के Driver and Vehicle Services Size and Weight Limitations पृष्ठ पर भी यही आंकड़ा दिया गया है।"},"1":{"q":"पेंसिल्वेनिया के राजमार्गों पर सामान्यतः किसी वाहन की, उसके भार सहित, अनुमत अधिकतम ऊंचाई क्या है?","options":["13 feet 6 inches","13 feet 0 inches","14 feet 0 inches","12 feet 6 inches"],"explanation":"75 Pa.C.S. § 4922 (वाहनों की ऊंचाई) के अंतर्गत, कोई भी वाहन, उसके भार सहित, 13 feet 6 inches की ऊंचाई से अधिक नहीं हो सकता। इसकी पुष्टि PennDOT के Size and Weight Limitations पृष्ठ पर की गई है।"},"2":{"q":"पेंसिल्वेनिया के राजमार्गों पर किसी एकल (व्यक्तिगत) मोटर वाहन की, भार और बंपर सहित, अधिकतम कुल लंबाई क्या है?","options":["40 feet","45 feet","53 feet","35 feet"],"explanation":"75 Pa.C.S. § 4923 (वाहनों की लंबाई) के अंतर्गत, कोई एकल मोटर वाहन, किसी भी भार और बंपर सहित, कुल मिलाकर 40 feet से अधिक नहीं हो सकता। विशेष प्रकार के वाहनों (बसें, मोटर होम, बूम-युक्त वाहन) के लिए अलग, उच्चतर सीमाएं हैं।"},"3":{"q":"Vehicle Code के अंतर्गत पेंसिल्वेनिया के राजमार्गों पर किसी भी एकल वाहन या संयोजन का अधिकतम सकल भार क्या है?","options":["80,000 pounds","73,280 pounds","90,000 pounds","100,000 pounds"],"explanation":"75 Pa.C.S. § 4941 के अंतर्गत, और जैसा PennDOT के Size and Weight Limitations पृष्ठ पर बताया गया है, किसी भी व्यक्तिगत वाहन या किसी भी संयोजन का अधिकतम सकल भार 80,000 pounds है, जो पंजीकृत भार और एक्सल-भार सीमाओं के भी अधीन है।"},"4":{"q":"पेंसिल्वेनिया में संचालित किसी ट्रैक्टर-ट्रेलर संयोजन में एकल सेमीट्रेलर की अधिकतम लंबाई क्या है?","options":["53 feet","48 feet","57 feet","40 feet"],"explanation":"पेंसिल्वेनिया एक ट्रैक्टर-सेमीट्रेलर संयोजन में एकल ट्रेलर को 53 feet तक लंबा होने की अनुमति देता है, बशर्ते किंगपिन-से-पिछले-एक्सल की दूरी 41 feet से अधिक न हो। यह 75 Pa.C.S. Chapter 49 और PennDOT के Size and Weight Limitations पृष्ठ में दर्शाया गया है।"},"5":{"q":"पेंसिल्वेनिया में डबल-ट्रेलर (twin) संयोजन में, प्रत्येक ट्रेलर की अधिकतम लंबाई क्या है?","options":["28 feet 6 inches","28 feet 0 inches","33 feet 0 inches","30 feet 0 inches"],"explanation":"PennDOT के Size and Weight Limitations पृष्ठ में कहा गया है कि डबल-ट्रेलर संयोजन में, प्रत्येक ट्रेलर 28 feet 6 inches तक सीमित है, जो 75 Pa.C.S. Chapter 49 की लंबाई संबंधी प्रावधानों के अनुरूप है।"},"6":{"q":"पेंसिल्वेनिया की Interstate राजमार्ग प्रणाली पर, अधिकतम सकल वाहन भार क्या है, भले ही फेडरल ब्रिज फॉर्मूला अन्यथा अधिक की अनुमति देता हो?","options":["80,000 pounds","85,500 pounds","90,000 pounds","73,280 pounds"],"explanation":"पेंसिल्वेनिया फेडरल मानक का पालन करता है: Interstate System पर सकल वाहन भार 80,000 pounds तक सीमित है, भले ही Federal Bridge Formula का परिणाम अधिक हो। यह फेडरल सीमा 23 U.S.C. § 127 और 75 Pa.C.S. § 4941 के अनुसार पेंसिल्वेनिया के Interstates पर लागू होती है।"},"7":{"q":"पेंसिल्वेनिया में किसी भारी संयोजन के लिए एकल एक्सल (स्टीयरिंग एक्सल को छोड़कर) पर अनुमत अधिकतम भार क्या है?","options":["20,000 pounds","18,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"75 Pa.C.S. § 4943 (और पेंसिल्वेनिया जिस फेडरल मानक का पालन करता है) के अंतर्गत, एकल एक्सल पर अधिकतम भार 20,000 pounds है। यह Interstate System पर लागू फेडरल एकल-एक्सल सीमा से मेल खाता है।"},"8":{"q":"पेंसिल्वेनिया जिस फेडरल भार मानक को लागू करता है, उसके अंतर्गत किसी टैंडम एक्सल (दो लगातार एक्सलों का समूह) पर अधिकतम भार क्या है?","options":["34,000 pounds","36,000 pounds","40,000 pounds","20,000 pounds"],"explanation":"पेंसिल्वेनिया 34,000 pounds की फेडरल टैंडम-एक्सल सीमा लागू करता है। 75 Pa.C.S. § 4943 एक्सलों के दो लगातार जोड़ों को प्रत्येक 34,000 pounds ढोने की अनुमति देता है जब जोड़ों के पहले और अंतिम एक्सल के बीच की दूरी 36 feet या उससे अधिक हो।"},"9":{"q":"पेंसिल्वेनिया में लागू किए जाने के अनुसार Federal Bridge Formula का प्राथमिक उद्देश्य क्या है?","options":["राजमार्ग पुलों को क्षति के जोखिम को कम करने के लिए एक्सलों के समूहों पर भार को सीमित करना","पुलों के नीचे से गुजरने वाले भारों की अधिकतम ऊंचाई निर्धारित करना","Pennsylvania Turnpike पर देय टोल की गणना करना","भारी ट्रकों के लिए न्यूनतम अनुसरण दूरी निर्धारित करना"],"explanation":"Federal Bridge Formula (Bridge Gross Weight Formula) पुलों की रक्षा के लिए, एक्सलों की संख्या और उनके बीच की दूरी के आधार पर किसी भी लगातार एक्सलों के समूह पर अनुमत भार को सीमित करता है। यह 23 U.S.C. § 127 के अंतर्गत पेंसिल्वेनिया की Interstate System पर लागू होता है।"},"10":{"q":"पेंसिल्वेनिया में किसी वाहन को संचालित करने के लिए PennDOT hauling permit की आवश्यकता कब होती है?","options":["जब वाहन या भार Vehicle Code में दी गई कानूनी आकार या भार सीमाओं से अधिक हो","केवल जब किसी अन्य राज्य में प्रवेश किया जाए","जब भी कोई वाणिज्यिक माल परिवहन किया जाए","केवल जब चालक के पास CDL न हो"],"explanation":"PennDOT के Size and Weight Limitations पृष्ठ के अनुसार, किसी वाहन को कानूनी आकार/भार सीमाओं के बाहर केवल PennDOT के परमिट के साथ ही संचालित किया जा सकता है। Oversize/overweight hauling permits 75 Pa.C.S. Chapter 49 में दी गई सीमाओं से अधिक संचलन को अधिकृत करते हैं।"},"11":{"q":"पेंसिल्वेनिया में oversize/overweight विशेष hauling permits के लिए मुख्य रूप से किस PennDOT प्रणाली के माध्यम से आवेदन किया जाता है और जारी किए जाते हैं?","options":["APRAS (Automated Permit Routing and Analysis System)","CDLIS (Commercial Driver License Information System)","IRP (International Registration Plan) portal","SAFER (Safety and Fitness Electronic Records)"],"explanation":"PennDOT oversize/overweight Special Hauling permits को APRAS, यानी Automated Permit Routing and Analysis System के माध्यम से जारी करता है, जो प्रतिवर्ष लाखों परमिट संसाधित करता है, जिनमें से कई स्वचालित रूप से। स्रोत: PennDOT APRAS / Apply for a PennDOT Hauling Permit।"},"12":{"q":"किस चौड़ाई से अधिक मापने वाले वाहन और भार को oversize माना जाता है और PennDOT permit की आवश्यकता होती है?","options":["8 feet 6 inches से अधिक","8 feet 0 inches से अधिक","9 feet 0 inches से अधिक","10 feet 0 inches से अधिक"],"explanation":"चूंकि 75 Pa.C.S. § 4921 के अंतर्गत कानूनी चौड़ाई 8 feet 6 inches है, इसलिए 8 feet 6 inches से अधिक चौड़ा कोई भी वाहन और भार oversize है और इसके लिए PennDOT hauling permit की आवश्यकता होती है। स्रोत: PennDOT hauling permit / Load Type मार्गदर्शन।"},"13":{"q":"किस ऊंचाई से अधिक ऊंचे भार को oversize माना जाता है और PennDOT permit की आवश्यकता होती है?","options":["13 feet 6 inches से अधिक","13 feet 0 inches से अधिक","14 feet 0 inches से अधिक","12 feet 6 inches से अधिक"],"explanation":"चूंकि 75 Pa.C.S. § 4922 के अंतर्गत कानूनी ऊंचाई सीमा 13 feet 6 inches है, इसलिए 13 feet 6 inches से अधिक का भार oversize है और इसके लिए PennDOT hauling permit की आवश्यकता होती है। स्रोत: PennDOT Size and Weight Limitations / hauling permit मार्गदर्शन।"},"14":{"q":"पेंसिल्वेनिया में किसी वाहन को overweight माने जाने से पहले स्टीयरिंग एक्सल पर अधिकतम अनुमत भार क्या है?","options":["20,000 pounds","12,000 pounds","18,000 pounds","22,400 pounds"],"explanation":"75 Pa.C.S. § 4943 के अंतर्गत PennDOT permit मार्गदर्शन के अनुसार, यदि स्टीयरिंग एक्सल पर भार 20,000 pounds से अधिक हो तो वाहन overweight है। इससे ऊपर, PennDOT overweight permit की आवश्यकता होती है।"},"15":{"q":"पेंसिल्वेनिया के वार्षिक 'movement during course of manufacture' permit (75 Pa.C.S. § 4968) के अंतर्गत, कौन सी कच्ची वन-उत्पाद वस्तु अधिकतम भार से ऊपर ले जाई जा सकती है?","options":["Pulpwood और wood chips","तैयार फर्नीचर","खुदरा बिक्री के लिए बैग में पैक mulch","किसी खुदरा डीलर को construction lumber"],"explanation":"75 Pa.C.S. § 4968 raw milk, raw coal, pulpwood और wood chips जैसी वस्तुओं के लिए, जब वे निर्माण की प्रक्रिया में और निर्माता के नियंत्रण में हों, अधिकतम भार से ऊपर वार्षिक-परमिट संचलन की अनुमति देता है। किसी क्रेता या डीलर तक ले जाए जा रहे माल के लिए कोई परमिट जारी नहीं किया जाता।"},"16":{"q":"Pennsylvania Turnpike पर, कुछ परमिट प्राप्त भार सामान्य 80,000-pound सीमा से अधिक होकर किस अधिकतम सकल भार तक जा सकते हैं?","options":["100,000 pounds","80,000 pounds","90,000 pounds","120,000 pounds"],"explanation":"Pennsylvania Turnpike अपनी स्वयं की वाणिज्यिक परमिट सीमाएं निर्धारित करता है, जो परमिट प्राप्त सकल भार को 100,000 pounds तक (एक्सल भार 22,400 pounds तक के साथ) अनुमति देता है। स्रोत: PA Turnpike Commercial Permits and Restrictions। PennDOT राजमार्ग 80,000 lb पर सीमित रहते हैं।"},"17":{"q":"75 Pa.C.S. § 4943 के अंतर्गत, किसी भारी संयोजन पर 8 feet से अधिक की दूरी पर रखे गए एक्सलों के जोड़े पर अधिकतम भार क्या है?","options":["प्रत्येक 22,400 pounds","प्रत्येक 18,000 pounds","प्रत्येक 20,000 pounds","प्रत्येक 34,000 pounds"],"explanation":"75 Pa.C.S. § 4943 के एक्सल-दूरी नियमों के अंतर्गत, 8 feet से अधिक दूरी पर रखे गए एक्सल प्रत्येक 22,400 pounds तक ढो सकते हैं, जबकि 6 feet से कम दूरी पर रखे गए एक्सल प्रत्येक 18,000 pounds तक सीमित हैं।"},"18":{"q":"Federal Bridge Formula कभी-कभी किसी ट्रक को 80,000 pounds से कम पर क्यों सीमित कर देता है, भले ही कोई एकल एक्सल समूह अधिभारित न हो?","options":["क्योंकि निकट दूरी पर रखे एक्सल समूह भार को केंद्रित करते हैं, इसलिए फॉर्मूला पुलों की रक्षा के लिए अनुमत सकल भार को घटा देता है","क्योंकि स्टीयरिंग एक्सल को हमेशा सकल भार से बाहर रखा जाता है","क्योंकि पेंसिल्वेनिया सभी ट्रकों को 73,280 pounds पर सीमित करता है","क्योंकि एक्सल की दूरी के साथ टोल बढ़ते हैं"],"explanation":"Federal Bridge Formula अनुमत भार को एक्सलों की संख्या और तय की गई दूरी से जोड़ता है। जब एक्सल निकट दूरी पर होते हैं, तो फॉर्मूला पुल के स्पैन पर तनाव को सीमित करने के लिए 80,000 pounds से कम मान देता है। पेंसिल्वेनिया इसे 23 U.S.C. § 127 के अनुसार Interstate System पर लागू करता है।"},"19":{"q":"पेंसिल्वेनिया में सबसे बड़े मानक परमिट थ्रेशोल्ड से अधिक oversize/overweight संचलन (एक 'superload') को कैसे संभाला जाना चाहिए?","options":["अनुमोदन से पहले अक्सर मैनुअल विश्लेषण और रूटिंग की आवश्यकता के साथ, समीक्षा के लिए APRAS के माध्यम से प्रस्तुत किया जाए","यदि रात में ले जाया जाए तो बिना परमिट के चलाया जाए","किसी भी PennDOT photo license center पर स्वचालित रूप से अनुमोदित","क्योंकि यह अधिक टोल चुकाता है, इसलिए सभी रूटिंग से छूट प्राप्त"],"explanation":"Superload आवेदन PennDOT की APRAS प्रणाली के माध्यम से प्रस्तुत किए जाने चाहिए; जबकि अधिकांश नियमित परमिट लगभग एक मिनट में स्वचालित रूप से अनुमोदित हो जाते हैं, superloads और लगभग पांच में से एक आवेदन को मैनुअल समीक्षा और रूट विश्लेषण की आवश्यकता होती है। स्रोत: PennDOT APRAS।"},"20":{"q":"पेंसिल्वेनिया में, 26,001 pounds या उससे अधिक के Gross Combination Weight Rating (GCWR) वाले वाहनों के संयोजन को संचालित करने के लिए किस वर्ग के CDL की आवश्यकता होती है, जब खींचे जाने वाले वाहन का GVWR 10,000 pounds से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"PennDOT Commercial Driver's License Fact Sheet (June 2025) और PUB 223 के अनुसार, Class A CDL 26,001 pounds या उससे अधिक GCWR वाले संयोजन वाहन को कवर करता है, बशर्ते खींचे जाने वाले वाहन का GVWR 10,000 pounds से अधिक हो। स्रोत: PennDOT CDL Fact Sheet / Commercial Driver's Manual (PUB 223)।"},"21":{"q":"पेंसिल्वेनिया CDL नियमों के अंतर्गत, 26,001 pounds या उससे अधिक के Gross Vehicle Weight Rating (GVWR) वाले एकल वाहन (या ऐसा वाहन जो 10,000 pounds से अधिक न खींच रहा हो) के लिए किस लाइसेंस वर्ग की आवश्यकता होती है?","options":["Class A","Class B","Class C","Class M"],"explanation":"PennDOT Class B को 26,001 pounds या उससे अधिक GVWR वाले एकल वाहन के रूप में, या ऐसे किसी वाहन के रूप में परिभाषित करता है जो 10,000 pounds से अधिक के वाहन को न खींच रहा हो। स्रोत: PennDOT CDL Fact Sheet (June 2025) / PUB 223।"},"22":{"q":"PennDOT के अनुसार, पेंसिल्वेनिया का Class C CDL 26,001 pounds GVWR से कम के एकल वाहन के लिए उपयोग किया जाता है जो placarded खतरनाक सामग्री ले जाता है, 16 या अधिक लोगों को ढोता है, या एक स्कूल बस है। Class C CDL में और क्या शामिल होना चाहिए?","options":["एक S, P, या H endorsement","एक मोटरसाइकिल (M) endorsement","एक Class A air-brake प्रमाणन","एक farm-vehicle waiver"],"explanation":"PennDOT CDL Fact Sheet में कहा गया है कि Class C CDL 26,001 lbs GVWR से कम के एकल वाहनों को कवर करता है जो placarded hazmat परिवहन करते हैं, चालक सहित 16+ ले जाने के लिए डिज़ाइन किए गए हैं, या स्कूल बस हैं, और यह कि Class C CDL में एक S, P, या H endorsement शामिल होना चाहिए। स्रोत: PennDOT CDL Fact Sheet (June 2025)।"},"23":{"q":"पेंसिल्वेनिया में, 'N' endorsement किसी CDL धारक को क्या करने के लिए अधिकृत करता है?","options":["टैंक वाहनों का संचालन करना","डबल और ट्रिपल ट्रेलरों का संचालन करना","किसी बस में यात्रियों को ले जाना","placarded खतरनाक सामग्री का परिवहन करना"],"explanation":"PennDOT बताता है कि endorsement N चालक को टैंक वाहनों का संचालन करने के लिए अधिकृत करता है। (Endorsement T doubles/triples के लिए, P यात्रियों के लिए, और H placarded hazmat के लिए है।) स्रोत: PennDOT CDL Fact Sheet (June 2025) / PUB 223।"},"24":{"q":"डबल और ट्रिपल ट्रेलर चलाने के लिए कौन सा पेंसिल्वेनिया CDL endorsement आवश्यक है?","options":["Endorsement T","Endorsement N","Endorsement X","Endorsement H"],"explanation":"PennDOT बताता है कि endorsement T डबल और ट्रिपल ट्रेलर चलाने को अधिकृत करता है। स्रोत: PennDOT CDL Fact Sheet (June 2025) / PUB 223।"},"25":{"q":"पेंसिल्वेनिया CDL पर, संयुक्त 'X' endorsement किसका प्रतिनिधित्व करता है?","options":["खतरनाक सामग्री और टैंक वाहन दोनों (H and N)","यात्री और स्कूल बस दोनों (P and S)","doubles/triples और टैंक दोनों (T and N)","नवीनीकरण के लंबित एक समाप्त endorsement"],"explanation":"PennDOT endorsement X को खतरनाक सामग्री और टैंक वाहन संयुक्त (H,N) के रूप में सूचीबद्ध करता है। स्रोत: PennDOT CDL Fact Sheet (June 2025)।"},"26":{"q":"intrastate ड्राइविंग (केवल पेंसिल्वेनिया के भीतर वाणिज्यिक वाहन संचालित करना) के लिए पेंसिल्वेनिया CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 वर्ष","16 वर्ष","19 वर्ष","21 वर्ष"],"explanation":"पेंसिल्वेनिया intrastate (केवल राज्य के भीतर) वाणिज्यिक ड्राइविंग के लिए CDL रखने हेतु न्यूनतम आयु 18 की आवश्यकता रखता है। स्रोत: PennDOT Driver and Vehicle Services, Commercial Drivers / License Types & Restrictions।"},"27":{"q":"पेंसिल्वेनिया CDL के साथ interstate commerce (राज्य की सीमाओं के पार) में किसी वाणिज्यिक मोटर वाहन को संचालित करने के लिए आवश्यक न्यूनतम आयु क्या है?","options":["21 वर्ष","18 वर्ष","19 वर्ष","25 वर्ष"],"explanation":"interstate commerce में किसी CMV को संचालित करने के लिए, चालक की आयु कम से कम 21 होनी चाहिए। 18-20 आयु के चालक केवल पेंसिल्वेनिया के भीतर intrastate संचालन कर सकते हैं। स्रोत: PennDOT Commercial Drivers / पेंसिल्वेनिया में लागू 49 CFR 391.11।"},"28":{"q":"आवश्यक knowledge test पास करने और एक पेंसिल्वेनिया commercial learner's permit जारी होने के बाद, Class A, B, या C skills test निर्धारित किए जाने से पहले न्यूनतम प्रतीक्षा अवधि क्या है?","options":["15 days","10 days","30 days","7 days"],"explanation":"PennDOT के अनुसार, knowledge test पास होने और permit जारी होने के 15 days बाद तक skills testing नहीं ली जा सकती। यह फेडरल 14-day CLP-hold आवश्यकता को पूरा करता है। स्रोत: PennDOT CDL Fact Sheet (June 2025) और CDL Learner's Permit FAQs।"},"29":{"q":"एक पेंसिल्वेनिया Knowledge Test Authorization (KTA) / commercial learner's permit कितने समय तक वैध रहता है, जिससे आवेदक को सभी knowledge और skills tests पास करने का समय मिलता है?","options":["जारी होने की तारीख से एक वर्ष","जारी होने की तारीख से 90 days","जारी होने की तारीख से छह महीने","जारी होने की तारीख से दो वर्ष"],"explanation":"PennDOT बताता है कि KTA जारी होने की तारीख से एक वर्ष तक वैध है, और आवेदकों के पास अपना CDL प्राप्त करने के लिए सभी knowledge और skills tests पास करने हेतु एक वर्ष होता है। स्रोत: PennDOT CDL Learner's Permit FAQs।"},"30":{"q":"प्रत्येक व्यक्ति जो पेंसिल्वेनिया commercial learner's permit के लिए आवेदन करता है या CDL रखता है, उसे कौन सा दस्तावेज़ पूरा करना होगा जो उनके द्वारा किए जाने वाले वाणिज्यिक संचालन के प्रकार की पहचान करता है?","options":["एक Self-Certification Form (DL-11CD)","एक REAL ID waiver form","एक IRP apportioned registration form","एक Form I-9 employment authorization"],"explanation":"PennDOT प्रत्येक CDL धारक और प्रत्येक CLP आवेदक से एक Self-Certification Form (DL-11CD) प्रस्तुत करने की आवश्यकता रखता है जो उनके ड्राइविंग के प्रकार की पहचान करता है। स्रोत: PennDOT CDL Fact Sheet (June 2025) और Self-Certification/Medical Examiner FAQs।"},"31":{"q":"निम्नलिखित में से कौन सी एक पेंसिल्वेनिया CDL आवेदक को चुनने के लिए चार medical self-certification श्रेणियों में से एक है?","options":["Non-excepted Interstate","Excepted Out-of-State","Placarded Interstate","Restricted Intrastate"],"explanation":"चार self-certification श्रेणियां Non-excepted Interstate, Non-excepted Intrastate, Excepted Interstate, और Excepted Intrastate हैं। एक Non-excepted Interstate चालक के पास PennDOT के पास एक वैध Medical Examiner's Certificate फ़ाइल में होना चाहिए। स्रोत: PennDOT Self-Certification/Medical Examiner FAQs।"},"32":{"q":"एक पेंसिल्वेनिया चालक जो 'Non-excepted Intrastate' के रूप में self-certify करता है, केवल राज्य के भीतर ड्राइविंग करते समय फेडरल physical qualification मानकों के अधीन होता है। इस मामले में PennDOT कौन सा लाइसेंस प्रतिबंध जोड़ता है?","options":["एक 'K' restriction (केवल intrastate commerce)","एक 'L' restriction (कोई air brakes नहीं)","एक 'E' restriction (कोई manual transmission नहीं)","एक 'O' restriction (कोई fifth-wheel combination नहीं)"],"explanation":"PennDOT restriction K लागू करता है जो चालक को केवल intrastate commerce तक सीमित करता है। K restriction केवल-intrastate वाणिज्यिक संचालन के लिए दिखाई देता है। स्रोत: PennDOT CDL Fact Sheet (June 2025) और Self-Certification FAQs।"},"33":{"q":"February 7, 2022 से प्रभावी, पेंसिल्वेनिया में किस प्रमाणपत्र(पत्रों) के पहली बार आवेदकों के लिए Entry-Level Driver Training (ELDT) आवश्यक है?","options":["पहली Class A या B CDL, या पहला P, S, या H endorsement","वर्ग की परवाह किए बिना कोई भी CDL renewal","केवल एक HazMat (H) endorsement","केवल intrastate Class C CDLs"],"explanation":"PennDOT द्वारा अपनाए गए FMCSA नियमों के अनुसार, ELDT (Feb 7, 2022 से प्रभावी) पहली बार Class A या B CDL प्राप्त करने, Class A या B में अपग्रेड करने, या पहली बार P, S, या H endorsement प्राप्त करने पर लागू होता है। यह पूर्वव्यापी नहीं है। स्रोत: PennDOT Entry Level Driver Training पृष्ठ / 49 CFR Part 380।"},"34":{"q":"एक पेंसिल्वेनिया entry-level चालक को skills test देने से पहले अपना आवश्यक ELDT प्रशिक्षण कहाँ से प्राप्त करना चाहिए?","options":["FMCSA Training Provider Registry (TPR) पर सूचीबद्ध किसी प्रदाता से","किसी भी PennDOT driver license center से","किसी नियोक्ता के अनौपचारिक on-the-job कार्यक्रम से","किसी भी AAA-affiliated driving school से"],"explanation":"PennDOT skills test से पहले ELDT को FMCSA Training Provider Registry (tpr.fmcsa.dot.gov) पर सूचीबद्ध किसी प्रदाता के साथ पूरा करने की आवश्यकता रखता है। स्रोत: PennDOT CDL Fact Sheet (June 2025) / Entry Level Driver Training पृष्ठ।"},"35":{"q":"पेंसिल्वेनिया HazMat (H) endorsement प्राप्त करने के लिए, एक आवेदक को एक knowledge test पास करना होगा और कौन सी फेडरल background screening पूरी करनी होगी?","options":["fingerprinting के साथ एक TSA Security Threat Assessment","एक E-Verify employment check","केवल-PennDOT ड्राइविंग रिकॉर्ड समीक्षा","एक FAA medical certification"],"explanation":"PennDOT HazMat आवेदकों से एक फेडरल Transportation Security Administration (TSA) Security Threat Assessment पूरा करने की आवश्यकता रखता है, जिसमें fingerprinting शामिल है (Form DL-288, PUB 512)। H endorsement जारी करने से पहले PennDOT को फेडरल अनुमोदन प्राप्त करना होगा। स्रोत: PennDOT Hazardous Materials Endorsement Fact Sheet (FS-HM) और FAQs।"},"36":{"q":"आधिकारिक PennDOT CDL knowledge tests पर, Hazardous Materials (H) endorsement test में कितने प्रश्न होते हैं?","options":["30 questions","20 questions","25 questions","50 questions"],"explanation":"PennDOT Hazardous Materials Endorsement knowledge test को 30 questions के रूप में सूचीबद्ध करता है, और HazMat test केवल अंग्रेज़ी में उपलब्ध है। स्रोत: PennDOT CDL Fact Sheet (June 2025)।"},"37":{"q":"पेंसिल्वेनिया School Bus (S) endorsement अर्जित करने से पहले, चालक के पास कौन सा endorsement भी होना चाहिए?","options":["Passenger (P) endorsement","Tank (N) endorsement","Doubles/Triples (T) endorsement","HazMat (H) endorsement"],"explanation":"PennDOT School Bus (S) endorsement के लिए एक पूर्वापेक्षा के रूप में Passenger (P) endorsement की आवश्यकता रखता है; S knowledge test के लिए passenger endorsement आवश्यक है। स्रोत: PennDOT CDL Fact Sheet (June 2025) / School Transportation FAQs।"},"38":{"q":"PennDOT के अनुसार पेंसिल्वेनिया School Bus (S) endorsement कार्ड के बारे में कौन सा कथन सही है?","options":["एक School Bus endorsement कार्ड प्रतिवर्ष जारी किया जाता है","S endorsement को कभी नवीनीकरण की आवश्यकता नहीं होती","S endorsement केवल हर आठ वर्ष में जारी किया जाता है","S endorsement कार्ड TSA द्वारा डाक से भेजा जाता है"],"explanation":"PennDOT CDL Fact Sheet में उल्लेख है कि endorsement S एक स्कूल बस संचालित करने को अधिकृत करता है और यह कि एक School Bus endorsement कार्ड प्रतिवर्ष जारी किया जाता है। स्रोत: PennDOT CDL Fact Sheet (June 2025)।"},"39":{"q":"पेंसिल्वेनिया CDL/CLP के लिए व्यक्तिगत रूप से आवेदन करते समय, एक आवेदक को आम तौर पर पहचान और वैध स्थिति का प्रमाण, Social Security number का प्रमाण, और पेंसिल्वेनिया निवास के कितने प्रमाण प्रदान करने होंगे?","options":["पेंसिल्वेनिया निवास के दो प्रमाण","पेंसिल्वेनिया निवास का एक प्रमाण","पेंसिल्वेनिया निवास के तीन प्रमाण","निवास का कोई प्रमाण आवश्यक नहीं है"],"explanation":"PennDOT पहचान/वैध स्थिति सिद्ध करने वाला एक दस्तावेज़, Social Security number सिद्ध करने वाला एक दस्तावेज़, और पेंसिल्वेनिया निवास सिद्ध करने वाले दो दस्तावेज़ों की आवश्यकता रखता है। स्रोत: PennDOT Proof of Identity and Residency requirements (PUB 195US)।"},"40":{"q":"पेंसिल्वेनिया में, अधिकतम रक्त अल्कोहल सांद्रता (BAC) क्या है जिस पर या उससे ऊपर किसी चालक को नशे में वाणिज्यिक मोटर वाहन (CMV) संचालित करते हुए माना जाता है?","options":["0.02 percent","0.04 percent","0.08 percent","0.10 percent"],"explanation":"पेंसिल्वेनिया 0.04 percent या उससे अधिक BAC के साथ CMV संचालित करना प्रतिबंधित करता है, जो गैर-वाणिज्यिक चालकों के लिए 0.08 percent सीमा का आधा है। स्रोत: PA CDL Manual; 75 Pa.C.S. और 49 CFR 383.51।"},"41":{"q":"पेंसिल्वेनिया के implied consent नियमों के अंतर्गत, उस CMV चालक के साथ क्या होता है जो किसी उचित अधिकारी की चेतावनी के बाद chemical testing कराने से इनकार करता है?","options":["किसी disqualification के बिना केवल एक लिखित चेतावनी","एक 30-day CDL disqualification","एक 1-year CDL disqualification, जिसे DUI दोषसिद्धि की तरह माना जाता है","एक 6-month CDL disqualification"],"explanation":"एक CMV चालक जो chemical testing से इनकार करता है, उसे कम से कम 1 year के लिए अयोग्य ठहराया जाता है, ठीक एक major-offense दोषसिद्धि के समान। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51।"},"42":{"q":"पेंसिल्वेनिया में, पहला major offense (जैसे 0.04 percent या उससे अधिक BAC के साथ CMV संचालित करना) कम से कम कितने समय की CDL disqualification में परिणत होता है?","options":["60 days","6 months","1 year","3 years"],"explanation":"पहला major offense एक पेंसिल्वेनिया CDL धारक को न्यूनतम 1 year के लिए अयोग्य ठहराता है। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51।"},"43":{"q":"पेंसिल्वेनिया में, यदि कोई चालक खतरनाक सामग्री के लिए placarded किसी CMV को संचालित करते समय पहला major offense करता है, तो disqualification अवधि बढ़कर हो जाती है:","options":["1 year","2 years","3 years","5 years"],"explanation":"placarded खतरनाक सामग्री परिवहन करते समय किया गया पहला major offense disqualification को 1 year से बढ़ाकर 3 years कर देता है। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51।"},"44":{"q":"पेंसिल्वेनिया में दूसरे major offense (उदाहरण के लिए, किसी CMV में दूसरा DUI) के लिए CDL disqualification अवधि क्या है?","options":["3 years","5 years","10 years","आजीवन"],"explanation":"किसी भी वाहन में दो major offenses के परिणामस्वरूप पेंसिल्वेनिया में आजीवन CDL disqualification होती है। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51।"},"45":{"q":"पेंसिल्वेनिया में, 3-year अवधि के भीतर अलग-अलग घटनाओं में दो serious traffic violations के लिए दोषी ठहराए जाने के परिणामस्वरूप कितनी CDL disqualification होती है:","options":["30 days","60 days","120 days","1 year"],"explanation":"3 years के भीतर दो serious traffic violations एक पेंसिल्वेनिया CDL धारक को 60 days के लिए अयोग्य ठहराती हैं। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51।"},"46":{"q":"पेंसिल्वेनिया में, 3-year अवधि के भीतर अलग-अलग घटनाओं में तीन serious traffic violations के लिए दोषी ठहराए जाने के परिणामस्वरूप कितनी CDL disqualification होती है:","options":["60 days","90 days","120 days","1 year"],"explanation":"3 years के भीतर तीन serious traffic violations एक पेंसिल्वेनिया CDL धारक को 120 days के लिए अयोग्य ठहराती हैं, जो किसी भी 60-day disqualification के बाद क्रमिक रूप से लागू होती हैं। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51।"},"47":{"q":"निम्नलिखित में से किसे एक पेंसिल्वेनिया CDL धारक के लिए एक SERIOUS traffic violation के रूप में वर्गीकृत किया गया है?","options":["एक खराब tail lamp","गति सीमा को 15 mph या उससे अधिक से पार करना","no-stopping zone में पार्किंग करना","समाप्त पंजीकरण के साथ ड्राइविंग करना"],"explanation":"सीमा से 15 mph या उससे अधिक तेज गति एक serious traffic violation है; अन्य में लापरवाह ड्राइविंग, अनुचित lane change, बहुत निकट से अनुसरण करना, texting, और handheld phone का उपयोग शामिल हैं। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51।"},"48":{"q":"एक पेंसिल्वेनिया CDL चालक के लिए, किसी railroad-highway grade crossing कानून का उल्लंघन करने की पहली दोषसिद्धि के लिए disqualification क्या है?","options":["30 days","60 days","120 days","1 year"],"explanation":"पहला railroad-grade-crossing उल्लंघन एक पेंसिल्वेनिया CDL धारक को 60 days के लिए अयोग्य ठहराता है। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51।"},"49":{"q":"एक पेंसिल्वेनिया CDL चालक के लिए, 3-year अवधि के भीतर दूसरा railroad-highway grade crossing उल्लंघन के परिणामस्वरूप कितनी disqualification होती है:","options":["60 days","120 days","1 year","3 years"],"explanation":"3 years के भीतर दूसरा railroad-grade-crossing उल्लंघन एक पेंसिल्वेनिया CDL धारक को 120 days के लिए अयोग्य ठहराता है। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51।"},"50":{"q":"एक पेंसिल्वेनिया CDL चालक के लिए, 3-year अवधि के भीतर तीसरा या उसके बाद का railroad-highway grade crossing उल्लंघन के परिणामस्वरूप कितनी disqualification होती है:","options":["120 days","180 days","1 year","3 years"],"explanation":"3 years के भीतर तीसरा या उसके बाद का railroad-grade-crossing उल्लंघन एक पेंसिल्वेनिया CDL धारक को 1 year के लिए अयोग्य ठहराता है। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51।"},"51":{"q":"पेंसिल्वेनिया में, गैर-खतरनाक सामग्री ढोते समय किसी out-of-service (OOS) order का उल्लंघन करने की पहली दोषसिद्धि एक CDL चालक को कितने समय के लिए अयोग्य ठहराती है:","options":["90 days","180 days","1 year","2 years"],"explanation":"पहला out-of-service order उल्लंघन (non-hazmat) एक पेंसिल्वेनिया CDL धारक को कम से कम 1 year के लिए अयोग्य ठहराता है। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51।"},"52":{"q":"पेंसिल्वेनिया में, 10-year अवधि के भीतर दूसरा out-of-service order उल्लंघन (non-hazmat) के परिणामस्वरूप कितनी CDL disqualification होती है:","options":["1 year","2 years","3 years","5 years"],"explanation":"10 years के भीतर दूसरा out-of-service order उल्लंघन (non-hazmat) एक पेंसिल्वेनिया CDL धारक को कम से कम 3 years के लिए अयोग्य ठहराता है। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51।"},"53":{"q":"पेंसिल्वेनिया में, खतरनाक सामग्री परिवहन करते समय या 16 या अधिक यात्रियों को ले जाते समय पहला out-of-service order उल्लंघन एक CDL चालक को कितने समय के लिए अयोग्य ठहराता है:","options":["1 year","2 years","3 years","5 years"],"explanation":"hazmat ढोते समय या 16+ यात्रियों को ले जाते समय पहला out-of-service order उल्लंघन एक पेंसिल्वेनिया CDL धारक को कम से कम 2 years के लिए अयोग्य ठहराता है। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51।"},"54":{"q":"पेंसिल्वेनिया में, खतरनाक सामग्री परिवहन करते समय या 16 या अधिक यात्रियों को ले जाते समय 10 years के भीतर दूसरा out-of-service order उल्लंघन एक CDL चालक को कितने समय के लिए अयोग्य ठहराता है:","options":["2 years","3 years","5 years","आजीवन"],"explanation":"hazmat ढोते समय या 16+ यात्रियों को ले जाते समय 10 years के भीतर दूसरा out-of-service order उल्लंघन एक पेंसिल्वेनिया CDL धारक को कम से कम 5 years के लिए अयोग्य ठहराता है। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51।"},"55":{"q":"एक पेंसिल्वेनिया CDL धारक के लिए, किसी CMV को चलाते समय एक handheld मोबाइल फ़ोन का उपयोग करना किस रूप में माना जाता है:","options":["एक गैर-रिपोर्ट योग्य उपकरण उल्लंघन","एक serious traffic violation जो disqualification का कारण बन सकता है","पहले अपराध पर एक स्वचालित 1-year disqualification","एक आजीवन disqualification अपराध"],"explanation":"किसी CMV को संचालित करते समय एक handheld phone का उपयोग करना एक serious traffic violation है; 3 years के भीतर दो से 60-day disqualification होती है और तीन से 120 days होती है। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51 और 392.82।"},"56":{"q":"एक पेंसिल्वेनिया CDL धारक के लिए, किसी वाणिज्यिक मोटर वाहन को चलाते समय texting करना क्या है:","options":["यदि वाहन किसी लाइट पर रुका हो तो अनुमत","एक serious traffic violation जो disqualification का कारण बन सकता है","केवल एक पार्किंग-प्रकार का जुर्माना जिसका लाइसेंस पर कोई प्रभाव नहीं","dispatch संचार के लिए अनुमत"],"explanation":"किसी CMV को संचालित करते समय texting करना एक serious traffic violation है; 3 years के भीतर इनके संचयन से 60- या 120-day disqualifications होती हैं। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51 और 392.80।"},"57":{"q":"पेंसिल्वेनिया में, कौन सी दोषसिद्धि 10 years के बाद पुनर्बहाली के विकल्प के बिना एक आजीवन CDL disqualification वहन करती है?","options":["किसी CMV में दूसरा DUI","किसी नियंत्रित पदार्थ के निर्माण या वितरण से संबंधित अपराध करने के लिए किसी CMV का उपयोग करना","3 years के भीतर दो serious traffic violations","पहला out-of-service order उल्लंघन"],"explanation":"किसी नियंत्रित पदार्थ के निर्माण, वितरण, या वितरण से संबंधित किसी अपराध में किसी CMV का उपयोग करने के परिणामस्वरूप एक आजीवन disqualification होती है जिसे कम नहीं किया जा सकता। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51।"},"58":{"q":"किसी CMV के लापरवाह या आपराधिक संचालन के माध्यम से मृत्यु में परिणत होने वाले एक major offense का दोषी एक पेंसिल्वेनिया CDL चालक कम से कम कितने समय के लिए अयोग्य ठहराया जाता है:","options":["60 days","120 days","1 year","5 years"],"explanation":"किसी CMV के लापरवाह या आपराधिक संचालन के माध्यम से मृत्यु का कारण बनना एक major offense है जो न्यूनतम 1-year disqualification वहन करता है (hazmat के लिए placarded होने पर 3 years)। स्रोत: PennDOT Disqualifications and Traffic Offenses fact sheet; 49 CFR 383.51।"},"59":{"q":"पेंसिल्वेनिया के स्कूल बस कानून के तहत, जब किसी स्कूल बस की लाल सिग्नल लाइटें चमक रही हों और स्टॉप आर्म बाहर निकला हो, तो बस के पास पहुँचने से कितनी दूरी पहले सामने से आने वाले या आगे निकलने वाले चालक को रुकना चाहिए?","options":["कम से कम 10 feet","कम से कम 15 feet","कम से कम 20 feet","कम से कम 25 feet"],"explanation":"पेंसिल्वेनिया में सामने से आने वाले या स्कूल बस से आगे निकलने वाले चालकों को, जिनकी लाल सिग्नल लाइटें चमक रही हों, बस से कम से कम 10 feet की दूरी पर रुकना आवश्यक है और तब तक आगे नहीं बढ़ना चाहिए जब तक लाइटें चमकना बंद न कर दें और स्टॉप आर्म वापस अंदर न हो जाए। स्रोत: 75 Pa.C.S. § 3345 (Meeting or overtaking school bus); PA Commercial Driver's Manual (PUB 223)।"},"60":{"q":"किसी पेंसिल्वेनिया राजमार्ग पर जहाँ अलग-अलग सड़कें किसी भौतिक अवरोध या स्पष्ट रूप से दर्शाए गए विभाजन खंड द्वारा बँटी हों, वहाँ चमकती लाल लाइटों वाली रुकी हुई स्कूल बस से OPPOSITE (विपरीत) सड़क पर चलने वाले चालक को क्या करना चाहिए:","options":["रुकना आवश्यक नहीं है","मीडियन से कम से कम 10 feet दूर रुकना","केवल तभी रुकना जब बच्चे दिखाई दें","15 mph तक धीमे होना लेकिन रुकना आवश्यक नहीं"],"explanation":"पेंसिल्वेनिया के विभाजित-राजमार्ग अपवाद के अनुसार, अलग-अलग सड़कों वाले राजमार्ग पर किसी चालक को उस स्कूल बस के लिए रुकने की आवश्यकता नहीं है जिसकी चमकती लाल लाइटें हों और जो किसी DIFFERENT (अलग) सड़क पर हो। 'अलग सड़क' के लिए एक भौतिक अवरोध या स्पष्ट रूप से दर्शाए गए विभाजन खंड की आवश्यकता होती है; केवल पेंट की गई रेखाएँ या संकेत इसे नहीं बनाते। स्रोत: 75 Pa.C.S. § 3345।"},"61":{"q":"पेंसिल्वेनिया के स्कूल-बस 'अलग सड़कों' अपवाद के लागू होने के लिए (ताकि विपरीत दिशा के यातायात को रुकने की आवश्यकता न हो) कौन-सी विशेषता आवश्यक है?","options":["एक भौतिक अवरोध या स्पष्ट रूप से दर्शाया गया विभाजन खंड","एक दोहरी पीली केंद्र रेखा","एक केंद्रीय बाएँ-मुड़ने वाली लेन","एक लगा हुआ संकेत जिस पर 'DIVIDED HIGHWAY' लिखा हो"],"explanation":"पेंसिल्वेनिया में यह अपवाद केवल वहीं लागू होता है जहाँ सड़कें किसी भौतिक अवरोध या स्पष्ट रूप से दर्शाए गए विभाजन खंड द्वारा अलग की गई हों। केवल फुटपाथ चिह्न या संकेत अलग सड़क नहीं बनाते, इसलिए केवल पेंट से विभाजित सड़कों पर सभी दिशाओं को रुकना ही पड़ता है। स्रोत: 75 Pa.C.S. § 3345।"},"62":{"q":"पेंसिल्वेनिया में किसी रेलमार्ग ग्रेड क्रॉसिंग पर रुकने के लिए आवश्यक वाहन को सबसे निकट की रेल से कितनी दूरी के भीतर रुकना चाहिए?","options":["50 feet के भीतर लेकिन 15 feet से कम नहीं","100 feet के भीतर लेकिन 25 feet से कम नहीं","30 feet के भीतर लेकिन 10 feet से कम नहीं","75 feet के भीतर लेकिन 20 feet से कम नहीं"],"explanation":"पेंसिल्वेनिया कानून के अनुसार जिन वाहनों को रेलमार्ग क्रॉसिंग पर रुकना आवश्यक है (स्कूल बसें, यात्री बसें, और कुछ ईंधन/विस्फोटक/रेडियोधर्मी सामग्री ले जाने वाले ट्रक) उन्हें सबसे निकट की रेल से 50 feet के भीतर लेकिन 15 feet से कम दूरी पर नहीं रुकना चाहिए, फिर देखना और सुनना चाहिए। स्रोत: 75 Pa.C.S. § 3342 (Vehicles required to stop at railroad crossings); PA CDL Manual।"},"63":{"q":"पेंसिल्वेनिया कानून के तहत कौन-सा वाहन हर रेलमार्ग ग्रेड क्रॉसिंग पर रुकने के लिए आवश्यक नहीं है?","options":["कोई खतरनाक सामग्री न ले जाने वाला एक खाली ड्राई-वैन ट्रैक्टर-ट्रेलर","एक स्कूल बस, चाहे यात्री ले जा रही हो या नहीं","यात्रियों को ले जाने वाली एक बस","प्लेकार्ड लगे विस्फोटक ले जाने वाला एक ट्रक"],"explanation":"पेंसिल्वेनिया में स्कूल बसों (भरी हुई या खाली), यात्री ले जाने वाली बसों, और गैसोलीन, डीज़ल/ईंधन तेल, विस्फोटक, या रेडियोधर्मी सामग्री ढोने वाले ट्रकों को क्रॉसिंग पर रुकना आवश्यक है। बिना किसी खतरनाक माल वाली एक साधारण खाली मालवाहक वैन को रुकने की आवश्यकता नहीं है। स्रोत: 75 Pa.C.S. § 3342।"},"64":{"q":"जब एक पेंसिल्वेनिया CMV जिसे रुकना आवश्यक है, रेलमार्ग की पटरियों को पार कर रहा हो, तो चालक को विशेष रूप से क्या करने से मना किया गया है?","options":["पटरियों पर रहते हुए मैन्युअल रूप से गियर बदलना","इंजन ब्रेक का उपयोग करना","लो गियर में पार करना","फोर-वे फ्लैशर सक्रिय करना"],"explanation":"पेंसिल्वेनिया कानून निर्देश देता है कि जिस चालक को रुकना आवश्यक है वह ऐसे गियर में पार करे जिसमें पार करते समय गियर बदलने की आवश्यकता न हो, और पटरी(यों) पर रहते हुए मैन्युअल रूप से गियर न बदले। स्रोत: 75 Pa.C.S. § 3342; PA CDL Manual।"},"65":{"q":"किसी पेंसिल्वेनिया रेलमार्ग क्रॉसिंग पर जिस पर 'EXEMPT' लिखा संकेत लगा हो, वहाँ एक प्लेकार्ड लगा हुआ हैज़मैट ट्रक या बस:","options":["रुकने के लिए आवश्यक नहीं है","फिर भी रेल से 50 feet के भीतर रुकना चाहिए","रुकना चाहिए और हॉर्न बजाना चाहिए","केवल तभी रुकना चाहिए जब कोई गेट मौजूद हो"],"explanation":"पेंसिल्वेनिया 'exempt' संकेत लगी क्रॉसिंगों (और इस प्रकार चिह्नित परित्यक्त क्रॉसिंगों) को अनिवार्य-रुकने के नियम से छूट देता है; वाहन को आगे निर्देशित करने वाला कोई अधिकारी या फ्लैगमैन, या हरा यातायात सिग्नल भी रुकने के कर्तव्य से मुक्त कर देता है। स्रोत: 75 Pa.C.S. § 3342।"},"66":{"q":"पेंसिल्वेनिया के Move Over कानून के तहत, जब कोई चालक किसी आपातकालीन प्रतिक्रिया क्षेत्र के पास किसी गैर-निकटवर्ती लेन में सुरक्षित रूप से नहीं जा सकता, तो चालक को इसके बजाय पोस्ट की गई सीमा से अधिकतम कितनी कम गति पर गुजरना चाहिए?","options":["पोस्ट की गई गति सीमा से 20 mph कम","पोस्ट की गई गति सीमा से 10 mph कम","पोस्ट की गई गति सीमा से 15 mph कम","पोस्ट की गई गति सीमा से 25 mph कम"],"explanation":"पेंसिल्वेनिया का Move Over (Steer Clear) कानून आवश्यकता पड़ने पर आपातकालीन प्रतिक्रिया क्षेत्र से निकटवर्ती न होने वाली लेन में गुजरने की आवश्यकता रखता है; यदि वह असंभव, अवैध, या असुरक्षित हो, तो चालक को पोस्ट की गई गति सीमा से 20 mph से अधिक कम न होने वाली गति पर और सुरक्षा के लिए उचित गति पर गुजरना चाहिए। स्रोत: 75 Pa.C.S. § 3327।"},"67":{"q":"पेंसिल्वेनिया का Move Over कानून (Act 105 of 2020) किसी आपातकालीन प्रतिक्रिया क्षेत्र के पास न होने वाली लेन में विलय करने में विफल रहने के लिए कितने अंक निर्धारित करता है?","options":["2 points","3 points","4 points","5 points"],"explanation":"Act 105 of 2020 ने मूव ओवर करने में विफल रहने के लिए 2-अंक का दंड जोड़ा, साथ ही बढ़ते हुए जुर्माने $500 (पहली बार), $1,000 (दूसरी बार), और $2,000 के साथ 90-दिन का निलंबन (तीसरी या बाद की बार) निर्धारित किया। स्रोत: 75 Pa.C.S. § 3327; PennDOT Move Over campaign।"},"68":{"q":"पुलिस, अग्निशमन, एम्बुलेंस, और टो ट्रकों के अलावा, पेंसिल्वेनिया का Move Over कानून निम्नलिखित में से किसकी भी रक्षा करता है?","options":["कम से कम दो आपातकालीन चिह्न प्रदर्शित करने वाला एक खराब वाहन (जैसे, हैज़र्ड लाइटें और फ्लेयर्स)","किनारे पर कानूनी रूप से खड़ा कोई भी वाहन","केवल सरकारी स्वामित्व वाले वाहन","लाल बत्ती पर रुके हुए वाहन"],"explanation":"पेंसिल्वेनिया ने Move Over कर्तव्य को उन खराब वाहनों तक बढ़ाया जो कम से कम दो आपातकालीन चिह्न प्रदर्शित करते हैं जैसे हैज़र्ड लाइटें, सावधानी संकेत/उपकरण, या रोड फ्लेयर्स। चालकों को लेन बदलनी चाहिए या गति सीमा से 20 mph से अधिक कम न होने वाली गति तक धीमा होना चाहिए। स्रोत: 75 Pa.C.S. § 3327 (खराब वाहनों के संबंध में कर्तव्य)।"},"69":{"q":"एक दिशा में तीन या अधिक लेन वाले किसी पेंसिल्वेनिया सीमित-पहुँच राजमार्ग पर, 10,000 pounds से अधिक का ट्रक संयोजन कहाँ चल सकता है?","options":["बाएँ-हाथ की लेन को छोड़कर किसी भी लेन में (जो अनुमत बाएँ-मोड़ की तैयारी को छोड़कर प्रतिबंधित है)","हर समय केवल केंद्रीय लेन में","हर समय केवल दाएँ-हाथ की लेन में","किसी भी लेन में, बिना किसी प्रतिबंध के"],"explanation":"पेंसिल्वेनिया एक ही दिशा में तीन या अधिक लेन वाले सीमित-पहुँच राजमार्ग की बाएँ-हाथ की लेन में 10,000 pounds से अधिक के वाहन या संयोजन को चलाने से प्रतिबंधित करता है, सिवाय इसके कि जब किसी चौराहे, निकास, या ड्राइववे पर कानूनी रूप से अनुमत बाएँ-मोड़ की तैयारी कर रहा हो। स्रोत: 75 Pa.C.S. § 3313 (Restrictions on use of limited access highways)।"},"70":{"q":"एक दिशा में दो या अधिक लेन वाले पेंसिल्वेनिया सीमित-पहुँच राजमार्गों पर, सभी वाहनों के लिए सामान्य नियम दाईं लेनों में चलना है, सिवाय इसके कि जब:","options":["आगे निकलना और पास करना हो, यातायात प्रवाह से तेज़ चल रहे हों, या किसी अनुमत बाएँ-मोड़ की तैयारी कर रहे हों","रात में यात्रा कर रहे हों","सड़क गीली हो","कोई यात्री बाईं लेन का अनुरोध करे"],"explanation":"पेंसिल्वेनिया वाहनों से उपलब्ध होने पर दाएँ-हाथ की लेनों का उपयोग करने की आवश्यकता रखता है, सिवाय इसके कि जब किसी वाहन से आगे निकल रहे हों और पास कर रहे हों, यातायात प्रवाह से अधिक गति पर यात्रा कर रहे हों, या किसी कानूनी रूप से अनुमत बाएँ-मोड़ की तैयारी कर रहे हों। स्रोत: 75 Pa.C.S. § 3313।"},"71":{"q":"किसी लगे हुए संकेत के अभाव में, अधिकांश पेंसिल्वेनिया सड़कों (शहरी क्षेत्र या फ्रीवे नहीं) पर डिफ़ॉल्ट अधिकतम गति सीमा है:","options":["55 mph","50 mph","60 mph","65 mph"],"explanation":"पेंसिल्वेनिया उन स्थानों पर जहाँ अन्यथा पोस्ट नहीं किया गया है, 55 mph की वैधानिक अधिकतम सीमा, किसी भी शहरी क्षेत्र में 35 mph, और फ्रीवे पर 65 या 70 mph तक की सीमा निर्धारित करता है जहाँ विभाग वह सीमा पोस्ट करता है। स्रोत: 75 Pa.C.S. § 3362 (Maximum speed limits)।"},"72":{"q":"70 mph पर पोस्ट किए गए किसी पेंसिल्वेनिया फ्रीवे पर, एक भारी वाणिज्यिक ट्रक के लिए अधिकतम गति सीमा एक यात्री कार की तुलना में कैसी होती है?","options":["यह समान है—70 mph सभी वाहनों पर लागू होती है","ट्रक 55 mph तक सीमित हैं","ट्रक 60 mph तक सीमित हैं","ट्रक 65 mph तक सीमित हैं"],"explanation":"पेंसिल्वेनिया कोई अलग, कम ट्रक गति सीमा निर्धारित नहीं करता; पोस्ट की गई 65 या 70 mph फ्रीवे अधिकतम सीमा सभी वाहनों पर लागू होती है। (विशिष्ट ढलानों पर या पोस्ट किए गए संकेतों के माध्यम से कम सीमाएँ लागू हो सकती हैं।) स्रोत: 75 Pa.C.S. § 3362।"},"73":{"q":"पेंसिल्वेनिया टर्नपाइक मेनलाइन (I-76) पर अधिकतम पोस्ट की गई गति सीमा है:","options":["70 mph","65 mph","75 mph","80 mph"],"explanation":"पेंसिल्वेनिया टर्नपाइक की अधिकतम पोस्ट की गई गति सीमा 70 mph है, जो अधिकांश मेनलाइन (जैसे, Blue Mountain और Morgantown इंटरचेंजों के बीच) और कई PennDOT फ्रीवे पर लागू है। कोई भी खंड 75 mph पर पोस्ट नहीं किया गया है। स्रोत: Pennsylvania Turnpike Commission / PennDOT; 75 Pa.C.S. § 3362।"},"74":{"q":"पेंसिल्वेनिया की शहरी-क्षेत्र वैधानिक गति सीमा, जहाँ कोई अन्य सीमा पोस्ट नहीं की गई है, है:","options":["35 mph","25 mph","30 mph","40 mph"],"explanation":"किसी भी शहरी क्षेत्र में, पेंसिल्वेनिया की वैधानिक अधिकतम गति 35 mph है जब तक कि किसी यातायात अध्ययन के बाद कोई भिन्न सीमा पोस्ट न की जाए। स्रोत: 75 Pa.C.S. § 3362।"},"75":{"q":"एक ट्रक चालक जिसका CMV किसी दो-लेन, दो-तरफ़ा पेंसिल्वेनिया राजमार्ग के चलने वाले हिस्से पर रुका हुआ है, उसे कितने समय के भीतर और कहाँ चेतावनी उपकरण लगाने चाहिए?","options":["10 minutes के भीतर: 10 ft पर, पीछे की ओर 100 ft पर, और आगे की ओर 100 ft पर","15 minutes के भीतर: 25 ft, 50 ft, और 100 ft पर","30 minutes के भीतर: 10 ft, 200 ft, और 300 ft पर","5 minutes के भीतर: तीनों 50 ft के भीतर"],"explanation":"पेंसिल्वेनिया द्वारा लागू संघीय मानक के अनुसार, एक रुके हुए CMV को 10 minutes के भीतर चेतावनी उपकरण प्रदर्शित करने चाहिए। दो-तरफ़ा सड़क पर, एक उपकरण वाहन के 10 ft के भीतर आ रहे यातायात की ओर रखें, एक लगभग 100 ft पीछे की ओर, और एक लगभग 100 ft आगे की ओर। स्रोत: PA CDL Manual (PUB 223); 49 CFR 392.22।"},"76":{"q":"जब कोई CMV किसी एकतरफ़ा या विभाजित पेंसिल्वेनिया राजमार्ग पर रुका हो, तो आ रहे यातायात की ओर तीन चेतावनी उपकरण कहाँ रखे जाते हैं?","options":["पीछे की ओर लगभग 10 ft, 100 ft, और 200 ft पर","पीछे की ओर लगभग 10 ft, 50 ft, और 100 ft पर","पीछे की ओर लगभग 25 ft, 100 ft, और 250 ft पर","पीछे की ओर लगभग 10 ft, 100 ft, और 150 ft पर"],"explanation":"किसी एकतरफ़ा या विभाजित राजमार्ग पर, रुकने के 10 minutes के भीतर आ रहे यातायात की ओर (जिस तरफ़ से यातायात आता है) लगभग 10 feet, 100 feet, और 200 feet पर चेतावनी उपकरण रखें। स्रोत: PA CDL Manual (PUB 223); 49 CFR 392.22।"},"77":{"q":"खतरनाक सामग्रियों के किस वर्ग को पेंसिल्वेनिया टर्नपाइक की सुरंगों से होकर ले जाने पर प्रतिबंध है?","options":["सभी विस्फोटक और अन्य Table 1 सामग्री (जैसे, ज़हरीली गैस, रेडियोधर्मी)","केवल बल्क में ज्वलनशील तरल पदार्थ","केवल संक्षारक सामग्री","केवल प्रशीतित गैसें"],"explanation":"पेंसिल्वेनिया टर्नपाइक अपनी सुरंगों से सभी Table 1 सामग्रियों पर प्रतिबंध लगाता है—जिनमें सभी विस्फोटक, ज़हरीली गैस, गीले होने पर खतरनाक, ज़हर-श्वसन-खतरा, और रेडियोधर्मी सामग्री शामिल हैं; अन्य हैज़मैट की कुछ गैर-बल्क खेपों को अनुमति दी जा सकती है। स्रोत: Pennsylvania Turnpike Commission Hazardous Materials Tunnel Restrictions; 67 Pa. Code § 601.5।"},"78":{"q":"पेंसिल्वेनिया में चमकती लाल लाइटों वाली रुकी हुई स्कूल बस को अवैध रूप से पास करने के दोषी पाए गए चालक को एक मूल जुर्माना और एक अधिभार का सामना करना पड़ता है:","options":["$250 जुर्माना और $35 अधिभार (अंकों और लाइसेंस निलंबन के साथ)","बिना किसी अधिभार के $100 जुर्माना","$500 जुर्माना और $50 अधिभार","$50 जुर्माना और $25 अधिभार"],"explanation":"पेंसिल्वेनिया रुकी हुई स्कूल बस को अवैध रूप से पास करने पर $250 जुर्माना और $35 अधिभार के साथ दंडित करता है; किसी अधिकारी द्वारा देखे गए उल्लंघन पर 5 अंक और 60-दिन का लाइसेंस निलंबन भी होता है। स्रोत: 75 Pa.C.S. § 3345।"},"79":{"q":"पेंसिल्वेनिया में वाणिज्यिक चालक लाइसेंस (CDL) कौन-सी एजेंसी जारी करती है?","options":["The Pennsylvania State Police, Commercial Vehicle Unit","The Pennsylvania Department of Transportation (PennDOT), Bureau of Driver and Vehicle Services","The Pennsylvania Public Utility Commission (PUC)","The Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"पेंसिल्वेनिया CDL, PennDOT द्वारा अपने Bureau of Driver and Vehicle Services के माध्यम से जारी किए जाते हैं। FMCSA संघीय मानक निर्धारित करता है लेकिन राज्य लाइसेंस जारी नहीं करता। स्रोत: PennDOT Commercial Driver's License Fact Sheet (PUB 223 reference) और pa.gov Driver and Vehicle Services।"},"80":{"q":"पेंसिल्वेनिया में, अंतर्राज्यीय (पेंसिल्वेनिया के भीतर) ड्राइविंग बनाम अंतरराज्यीय ड्राइविंग के लिए CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["अंतर्राज्यीय और अंतरराज्यीय दोनों के लिए 21","अंतर्राज्यीय के लिए 16 और अंतरराज्यीय के लिए 18","अंतर्राज्यीय के लिए 18 और अंतरराज्यीय के लिए 21","अंतर्राज्यीय और अंतरराज्यीय दोनों के लिए 18"],"explanation":"पेंसिल्वेनिया केवल अंतर्राज्यीय संचालन के लिए 18 वर्ष की आयु में CDL की अनुमति देता है, जबकि अंतरराज्यीय संचालन (और राज्य की सीमाओं के पार हैज़मैट या यात्री परिवहन) के लिए चालक का कम से कम 21 वर्ष का होना आवश्यक है। स्रोत: PennDOT CDL licensing requirements (pa.gov) जो 49 CFR 383.3 के अनुरूप है।"},"81":{"q":"पेंसिल्वेनिया में CDL स्किल्स टेस्ट देने से पहले, एक आवेदक को सबसे पहले कौन-सा क्रेडेंशियल प्राप्त करना चाहिए?","options":["PennDOT से एक चिकित्सा छूट","A Commercial Learner's Permit (CLP)","एक REAL ID-अनुपालक फ़ोटो लाइसेंस","एक Class C गैर-वाणिज्यिक CDL"],"explanation":"आवेदकों को स्किल्स टेस्ट देने से पहले आवश्यक ज्ञान परीक्षण(ओं) को पास करना होगा और एक Commercial Learner's Permit जारी किया जाना चाहिए। स्रोत: PennDOT CDL Learner's Permit FAQs और CDL Fact Sheet (pa.gov)।"},"82":{"q":"एक पेंसिल्वेनिया CDL या CLP आवेदक अपने द्वारा किए जाने वाले वाणिज्यिक ड्राइविंग के प्रकार को स्वयं-प्रमाणित करने के लिए कौन-सा फॉर्म उपयोग करता है?","options":["Driver's Record Request DL-503","Commercial Learner's Permit Application DL-31CD","Medical Examiner's Certificate DL-26","Self-Certification Form DL-11CD"],"explanation":"प्रत्येक CDL धारक और प्रत्येक CLP आवेदक को अपने संचालन की श्रेणी घोषित करते हुए Self-Certification Form DL-11CD जमा करना होगा। DL-31CD, CLP आवेदन है, जो एक अलग फॉर्म है। स्रोत: PennDOT Self-Certification/Medical Examiner's Certification FAQs और Form DL-11CD (pa.gov)।"},"83":{"q":"निम्नलिखित में से कौन-सी चार स्वयं-प्रमाणन श्रेणियों में से एक नहीं है जिनमें से एक पेंसिल्वेनिया CDL आवेदक को चुनना होगा?","options":["Exempt Agricultural Operator","Excepted Intrastate","Non-excepted Intrastate","Non-excepted Interstate"],"explanation":"चार स्वयं-प्रमाणन श्रेणियाँ हैं Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate, और Excepted Intrastate। \"Exempt Agricultural Operator\" एक स्वयं-प्रमाणन श्रेणी नहीं है। स्रोत: PennDOT Self-Certification Form DL-11CD और CDL Fact Sheet (pa.gov)।"},"84":{"q":"किस स्वयं-प्रमाणन श्रेणी में चालक के लिए PennDOT के रिकॉर्ड पर एक वैध Medical Examiner's Certificate (DOT physical card) होना आवश्यक है?","options":["Non-excepted Interstate","Excepted Intrastate","Excepted Interstate और Excepted Intrastate","Excepted Interstate"],"explanation":"केवल वे चालक जो स्वयं को Non-excepted (Interstate या Intrastate) के रूप में प्रमाणित करते हैं, उन्हें PennDOT के रिकॉर्ड पर एक वैध Medical Examiner's Certificate रखना होगा। Excepted श्रेणियों को MEC प्रदान करना आवश्यक नहीं है। स्रोत: PennDOT Self-Certification/Medical Examiner's Certification FAQs (pa.gov)।"},"85":{"q":"23 जून, 2025 तक, एक पेंसिल्वेनिया non-excepted CDL धारक का Medical Examiner's Certificate (DOT physical) PennDOT को कैसे जमा किया जाना चाहिए?","options":["इसे FMCSA National Registry से सीधे PennDOT को इलेक्ट्रॉनिक रूप से प्रेषित किया जाता है","चालक किसी भी PennDOT Driver License Center पर एक क्लर्क को कागज़ी कार्ड सौंपता है","चालक PennDOT को एक स्कैन की गई प्रति ईमेल करता है","चालक कागज़ी कार्ड को Harrisburg में PennDOT CDL Unit को डाक से भेजता है"],"explanation":"23 जून, 2025 से, PennDOT केवल FMCSA National Registry से इलेक्ट्रॉनिक रूप से प्रेषित Medical Examiner's Certificate जानकारी स्वीकार करता है; यह अब व्यक्तिगत रूप से, डाक से, या ईमेल द्वारा MEC स्वीकार नहीं करता। स्रोत: PennDOT Self-Certification/Medical Examiner's Certification FAQs (pa.gov)।"},"86":{"q":"पेंसिल्वेनिया CDL स्किल्स टेस्ट के तीन घटक हैं pre-trip (वाहन) निरीक्षण, ऑन-रोड ड्राइविंग टेस्ट, और कौन-सा तीसरा घटक?","options":["एक लिखित रक्षात्मक-ड्राइविंग परीक्षा","Basic vehicle control (सड़क से बाहर के युक्तियाँ और पार्किंग)","एक समयबद्ध ब्रेक-प्रतिक्रिया रिफ्लेक्स परीक्षण","एक कपलिंग-और-अनकपलिंग लैब सिमुलेशन"],"explanation":"पेंसिल्वेनिया के CDL स्किल्स टेस्ट के तीन भाग हैं: pre-trip inspection, basic vehicle control (सड़क से बाहर के युक्तियाँ और वाहन पार्किंग अभ्यास), और ऑन-रोड ड्राइविंग टेस्ट। स्रोत: PennDOT CDL Fact Sheet, \"Skills Tests\" section (pa.gov)।"},"87":{"q":"पहली बार Class A या Class B लाइसेंस के लिए CDL स्किल्स टेस्ट देने की अनुमति मिलने से पहले एक पेंसिल्वेनिया आवेदक को कौन-सी संघीय प्रशिक्षण आवश्यकता पूरी करनी चाहिए?","options":["एक PennDOT-संचालित कक्षा रक्षात्मक ड्राइविंग पाठ्यक्रम","किसी पंजीकृत प्रदाता से Entry-Level Driver Training (ELDT)","एक 40-घंटे का OSHA सुरक्षा पाठ्यक्रम","एक राज्य-जारी प्रशिक्षुता पूर्णता प्रमाणपत्र"],"explanation":"किसी आरंभिक Class A या B CDL के लिए स्किल्स टेस्ट देने से पहले (और पहली बार P, S, या H endorsements के लिए) FMCSA Training Provider Registry पर मौजूद किसी प्रदाता से Entry-Level Driver Training (ELDT) पूरा करना आवश्यक है। स्रोत: PennDOT CDL Fact Sheet (pa.gov) और FMCSA ELDT rule (49 CFR Part 380)।"},"88":{"q":"PennDOT CDL Fact Sheet के अनुसार, पेंसिल्वेनिया में Class A सामान्य ज्ञान लिखित परीक्षण में कितने प्रश्न होते हैं?","options":["50 questions","30 questions","70 questions","100 questions"],"explanation":"PennDOT की CDL Fact Sheet में Class A लिखित ज्ञान परीक्षण को 70 questions के रूप में सूचीबद्ध किया गया है, जबकि Class B और Class C प्रत्येक 50 questions हैं। स्रोत: PennDOT CDL Fact Sheet, \"What Tests Do I Need to Take?\" (pa.gov)।"},"89":{"q":"पेंसिल्वेनिया Hazardous Materials (HazMat) endorsement ज्ञान परीक्षण में कितने प्रश्न होते हैं, और यह किस भाषा में दिया जाता है?","options":["25 questions, केवल अंग्रेज़ी","30 questions, केवल अंग्रेज़ी","50 questions, कई भाषाएँ","20 questions, कई भाषाएँ"],"explanation":"PennDOT, HazMat endorsement ज्ञान परीक्षण को 30 questions के रूप में सूचीबद्ध करता है, और HazMat परीक्षण केवल अंग्रेज़ी में दिया जाता है (अन्य CDL ज्ञान परीक्षण कई भाषाओं में उपलब्ध हैं)। स्रोत: PennDOT CDL Fact Sheet (pa.gov)।"},"90":{"q":"PennDOT CDL Fact Sheet के अनुसार, ज्ञान परीक्षण पास करने और परमिट जारी होने के कितने समय बाद एक पेंसिल्वेनिया आवेदक स्किल्स टेस्ट दे सकता है?","options":["ज्ञान परीक्षण पास होने और परमिट जारी होने के 15 days बाद तक नहीं","परमिट जारी होने के 30 days बाद तक नहीं","परमिट जारी होने के 60 days बाद तक नहीं","ज्ञान परीक्षण पास करने के तुरंत बाद"],"explanation":"PennDOT कहता है कि ज्ञान परीक्षण पास होने और परमिट जारी होने के 15 days बाद तक स्किल्स परीक्षण नहीं दिया जा सकता (एक आवेदक स्किल्स टेस्ट तुरंत शेड्यूल कर सकता है, लेकिन 15-दिन के बिंदु से पहले इसे नहीं दे सकता)। स्रोत: PennDOT CDL Fact Sheet, \"Skills Tests\" note (pa.gov)।"},"91":{"q":"पेंसिल्वेनिया वाणिज्यिक चालक लाइसेंस को नवीनीकृत किए जाने से पहले उसकी मानक वैधता अवधि क्या है (65 वर्ष से कम आयु के चालक के लिए)?","options":["5 years","8 years","2 years","4 years"],"explanation":"एक पेंसिल्वेनिया CDL आम तौर पर 4 years के लिए वैध होता है; 65 वर्ष और उससे अधिक आयु के चालकों को 2-year चक्र पर जारी किया जाता है। स्रोत: PennDOT Driver and Vehicle Services licensing information (pa.gov)।"},"92":{"q":"65 वर्ष या उससे अधिक आयु के चालक को जारी किया गया पेंसिल्वेनिया CDL कितने समय के लिए होता है?","options":["4 years","2 years","3 years","1 year"],"explanation":"जबकि मानक पेंसिल्वेनिया CDL चक्र 4 years का है, 65 और उससे अधिक आयु के चालकों को 2-year नवीनीकरण चक्र पर रखा जाता है। स्रोत: PennDOT Driver and Vehicle Services licensing information (pa.gov)।"},"93":{"q":"यदि एक पेंसिल्वेनिया non-excepted CDL धारक अपने Medical Examiner's Certificate को समाप्त होने देता है और एक नया प्रदान नहीं करता, तो उनके लाइसेंस का क्या होता है?","options":["वाणिज्यिक (CDL) पदनाम को एक गैर-वाणिज्यिक लाइसेंस में अवनत कर दिया जाता है","$500 का नागरिक दंड लगाया जाता है लेकिन CDL वैध रहता है","लाइसेंस स्थायी रूप से रद्द कर दिया जाता है और बहाल नहीं किया जा सकता","अगले 4-year नवीनीकरण तक कुछ नहीं बदलता"],"explanation":"यदि किसी non-excepted चालक का चिकित्सा प्रमाणन समाप्त हो जाता है, तो PennDOT वाणिज्यिक पदनाम हटा देता है और क्रेडेंशियल को एक गैर-वाणिज्यिक चालक लाइसेंस में अवनत कर देता है; चालक को वाणिज्यिक विशेषाधिकार पुनः प्राप्त करने के लिए CLP के लिए फिर से आवेदन करना होगा। स्रोत: PennDOT Self-Certification/Medical Examiner's Certification FAQs (pa.gov)।"},"94":{"q":"पेंसिल्वेनिया में, स्वयं Commercial Learner's Permit के लिए आवेदन करने के लिए कौन-सा दस्तावेज़ उपयोग किया जाता है?","options":["Form MV-1, वाहन शीर्षक आवेदन","Form DL-180, गैर-वाणिज्यिक learner's permit आवेदन","Form DL-11CD, the Self-Certification Form","Form DL-31CD, the Commercial Learner's Permit Application"],"explanation":"Commercial Learner's Permit Application, Form DL-31CD है। Form DL-11CD अलग स्वयं-प्रमाणन फॉर्म है, और एक CLP आवेदक आम तौर पर दोनों जमा करता है। स्रोत: PennDOT CDL Learner's Permit FAQs (pa.gov)।"},"95":{"q":"PennDOT नियमों के तहत, एक बार जब कोई पेंसिल्वेनिया CDL आवेदक प्रक्रिया शुरू कर देता है, तो उन्हें फिर से शुरू करने से पहले सभी आवश्यक ज्ञान और स्किल्स टेस्ट पास करने के लिए कितना समय मिलता है?","options":["छह महीने","90 days","एक वर्ष","दो वर्ष"],"explanation":"PennDOT आवेदक को CDL प्राप्त करने के लिए सभी ज्ञान और स्किल्स टेस्ट पास करने के लिए एक वर्ष देता है; यदि परीक्षण समय पर पूरा नहीं होता है तो परमिट को एक नए DL-31CD आवेदन के साथ बढ़ाया जा सकता है। स्रोत: PennDOT CDL Learner's Permit FAQs (pa.gov)।"},"96":{"q":"एक चालक केवल एक 20-यात्री वाहन चलाने के लिए Class C CDL चाहता है। PennDOT CDL Fact Sheet के अनुसार, एक Class C CDL में क्या शामिल होना चाहिए?","options":["एक S, P, या H endorsement","किसी भी प्रकार का कोई endorsement नहीं","एक double/triple-trailer endorsement","केवल एक air-brake restriction code"],"explanation":"PennDOT Class C को 26,001 lbs से कम के एकल वाहनों के रूप में परिभाषित करता है जो प्लेकार्डिंग की आवश्यकता वाले हैज़मैट का परिवहन करते हैं, 16+ यात्रियों को ले जाते हैं, या स्कूल बसें हैं; Fact Sheet कहता है कि एक Class C CDL में एक S, P, या H endorsement शामिल होना चाहिए। स्रोत: PennDOT CDL Fact Sheet, license classes (pa.gov)।"},"97":{"q":"PennDOT CDL Fact Sheet के अनुसार, कौन-सा endorsement पहली बार प्राप्त किए जाने पर अलग से Entry-Level Driver Training की आवश्यकता रखता है?","options":["The Hazardous Materials (H) endorsement","The Doubles/Triples (T) endorsement","The Tank Vehicle (N) endorsement","एयर-ब्रेक प्रतिबंध हटाना"],"explanation":"PennDOT की Fact Sheet दर्शाती है कि Passenger, School Bus, और Hazardous Materials (H) endorsements के लिए ELDT आवश्यक है (केवल आरंभिक के लिए); Doubles/Triples और Tank endorsements को ELDT की आवश्यकता न होने के रूप में सूचीबद्ध किया गया है। स्रोत: PennDOT CDL Fact Sheet endorsement/testing table (pa.gov)।"},"98":{"q":"जब कोई पेंसिल्वेनिया आवेदक CDL स्किल्स टेस्ट के लिए उपस्थित होता है, तो उन्हें कौन-सा वाहन लाना चाहिए?","options":["वैध पंजीकरण वाली कोई भी यात्री कार","केंद्र पर सौंपा गया एक PennDOT-स्वामित्व वाला परीक्षण वाहन","मांगे जा रहे CDL से एक श्रेणी छोटा वाहन","उस श्रेणी और प्रकार का एक प्रतिनिधि वाहन जिसे वे चलाने का इरादा रखते हैं"],"explanation":"स्किल्स टेस्ट उस श्रेणी और प्रकार के वाहन में देना होगा जिसे आवेदक चलाने का इरादा रखता है (उदाहरण के लिए, एक school bus endorsement स्किल्स टेस्ट एक स्कूल बस में देना होगा)। स्रोत: PennDOT CDL Fact Sheet, \"Skills Tests\" section (pa.gov)।"}},"ar":{"0":{"q":"على طرق ولاية بنسلفانيا السريعة، ما هو الحد الأقصى للعرض الخارجي الإجمالي للمركبة، بما في ذلك أي حمولة؟","options":["8 أقدام و6 بوصات","8 أقدام و0 بوصة","9 أقدام و0 بوصة","10 أقدام و0 بوصة"],"explanation":"بموجب 75 Pa.C.S. § 4921 (عرض المركبات)، لا يجوز أن يتجاوز العرض الخارجي الإجمالي للمركبة، بما في ذلك أي حمولة، 8 أقدام و6 بوصات. وتنص صفحة قيود الحجم والوزن الخاصة بخدمات السائقين والمركبات في Pennsylvania DMV على الرقم ذاته."},"1":{"q":"ما هو الحد الأقصى لارتفاع المركبة، بما في ذلك أي حمولة، المسموح به عمومًا على طرق ولاية بنسلفانيا السريعة؟","options":["13 قدمًا و6 بوصات","13 قدمًا و0 بوصة","14 قدمًا و0 بوصة","12 قدمًا و6 بوصات"],"explanation":"بموجب 75 Pa.C.S. § 4922 (ارتفاع المركبات)، لا يجوز لأي مركبة، بما في ذلك حمولتها، أن تتجاوز ارتفاع 13 قدمًا و6 بوصات. وهذا مؤكد في صفحة قيود الحجم والوزن الخاصة بـ Pennsylvania DMV."},"2":{"q":"ما هو الحد الأقصى للطول الإجمالي لمركبة آلية فردية واحدة، بما في ذلك الحمولة والمصدّات، على طرق ولاية بنسلفانيا السريعة؟","options":["40 قدمًا","45 قدمًا","53 قدمًا","35 قدمًا"],"explanation":"بموجب 75 Pa.C.S. § 4923 (طول المركبات)، لا يجوز أن تتجاوز المركبة الآلية الفردية الواحدة، بما في ذلك أي حمولة والمصدّات، 40 قدمًا إجمالًا. وللأنواع الخاصة من المركبات (الحافلات، والبيوت المتنقلة، والمركبات المزودة بذراع رافعة) حدود منفصلة وأعلى."},"3":{"q":"ما هو الحد الأقصى للوزن الإجمالي لأي مركبة فردية أو تركيبة على طرق ولاية بنسلفانيا السريعة بموجب قانون المركبات؟","options":["80,000 رطل","73,280 رطلًا","90,000 رطل","100,000 رطل"],"explanation":"بموجب 75 Pa.C.S. § 4941، وكما هو مذكور في صفحة قيود الحجم والوزن الخاصة بـ Pennsylvania DMV، فإن الحد الأقصى للوزن الإجمالي لأي مركبة فردية أو أي تركيبة هو 80,000 رطل، مع الخضوع أيضًا لحدود الوزن المسجّل ووزن المحور."},"4":{"q":"ما هو الحد الأقصى لطول مقطورة نصفية واحدة في تركيبة جرّار ومقطورة تعمل في ولاية بنسلفانيا؟","options":["53 قدمًا","48 قدمًا","57 قدمًا","40 قدمًا"],"explanation":"تسمح ولاية بنسلفانيا بأن يصل طول مقطورة واحدة في تركيبة جرّار ومقطورة نصفية إلى 53 قدمًا، شريطة ألا تتجاوز المسافة من مسمار الارتكاز إلى المحور الخلفي 41 قدمًا. وهذا منعكس في 75 Pa.C.S. الفصل 49 وصفحة قيود الحجم والوزن الخاصة بـ Pennsylvania DMV."},"5":{"q":"في تركيبة ثنائية المقطورة (مزدوجة) في ولاية بنسلفانيا، ما هو الحد الأقصى لطول كل مقطورة؟","options":["28 قدمًا و6 بوصات","28 قدمًا و0 بوصة","33 قدمًا و0 بوصة","30 قدمًا و0 بوصة"],"explanation":"تنص صفحة قيود الحجم والوزن الخاصة بـ Pennsylvania DMV على أنه في التركيبة ثنائية المقطورة، يقتصر طول كل مقطورة على 28 قدمًا و6 بوصات، بما يتوافق مع أحكام الطول في 75 Pa.C.S. الفصل 49."},"6":{"q":"على نظام الطرق السريعة بين الولايات في بنسلفانيا، ما هو الحد الأقصى للوزن الإجمالي للمركبة حتى عندما تسمح صيغة الجسور الفيدرالية بأكثر من ذلك؟","options":["80,000 رطل","85,500 رطلًا","90,000 رطل","73,280 رطلًا"],"explanation":"تتبع ولاية بنسلفانيا المعيار الفيدرالي: على نظام الطرق بين الولايات يُحدَّد الوزن الإجمالي للمركبة بسقف 80,000 رطل، حتى لو كانت نتيجة صيغة الجسور الفيدرالية أعلى. وينطبق هذا الحد الفيدرالي على الطرق بين الولايات في بنسلفانيا بموجب 23 U.S.C. § 127 و75 Pa.C.S. § 4941."},"7":{"q":"ما هو الحد الأقصى للوزن المسموح به على محور واحد (غير محور التوجيه) لتركيبة ثقيلة في ولاية بنسلفانيا؟","options":["20,000 رطل","18,000 رطل","22,400 رطل","34,000 رطل"],"explanation":"بموجب 75 Pa.C.S. § 4943 (والمعيار الفيدرالي الذي تتبعه بنسلفانيا)، فإن الحد الأقصى للوزن على محور واحد هو 20,000 رطل. وهذا يطابق حد المحور الواحد الفيدرالي المطبَّق على نظام الطرق بين الولايات."},"8":{"q":"بموجب معيار الوزن الفيدرالي الذي تطبّقه بنسلفانيا، ما هو الحد الأقصى للوزن على محور مزدوج (مجموعة من محورين متتاليين)؟","options":["34,000 رطل","36,000 رطل","40,000 رطل","20,000 رطل"],"explanation":"تطبّق ولاية بنسلفانيا حد المحور المزدوج الفيدرالي البالغ 34,000 رطل. ويسمح 75 Pa.C.S. § 4943 لزوجين متتاليين من المحاور بحمل 34,000 رطل لكل منهما عندما تكون المسافة بين المحور الأول والأخير من الأزواج 36 قدمًا أو أكثر."},"9":{"q":"ما هو الغرض الأساسي من صيغة الجسور الفيدرالية كما تُطبَّق في ولاية بنسلفانيا؟","options":["الحد من الوزن على مجموعات المحاور لتقليل خطر إلحاق الضرر بجسور الطرق السريعة","تحديد الحد الأقصى لارتفاع الحمولات التي تمر تحت الجسور","حساب الرسوم المستحقة على طريق Pennsylvania Turnpike","تحديد الحد الأدنى لمسافة الاتباع للشاحنات الثقيلة"],"explanation":"تحدّ صيغة الجسور الفيدرالية (صيغة الوزن الإجمالي للجسور) من الوزن المسموح به على أي مجموعة من المحاور المتتالية بناءً على عدد المحاور والمسافة بينها، لحماية الجسور. وتنطبق على نظام الطرق بين الولايات في بنسلفانيا بموجب 23 U.S.C. § 127."},"10":{"q":"متى يُطلب الحصول على تصريح نقل من PennDOT لتشغيل مركبة في ولاية بنسلفانيا؟","options":["عندما تتجاوز المركبة أو الحمولة حدود الحجم أو الوزن القانونية المنصوص عليها في قانون المركبات","فقط عند العبور إلى ولاية أخرى","كلما تم نقل أي بضائع تجارية","فقط عندما لا يحمل السائق رخصة CDL"],"explanation":"وفقًا لصفحة قيود الحجم والوزن الخاصة بـ Pennsylvania DMV، لا يجوز تشغيل مركبة خارج حدود الحجم/الوزن القانونية إلا بتصريح من PennDOT. وتجيز تصاريح النقل للحمولات الزائدة الحجم/الوزن الحركة التي تتجاوز الحدود المنصوص عليها في 75 Pa.C.S. الفصل 49."},"11":{"q":"عبر أي نظام لدى PennDOT يتم بشكل أساسي تقديم طلبات تصاريح النقل الخاصة للحمولات الزائدة الحجم/الوزن وإصدارها في ولاية بنسلفانيا؟","options":["APRAS (النظام الآلي لتوجيه وتحليل التصاريح)","CDLIS (نظام معلومات رخص القيادة التجارية)","بوابة IRP (خطة التسجيل الدولية)","SAFER (السجلات الإلكترونية للسلامة واللياقة)"],"explanation":"تُصدر PennDOT تصاريح النقل الخاصة للحمولات الزائدة الحجم/الوزن عبر APRAS، النظام الآلي لتوجيه وتحليل التصاريح، الذي يعالج مئات الآلاف من التصاريح سنويًا، والكثير منها تلقائيًا. المصدر: PennDOT APRAS / التقدّم للحصول على تصريح نقل من PennDOT."},"12":{"q":"تُعتبر المركبة والحمولة التي يزيد عرضها عن أي قيمة زائدة الحجم وتتطلب تصريحًا من PennDOT؟","options":["أكثر من 8 أقدام و6 بوصات","أكثر من 8 أقدام و0 بوصة","أكثر من 9 أقدام و0 بوصة","أكثر من 10 أقدام و0 بوصة"],"explanation":"بما أن العرض القانوني بموجب 75 Pa.C.S. § 4921 هو 8 أقدام و6 بوصات، فإن أي مركبة وحمولة يزيد عرضها عن 8 أقدام و6 بوصات تُعتبر زائدة الحجم وتتطلب تصريح نقل من PennDOT. المصدر: تصريح النقل من PennDOT / إرشادات نوع الحمولة."},"13":{"q":"تُعتبر الحمولة التي يزيد ارتفاعها عن أي قيمة زائدة الحجم وتتطلب تصريحًا من PennDOT؟","options":["أكثر من 13 قدمًا و6 بوصات","أكثر من 13 قدمًا و0 بوصة","أكثر من 14 قدمًا و0 بوصة","أكثر من 12 قدمًا و6 بوصات"],"explanation":"بما أن حد الارتفاع القانوني بموجب 75 Pa.C.S. § 4922 هو 13 قدمًا و6 بوصات، فإن الحمولة التي تتجاوز 13 قدمًا و6 بوصات تُعتبر زائدة الحجم وتتطلب تصريح نقل من PennDOT. المصدر: قيود الحجم والوزن الخاصة بـ PennDOT / إرشادات تصريح النقل."},"14":{"q":"ما هو الحد الأقصى للوزن المسموح به على محور التوجيه قبل أن تُعتبر المركبة زائدة الوزن في ولاية بنسلفانيا؟","options":["20,000 رطل","12,000 رطل","18,000 رطل","22,400 رطل"],"explanation":"وفقًا لإرشادات تصاريح PennDOT بموجب 75 Pa.C.S. § 4943، تُعتبر المركبة زائدة الوزن إذا تجاوز الوزن على محور التوجيه 20,000 رطل. وفوق ذلك، يُطلب الحصول على تصريح وزن زائد من PennDOT."},"15":{"q":"بموجب تصريح ولاية بنسلفانيا السنوي 'الحركة أثناء عملية التصنيع' (75 Pa.C.S. § 4968)، أي سلعة خام من منتجات الغابات يجوز نقلها بوزن يتجاوز الحد الأقصى؟","options":["خشب اللبّ ورقائق الخشب","الأثاث الجاهز","النشارة المعبأة للبيع بالتجزئة","أخشاب البناء إلى تاجر تجزئة"],"explanation":"يجيز 75 Pa.C.S. § 4968 الحركة بموجب تصريح سنوي بوزن يتجاوز الحد الأقصى لسلع مثل الحليب الخام، والفحم الخام، وخشب اللبّ، ورقائق الخشب أثناء وجودها في عملية التصنيع وتحت سيطرة المصنّع. ولا يُصدر أي تصريح للبضائع العابرة إلى مشترٍ أو تاجر."},"16":{"q":"على طريق Pennsylvania Turnpike، قد تتجاوز بعض الحمولات المُصرَّح بها الحد العام البالغ 80,000 رطل حتى أي حد أقصى للوزن الإجمالي؟","options":["100,000 رطل","80,000 رطل","90,000 رطل","120,000 رطل"],"explanation":"يضع طريق Pennsylvania Turnpike حدوده الخاصة بالتصاريح التجارية، فيسمح بوزن إجمالي مُصرَّح به يصل إلى 100,000 رطل (مع وزن محور يصل إلى 22,400 رطل). المصدر: التصاريح والقيود التجارية لـ PA Turnpike. أما طرق PennDOT السريعة فتظل محدّدة بسقف 80,000 رطل."},"17":{"q":"بموجب 75 Pa.C.S. § 4943، ما هو الحد الأقصى للوزن على زوج من المحاور تفصل بينهما مسافة تزيد عن 8 أقدام في تركيبة ثقيلة؟","options":["22,400 رطل لكل منهما","18,000 رطل لكل منهما","20,000 رطل لكل منهما","34,000 رطل لكل منهما"],"explanation":"بموجب قواعد تباعد المحاور في 75 Pa.C.S. § 4943، يجوز للمحاور التي تفصل بينها مسافة تزيد عن 8 أقدام أن تحمل ما يصل إلى 22,400 رطل لكل منها، بينما تقتصر المحاور التي تفصل بينها مسافة تقل عن 6 أقدام على 18,000 رطل لكل منها."},"18":{"q":"لماذا تحدّ صيغة الجسور الفيدرالية أحيانًا الشاحنة بأقل من 80,000 رطل حتى عندما لا تكون أي مجموعة محاور واحدة محمّلة بشكل زائد؟","options":["لأن مجموعات المحاور المتقاربة تركّز الوزن، لذا تقلّل الصيغة الوزن الإجمالي المسموح به لحماية الجسور","لأن محور التوجيه يُستثنى دائمًا من الوزن الإجمالي","لأن بنسلفانيا تحدّد سقفًا لجميع الشاحنات عند 73,280 رطلًا","لأن الرسوم تزداد مع تباعد المحاور"],"explanation":"تربط صيغة الجسور الفيدرالية الوزن المسموح به بعدد المحاور والمسافة الممتدة بينها. وعندما تكون المحاور متقاربة، تنتج الصيغة قيمة أقل من 80,000 رطل للحد من الإجهاد على عوارض الجسور. وتطبّق بنسلفانيا هذا على نظام الطرق بين الولايات بموجب 23 U.S.C. § 127."},"19":{"q":"كيف يجب التعامل مع حركة زائدة الحجم/الوزن تتجاوز أكبر عتبات التصاريح القياسية في بنسلفانيا (حمولة فائقة 'superload')؟","options":["تقديمها عبر APRAS للمراجعة، وغالبًا ما تتطلب تحليلًا وتوجيهًا يدويًا قبل الموافقة","قيادتها دون تصريح إذا تم نقلها ليلًا","الموافقة عليها تلقائيًا في أي مركز ترخيص بالصور تابع لـ PennDOT","إعفاؤها من جميع عمليات التوجيه لأنها تدفع رسومًا أعلى"],"explanation":"يجب تقديم طلبات الحمولات الفائقة عبر نظام APRAS التابع لـ PennDOT؛ وبينما تتم الموافقة على معظم التصاريح الروتينية تلقائيًا في نحو دقيقة، فإن الحمولات الفائقة وما يقارب طلبًا واحدًا من كل خمسة طلبات تتطلب مراجعة يدوية وتحليل المسار. المصدر: PennDOT APRAS."},"20":{"q":"في ولاية بنسلفانيا، أي فئة من رخصة CDL مطلوبة لتشغيل تركيبة من المركبات بتصنيف وزن إجمالي مركّب (GCWR) يبلغ 26,001 رطل أو أكثر، عندما يكون للمركبة المقطورة تصنيف GVWR يتجاوز 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"وفقًا لصحيفة وقائع رخصة القيادة التجارية الخاصة بـ PennDOT (يونيو 2025) وPUB 223، تغطي رخصة CDL من الفئة A مركبة مركّبة بتصنيف GCWR يبلغ 26,001 رطل أو أكثر، شريطة أن يتجاوز تصنيف GVWR للمركبة المقطورة 10,000 رطل. المصدر: صحيفة وقائع CDL من PennDOT / دليل السائق التجاري (PUB 223)."},"21":{"q":"بموجب قواعد CDL في بنسلفانيا، تتطلب مركبة فردية واحدة بتصنيف وزن إجمالي للمركبة (GVWR) يبلغ 26,001 رطل أو أكثر (أو مثل هذه المركبة وهي تقطر وحدة لا تتجاوز 10,000 رطل) أي فئة رخصة؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"تعرّف PennDOT الفئة B بأنها مركبة فردية واحدة بتصنيف GVWR يبلغ 26,001 رطل أو أكثر، أو أي مركبة من هذا القبيل تقطر مركبة لا تتجاوز 10,000 رطل. المصدر: صحيفة وقائع CDL من PennDOT (يونيو 2025) / PUB 223."},"22":{"q":"وفقًا لـ PennDOT، تُستخدم رخصة CDL من الفئة C في بنسلفانيا لمركبة فردية واحدة يقل تصنيف GVWR لها عن 26,001 رطل وتنقل مواد خطرة موضوعة عليها لافتات، أو تحمل 16 شخصًا أو أكثر، أو تكون حافلة مدرسية. ماذا يجب أن تتضمن رخصة CDL من الفئة C أيضًا؟","options":["مصادقة S أو P أو H","مصادقة دراجة نارية (M)","شهادة فرامل هوائية من الفئة A","إعفاء مركبة زراعية"],"explanation":"تنص صحيفة وقائع CDL من PennDOT على أن رخصة CDL من الفئة C تغطي المركبات الفردية التي يقل تصنيف GVWR لها عن 26,001 رطل وتنقل مواد خطرة موضوعة عليها لافتات، أو المصممة لحمل 16 شخصًا أو أكثر بمن فيهم السائق، أو الحافلات المدرسية، وأن رخصة CDL من الفئة C يجب أن تتضمن مصادقة S أو P أو H. المصدر: صحيفة وقائع CDL من PennDOT (يونيو 2025)."},"23":{"q":"في ولاية بنسلفانيا، ماذا تخوّل مصادقة 'N' حامل رخصة CDL أن يفعل؟","options":["تشغيل مركبات الصهاريج","تشغيل المقطورات المزدوجة والثلاثية","نقل الركاب في حافلة","نقل مواد خطرة موضوعة عليها لافتات"],"explanation":"تنص PennDOT على أن المصادقة N تخوّل السائق تشغيل مركبات الصهاريج. (المصادقة T للمقطورات المزدوجة/الثلاثية، وP للركاب، وH للمواد الخطرة الموضوعة عليها لافتات.) المصدر: صحيفة وقائع CDL من PennDOT (يونيو 2025) / PUB 223."},"24":{"q":"أي مصادقة CDL في بنسلفانيا مطلوبة لقيادة المقطورات المزدوجة والثلاثية؟","options":["المصادقة T","المصادقة N","المصادقة X","المصادقة H"],"explanation":"تنص PennDOT على أن المصادقة T تخوّل قيادة المقطورات المزدوجة والثلاثية. المصدر: صحيفة وقائع CDL من PennDOT (يونيو 2025) / PUB 223."},"25":{"q":"على رخصة CDL في بنسلفانيا، ماذا تمثّل المصادقة المجمّعة 'X'؟","options":["كل من المواد الخطرة ومركبة الصهريج (H وN)","كل من الركاب والحافلة المدرسية (P وS)","كل من المزدوجة/الثلاثية والصهريج (T وN)","مصادقة منتهية الصلاحية بانتظار التجديد"],"explanation":"تُدرج PennDOT المصادقة X بأنها المواد الخطرة ومركبة الصهريج مجمّعتين (H,N). المصدر: صحيفة وقائع CDL من PennDOT (يونيو 2025)."},"26":{"q":"ما هو الحد الأدنى للسن للحصول على رخصة CDL في بنسلفانيا للقيادة داخل الولاية (تشغيل مركبة تجارية داخل بنسلفانيا فقط)؟","options":["18 عامًا","16 عامًا","19 عامًا","21 عامًا"],"explanation":"تتطلب ولاية بنسلفانيا حدًا أدنى للسن قدره 18 عامًا لحمل رخصة CDL للقيادة التجارية داخل الولاية (داخل الولاية فقط). المصدر: خدمات السائقين والمركبات في PennDOT، السائقون التجاريون / أنواع الرخص والقيود."},"27":{"q":"ما هو الحد الأدنى للسن المطلوب لتشغيل مركبة تجارية آلية في التجارة بين الولايات (عبر حدود الولايات) برخصة CDL من بنسلفانيا؟","options":["21 عامًا","18 عامًا","19 عامًا","25 عامًا"],"explanation":"لتشغيل مركبة تجارية آلية في التجارة بين الولايات، يجب أن يكون عمر السائق 21 عامًا على الأقل. ولا يجوز للسائقين الذين تتراوح أعمارهم بين 18 و20 عامًا سوى القيادة داخل ولاية بنسلفانيا فقط. المصدر: السائقون التجاريون في PennDOT / 49 CFR 391.11 كما هو مطبّق في بنسلفانيا."},"28":{"q":"بعد اجتياز اختبار المعرفة المطلوب وإصدار تصريح متعلّم القيادة التجارية في بنسلفانيا، ما هو الحد الأدنى لفترة الانتظار قبل جدولة اختبار المهارات للفئة A أو B أو C؟","options":["15 يومًا","10 أيام","30 يومًا","7 أيام"],"explanation":"وفقًا لـ PennDOT، لا يمكن إجراء اختبار المهارات إلا بعد 15 يومًا من اجتياز اختبار المعرفة وإصدار التصريح. وهذا يستوفي شرط الاحتفاظ بـ CLP لمدة 14 يومًا الفيدرالي. المصدر: صحيفة وقائع CDL من PennDOT (يونيو 2025) والأسئلة الشائعة حول تصريح متعلّم CDL."},"29":{"q":"إلى متى يكون تفويض اختبار المعرفة (KTA) / تصريح متعلّم القيادة التجارية في بنسلفانيا صالحًا، بما يمنح المتقدّم وقتًا لاجتياز جميع اختبارات المعرفة والمهارات؟","options":["سنة واحدة من تاريخ الإصدار","90 يومًا من تاريخ الإصدار","ستة أشهر من تاريخ الإصدار","سنتان من تاريخ الإصدار"],"explanation":"تنص PennDOT على أن KTA صالح لمدة سنة واحدة من تاريخ الإصدار، وأمام المتقدّمين سنة واحدة لاجتياز جميع اختبارات المعرفة والمهارات للحصول على رخصة CDL الخاصة بهم. المصدر: الأسئلة الشائعة حول تصريح متعلّم CDL من PennDOT."},"30":{"q":"يجب على كل شخص يتقدّم للحصول على تصريح متعلّم القيادة التجارية في بنسلفانيا أو يحمل رخصة CDL إكمال أي مستند يحدّد نوع العملية التجارية التي يقوم بها؟","options":["نموذج إقرار ذاتي (DL-11CD)","نموذج إعفاء REAL ID","نموذج تسجيل موزّع IRP","نموذج I-9 لتفويض العمل"],"explanation":"تتطلب PennDOT من كل حامل لرخصة CDL وكل متقدّم لـ CLP تقديم نموذج إقرار ذاتي (DL-11CD) يحدّد نوع قيادته. المصدر: صحيفة وقائع CDL من PennDOT (يونيو 2025) والأسئلة الشائعة حول الإقرار الذاتي/الفاحص الطبي."},"31":{"q":"أي مما يلي يُعد إحدى فئات الإقرار الطبي الذاتي الأربع التي يجب على متقدّم رخصة CDL في بنسلفانيا الاختيار من بينها؟","options":["غير المستثنى بين الولايات","المستثنى خارج الولاية","ذو اللافتات بين الولايات","المقيّد داخل الولاية"],"explanation":"فئات الإقرار الذاتي الأربع هي: غير المستثنى بين الولايات، وغير المستثنى داخل الولاية، والمستثنى بين الولايات، والمستثنى داخل الولاية. ويجب أن يكون لدى سائق 'غير مستثنى بين الولايات' شهادة فاحص طبي سارية مودعة لدى PennDOT. المصدر: الأسئلة الشائعة حول الإقرار الذاتي/الفاحص الطبي من PennDOT."},"32":{"q":"السائق في بنسلفانيا الذي يقرّ ذاتيًا بأنه 'غير مستثنى داخل الولاية' يخضع للمعايير الفيدرالية للياقة البدنية أثناء القيادة داخل الولاية فقط. أي قيد على الرخصة تضيفه PennDOT في هذه الحالة؟","options":["قيد 'K' (التجارة داخل الولاية فقط)","قيد 'L' (بدون فرامل هوائية)","قيد 'E' (بدون ناقل حركة يدوي)","قيد 'O' (بدون تركيبة العجلة الخامسة)"],"explanation":"تطبّق PennDOT القيد K الذي يقتصر بالسائق على التجارة داخل الولاية فقط. ويظهر القيد K للتشغيل التجاري داخل الولاية فقط. المصدر: صحيفة وقائع CDL من PennDOT (يونيو 2025) والأسئلة الشائعة حول الإقرار الذاتي."},"33":{"q":"اعتبارًا من 7 فبراير 2022، يُشترط تدريب السائقين المبتدئين (ELDT) في بنسلفانيا للمتقدّمين لأول مرة لأي مستند (مستندات)؟","options":["أول رخصة CDL من الفئة A أو B، أو أول مصادقة P أو S أو H","أي تجديد لرخصة CDL بغض النظر عن الفئة","مصادقة المواد الخطرة (H) فقط","رخص CDL من الفئة C داخل الولاية فقط"],"explanation":"وفقًا لقواعد FMCSA التي اعتمدتها PennDOT، ينطبق ELDT (الساري اعتبارًا من 7 فبراير 2022) على الحصول على رخصة CDL من الفئة A أو B لأول مرة، أو الترقية إلى الفئة A أو B، أو الحصول على مصادقة P أو S أو H لأول مرة. وهو غير رجعي الأثر. المصدر: صفحة تدريب السائقين المبتدئين من PennDOT / 49 CFR Part 380."},"34":{"q":"من أين يجب على السائق المبتدئ في بنسلفانيا الحصول على تدريب ELDT المطلوب قبل إجراء اختبار المهارات؟","options":["من مزوّد مدرَج في سجل مزوّدي التدريب (TPR) التابع لـ FMCSA","من أي مركز ترخيص سائقين تابع لـ PennDOT","من برنامج غير رسمي للتدريب أثناء العمل لدى صاحب عمل","من أي مدرسة قيادة تابعة لـ AAA"],"explanation":"تتطلب PennDOT إكمال ELDT لدى مزوّد مدرَج في سجل مزوّدي التدريب (tpr.fmcsa.dot.gov) التابع لـ FMCSA قبل اختبار المهارات. المصدر: صحيفة وقائع CDL من PennDOT (يونيو 2025) / صفحة تدريب السائقين المبتدئين."},"35":{"q":"للحصول على مصادقة المواد الخطرة (H) في بنسلفانيا، يجب على المتقدّم اجتياز اختبار معرفة وإكمال أي فحص خلفية فيدرالي؟","options":["تقييم تهديد أمني من TSA مع أخذ البصمات","فحص توظيف عبر E-Verify","مراجعة سجل قيادة من PennDOT فقط","شهادة طبية من FAA"],"explanation":"تتطلب PennDOT من المتقدّمين للمواد الخطرة إكمال تقييم تهديد أمني فيدرالي من إدارة أمن النقل (TSA)، بما في ذلك أخذ البصمات (النموذج DL-288، PUB 512). ويجب أن تتلقى PennDOT الموافقة الفيدرالية قبل إصدار مصادقة H. المصدر: صحيفة وقائع مصادقة المواد الخطرة من PennDOT (FS-HM) والأسئلة الشائعة."},"36":{"q":"في اختبارات معرفة CDL الرسمية لدى PennDOT، كم عدد الأسئلة في اختبار مصادقة المواد الخطرة (H)؟","options":["30 سؤالًا","20 سؤالًا","25 سؤالًا","50 سؤالًا"],"explanation":"تُدرج PennDOT اختبار معرفة مصادقة المواد الخطرة بأنه 30 سؤالًا، ويُقدَّم اختبار المواد الخطرة باللغة الإنجليزية فقط. المصدر: صحيفة وقائع CDL من PennDOT (يونيو 2025)."},"37":{"q":"قبل الحصول على مصادقة الحافلة المدرسية (S) في بنسلفانيا، أي مصادقة يجب أن يحملها السائق أيضًا؟","options":["مصادقة الركاب (P)","مصادقة الصهريج (N)","مصادقة المزدوجة/الثلاثية (T)","مصادقة المواد الخطرة (H)"],"explanation":"تتطلب PennDOT مصادقة الركاب (P) كشرط مسبق لمصادقة الحافلة المدرسية (S)؛ إذ يتطلب اختبار معرفة S مصادقة الركاب. المصدر: صحيفة وقائع CDL من PennDOT (يونيو 2025) / الأسئلة الشائعة حول النقل المدرسي."},"38":{"q":"أي عبارة حول بطاقة مصادقة الحافلة المدرسية (S) في بنسلفانيا صحيحة وفقًا لـ PennDOT؟","options":["تُصدر بطاقة مصادقة الحافلة المدرسية سنويًا","لا تتطلب المصادقة S التجديد أبدًا","تُصدر المصادقة S كل ثماني سنوات فقط","تُرسل بطاقة المصادقة S بالبريد من TSA"],"explanation":"تشير صحيفة وقائع CDL من PennDOT إلى أن المصادقة S تخوّل تشغيل حافلة مدرسية وأن بطاقة مصادقة الحافلة المدرسية تُصدر سنويًا. المصدر: صحيفة وقائع CDL من PennDOT (يونيو 2025)."},"39":{"q":"عند التقدّم شخصيًا للحصول على رخصة CDL/CLP في بنسلفانيا، يجب على المتقدّم عمومًا تقديم إثبات للهوية والوضع القانوني، وإثبات رقم الضمان الاجتماعي، وكم عدد إثباتات الإقامة في بنسلفانيا؟","options":["إثباتان للإقامة في بنسلفانيا","إثبات واحد للإقامة في بنسلفانيا","ثلاثة إثباتات للإقامة في بنسلفانيا","لا يُطلب إثبات للإقامة"],"explanation":"تتطلب PennDOT مستندًا واحدًا يثبت الهوية/الوضع القانوني، ومستندًا واحدًا يثبت رقم الضمان الاجتماعي، ومستندين يثبتان الإقامة في بنسلفانيا. المصدر: متطلبات إثبات الهوية والإقامة من PennDOT (PUB 195US)."},"40":{"q":"في ولاية بنسلفانيا، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي عنده أو فوقه يُعتبر السائق مشغّلًا لمركبة تجارية آلية (CMV) تحت تأثير الكحول؟","options":["0.02 بالمئة","0.04 بالمئة","0.08 بالمئة","0.10 بالمئة"],"explanation":"تحظر ولاية بنسلفانيا تشغيل مركبة تجارية آلية بتركيز كحول في الدم BAC قدره 0.04 بالمئة أو أكثر، أي نصف حد الـ 0.08 بالمئة الخاص بالسائقين غير التجاريين. المصدر: دليل PA CDL؛ 75 Pa.C.S. و49 CFR 383.51."},"41":{"q":"بموجب قواعد الموافقة الضمنية في بنسلفانيا، ماذا يحدث لسائق مركبة تجارية آلية يرفض الخضوع للاختبار الكيميائي بعد تحذير مناسب من الضابط؟","options":["تحذير كتابي فقط دون أي إيقاف للأهلية","إيقاف أهلية رخصة CDL لمدة 30 يومًا","إيقاف أهلية رخصة CDL لمدة سنة واحدة، يُعامَل مثل إدانة بالقيادة تحت التأثير","إيقاف أهلية رخصة CDL لمدة 6 أشهر"],"explanation":"يُوقَف سائق المركبة التجارية الآلية الذي يرفض الاختبار الكيميائي عن الأهلية لمدة سنة واحدة على الأقل، وهو نفس عقوبة الإدانة بمخالفة كبرى. المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51."},"42":{"q":"في ولاية بنسلفانيا، تؤدي أول مخالفة كبرى (مثل تشغيل مركبة تجارية آلية بتركيز كحول في الدم BAC قدره 0.04 بالمئة أو أكثر) إلى إيقاف أهلية رخصة CDL لمدة لا تقل عن كم؟","options":["60 يومًا","6 أشهر","سنة واحدة","3 سنوات"],"explanation":"توقف أول مخالفة كبرى أهلية حامل رخصة CDL في بنسلفانيا لمدة لا تقل عن سنة واحدة. المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51."},"43":{"q":"في ولاية بنسلفانيا، إذا ارتكب سائق أول مخالفة كبرى أثناء تشغيل مركبة تجارية آلية موضوعة عليها لافتات مواد خطرة، تزداد فترة إيقاف الأهلية إلى:","options":["سنة واحدة","سنتان","3 سنوات","5 سنوات"],"explanation":"أول مخالفة كبرى تُرتكب أثناء نقل مواد خطرة موضوعة عليها لافتات ترفع إيقاف الأهلية من سنة واحدة إلى 3 سنوات. المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51."},"44":{"q":"ما هي فترة إيقاف أهلية رخصة CDL في بنسلفانيا لثاني مخالفة كبرى (على سبيل المثال، ثاني قيادة تحت التأثير في مركبة تجارية آلية)؟","options":["3 سنوات","5 سنوات","10 سنوات","مدى الحياة"],"explanation":"تؤدي مخالفتان كبريان في أي مركبة إلى إيقاف أهلية رخصة CDL مدى الحياة في بنسلفانيا. المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51."},"45":{"q":"في ولاية بنسلفانيا، تؤدي الإدانة بمخالفتين مروريتين خطيرتين في حادثتين منفصلتين خلال فترة 3 سنوات إلى إيقاف أهلية رخصة CDL لمدة:","options":["30 يومًا","60 يومًا","120 يومًا","سنة واحدة"],"explanation":"توقف مخالفتان مروريتان خطيرتان خلال 3 سنوات أهلية حامل رخصة CDL في بنسلفانيا لمدة 60 يومًا. المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51."},"46":{"q":"في ولاية بنسلفانيا، تؤدي الإدانة بثلاث مخالفات مرورية خطيرة في حوادث منفصلة خلال فترة 3 سنوات إلى إيقاف أهلية رخصة CDL لمدة:","options":["60 يومًا","90 يومًا","120 يومًا","سنة واحدة"],"explanation":"توقف ثلاث مخالفات مرورية خطيرة خلال 3 سنوات أهلية حامل رخصة CDL في بنسلفانيا لمدة 120 يومًا، تُنفَّذ بشكل متتالٍ بعد أي إيقاف أهلية لمدة 60 يومًا. المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51."},"47":{"q":"أي مما يلي يُصنَّف كمخالفة مرورية خطيرة لحامل رخصة CDL في بنسلفانيا؟","options":["مصباح خلفي محترق","تجاوز حد السرعة بمقدار 15 mph أو أكثر","الوقوف في منطقة ممنوع التوقف فيها","القيادة بتسجيل منتهي الصلاحية"],"explanation":"تجاوز السرعة بمقدار 15 mph أو أكثر فوق الحد هو مخالفة مرورية خطيرة؛ وتشمل المخالفات الأخرى القيادة المتهورة، وتغيير الحارة بشكل غير سليم، والاتباع عن قرب شديد، وإرسال الرسائل النصية، واستخدام الهاتف المحمول باليد. المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51."},"48":{"q":"بالنسبة لسائق رخصة CDL في بنسلفانيا، ما هو إيقاف الأهلية لأول إدانة بانتهاك قانون معبر السكة الحديدية مع الطريق السريع؟","options":["30 يومًا","60 يومًا","120 يومًا","سنة واحدة"],"explanation":"أول انتهاك لمعبر السكة الحديدية يوقف أهلية حامل رخصة CDL في بنسلفانيا لمدة 60 يومًا. المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51."},"49":{"q":"بالنسبة لسائق رخصة CDL في بنسلفانيا، فإن ثاني انتهاك لمعبر السكة الحديدية مع الطريق السريع خلال فترة 3 سنوات يؤدي إلى إيقاف أهلية لمدة:","options":["60 يومًا","120 يومًا","سنة واحدة","3 سنوات"],"explanation":"ثاني انتهاك لمعبر السكة الحديدية خلال 3 سنوات يوقف أهلية حامل رخصة CDL في بنسلفانيا لمدة 120 يومًا. المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51."},"50":{"q":"بالنسبة لسائق رخصة CDL في بنسلفانيا، فإن ثالث انتهاك أو ما يليه لمعبر السكة الحديدية مع الطريق السريع خلال فترة 3 سنوات يؤدي إلى إيقاف أهلية لمدة:","options":["120 يومًا","180 يومًا","سنة واحدة","3 سنوات"],"explanation":"ثالث انتهاك أو ما يليه لمعبر السكة الحديدية خلال 3 سنوات يوقف أهلية حامل رخصة CDL في بنسلفانيا لمدة سنة واحدة. المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51."},"51":{"q":"في ولاية بنسلفانيا، فإن أول إدانة بانتهاك أمر إيقاف عن الخدمة (OOS) أثناء نقل مواد غير خطرة يوقف أهلية سائق رخصة CDL لمدة:","options":["90 يومًا","180 يومًا","سنة واحدة","سنتان"],"explanation":"أول انتهاك لأمر الإيقاف عن الخدمة (مواد غير خطرة) يوقف أهلية حامل رخصة CDL في بنسلفانيا لمدة لا تقل عن سنة واحدة. المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51."},"52":{"q":"في ولاية بنسلفانيا، فإن ثاني انتهاك لأمر إيقاف عن الخدمة خلال فترة 10 سنوات (مواد غير خطرة) يؤدي إلى إيقاف أهلية رخصة CDL لمدة:","options":["سنة واحدة","سنتان","3 سنوات","5 سنوات"],"explanation":"ثاني انتهاك لأمر الإيقاف عن الخدمة خلال 10 سنوات (مواد غير خطرة) يوقف أهلية حامل رخصة CDL في بنسلفانيا لمدة لا تقل عن 3 سنوات. المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51."},"53":{"q":"في ولاية بنسلفانيا، فإن أول انتهاك لأمر إيقاف عن الخدمة أثناء نقل مواد خطرة أو حمل 16 راكبًا أو أكثر يوقف أهلية سائق رخصة CDL لمدة:","options":["سنة واحدة","سنتان","3 سنوات","5 سنوات"],"explanation":"أول انتهاك لأمر الإيقاف عن الخدمة أثناء نقل مواد خطرة أو حمل 16 راكبًا أو أكثر يوقف أهلية حامل رخصة CDL في بنسلفانيا لمدة لا تقل عن سنتين. المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51."},"54":{"q":"في ولاية بنسلفانيا، فإن ثاني انتهاك لأمر إيقاف عن الخدمة خلال 10 سنوات أثناء نقل مواد خطرة أو حمل 16 راكبًا أو أكثر يوقف أهلية سائق رخصة CDL لمدة:","options":["سنتان","3 سنوات","5 سنوات","مدى الحياة"],"explanation":"ثاني انتهاك لأمر الإيقاف عن الخدمة خلال 10 سنوات أثناء نقل مواد خطرة أو حمل 16 راكبًا أو أكثر يوقف أهلية حامل رخصة CDL في بنسلفانيا لمدة لا تقل عن 5 سنوات. المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51."},"55":{"q":"بالنسبة لحامل رخصة CDL في بنسلفانيا، فإن استخدام هاتف محمول باليد أثناء قيادة مركبة تجارية آلية يُعامَل على أنه:","options":["مخالفة معدات غير قابلة للإبلاغ","مخالفة مرورية خطيرة يمكن أن تؤدي إلى إيقاف الأهلية","إيقاف أهلية تلقائي لمدة سنة واحدة في أول مخالفة","مخالفة تؤدي إلى إيقاف الأهلية مدى الحياة"],"explanation":"استخدام هاتف محمول باليد أثناء تشغيل مركبة تجارية آلية هو مخالفة مرورية خطيرة؛ ومخالفتان منها خلال 3 سنوات تسبّبان إيقاف أهلية لمدة 60 يومًا، وثلاث تسبّب 120 يومًا. المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51 و392.82."},"56":{"q":"بالنسبة لحامل رخصة CDL في بنسلفانيا، فإن إرسال الرسائل النصية أثناء قيادة مركبة تجارية آلية هو:","options":["مسموح به إذا كانت المركبة متوقفة عند إشارة ضوئية","مخالفة مرورية خطيرة يمكن أن تؤدي إلى إيقاف الأهلية","مجرد غرامة من نوع غرامات الوقوف دون أي أثر على الرخصة","مسموح به لأغراض الاتصال بالإرسالية"],"explanation":"إرسال الرسائل النصية أثناء تشغيل مركبة تجارية آلية هو مخالفة مرورية خطيرة؛ وتراكم هذه المخالفات خلال 3 سنوات يؤدي إلى إيقاف أهلية لمدة 60 أو 120 يومًا. المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51 و392.80."},"57":{"q":"في ولاية بنسلفانيا، أي إدانة تحمل إيقاف أهلية رخصة CDL مدى الحياة دون أي خيار لإعادة الأهلية بعد 10 سنوات؟","options":["ثاني قيادة تحت التأثير في مركبة تجارية آلية","استخدام مركبة تجارية آلية لارتكاب جناية تتعلق بتصنيع مادة خاضعة للرقابة أو توزيعها","مخالفتان مروريتان خطيرتان خلال 3 سنوات","أول انتهاك لأمر إيقاف عن الخدمة"],"explanation":"استخدام مركبة تجارية آلية في جناية تتعلق بتصنيع مادة خاضعة للرقابة أو توزيعها أو صرفها يؤدي إلى إيقاف أهلية مدى الحياة لا يمكن تخفيضه. المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51."},"58":{"q":"سائق رخصة CDL في بنسلفانيا المُدان بمخالفة كبرى تؤدي إلى وفاة عبر تشغيل مركبة تجارية آلية بإهمال أو بشكل جنائي يُوقَف عن الأهلية لمدة لا تقل عن:","options":["60 يومًا","120 يومًا","سنة واحدة","5 سنوات"],"explanation":"التسبب في وفاة عبر تشغيل مركبة تجارية آلية بإهمال أو بشكل جنائي هو مخالفة كبرى تحمل إيقاف أهلية لا يقل عن سنة واحدة (3 سنوات إذا كانت موضوعة عليها لافتات مواد خطرة). المصدر: صحيفة وقائع إيقاف الأهلية والمخالفات المرورية من PennDOT؛ 49 CFR 383.51."},"59":{"q":"بموجب قانون الحافلات المدرسية في بنسلفانيا، عندما تكون أضواء الإشارة الحمراء للحافلة المدرسية وامضة وذراع التوقف ممدودة، على أي مسافة قبل الوصول إلى الحافلة يجب على السائق القادم من الاتجاه المقابل أو المتجاوِز أن يتوقف؟","options":["على بُعد 10 feet على الأقل","على بُعد 15 feet على الأقل","على بُعد 20 feet على الأقل","على بُعد 25 feet على الأقل"],"explanation":"تشترط بنسلفانيا على السائقين القادمين من الاتجاه المقابل لحافلة مدرسية أو المتجاوِزين لها وأضواء إشارتها الحمراء وامضة أن يتوقفوا على بُعد 10 feet على الأقل من الحافلة وألا يتابعوا السير حتى تتوقف الأضواء عن الوميض وتُسحب ذراع التوقف. المصدر: 75 Pa.C.S. § 3345 (الالتقاء بحافلة مدرسية أو تجاوزها); دليل سائق المركبات التجارية في بنسلفانيا (PUB 223)."},"60":{"q":"على طريق سريع في بنسلفانيا ذي مسارات منفصلة مقسَّمة بحاجز مادي أو قسم فاصل محدد بوضوح، فإن السائق على الطريق المقابل لحافلة مدرسية متوقفة وأضواؤها الحمراء وامضة يجب عليه:","options":["ألا يُطلَب منه التوقف","أن يتوقف على بُعد 10 feet على الأقل من الجزيرة الوسطية","أن يتوقف فقط إذا كان الأطفال مرئيين","أن يخفّض سرعته إلى 15 mph لكن دون الحاجة إلى التوقف"],"explanation":"ينص استثناء الطرق المقسَّمة في بنسلفانيا على أن السائق على طريق سريع ذي مسارات منفصلة لا يلزمه التوقف لحافلة مدرسية وأضواؤها الحمراء وامضة إذا كانت على طريق مختلف. ويتطلب \"الطريق المنفصل\" وجود حاجز مادي أو قسم فاصل محدد بوضوح؛ فالخطوط المرسومة أو اللافتات وحدها لا تُنشئ طريقًا منفصلاً. المصدر: 75 Pa.C.S. § 3345."},"61":{"q":"أي ميزة تُعَدّ مطلوبة لتطبيق استثناء \"المسارات المنفصلة\" الخاص بالحافلات المدرسية في بنسلفانيا (بحيث لا يلزم المرور المقابل التوقف)؟","options":["حاجز مادي أو قسم فاصل محدد بوضوح","خط مركزي أصفر مزدوج","مسار وسطي للانعطاف لليسار","لافتة منصوبة مكتوب عليها 'DIVIDED HIGHWAY'"],"explanation":"في بنسلفانيا ينطبق الاستثناء فقط حيث تكون المسارات مفصولة بحاجز مادي أو قسم فاصل محدد بوضوح. ولا تُعَدّ علامات الرصف أو اللافتات وحدها مُنشئة لطريق منفصل، لذا على الطرق المقسَّمة بالطلاء فقط يجب على جميع الاتجاهات التوقف. المصدر: 75 Pa.C.S. § 3345."},"62":{"q":"المركبة المُلزَمة بالتوقف عند تقاطع السكة الحديدية في بنسلفانيا يجب أن تتوقف ضمن أي مسافة من أقرب قضيب؟","options":["ضمن 50 feet ولكن ليس أقل من 15 feet","ضمن 100 feet ولكن ليس أقل من 25 feet","ضمن 30 feet ولكن ليس أقل من 10 feet","ضمن 75 feet ولكن ليس أقل من 20 feet"],"explanation":"يشترط قانون بنسلفانيا على المركبات المُلزَمة بالتوقف عند تقاطعات السكة الحديدية (الحافلات المدرسية وحافلات الركاب والشاحنات التي تنقل بعض أنواع الوقود/المتفجرات/المواد المشعة) أن تتوقف ضمن 50 feet ولكن ليس أقل من 15 feet من أقرب قضيب، ثم تنظر وتستمع. المصدر: 75 Pa.C.S. § 3342 (المركبات المُلزَمة بالتوقف عند تقاطعات السكة الحديدية); دليل CDL في بنسلفانيا."},"63":{"q":"أي مركبة لا يُلزَم بالتوقف عند كل تقاطع للسكة الحديدية بموجب قانون بنسلفانيا؟","options":["شاحنة مقطورة جافة فارغة لا تحمل أي مواد خطرة","حافلة مدرسية، سواء كانت تنقل ركابًا أم لا","حافلة تنقل ركابًا","شاحنة تحمل متفجرات تحمل لافتات تحذيرية"],"explanation":"تشترط بنسلفانيا على الحافلات المدرسية (محمَّلة أو فارغة)، والحافلات الناقلة للركاب، والشاحنات الناقلة للبنزين أو الديزل/زيت الوقود أو المتفجرات أو المواد المشعة أن تتوقف عند التقاطعات. أما شاحنة الشحن الفارغة العادية التي لا تحمل بضائع خطرة فلا يُلزَم بتوقفها. المصدر: 75 Pa.C.S. § 3342."},"64":{"q":"عندما تعبر مركبة تجارية في بنسلفانيا مُلزَمة بالتوقف قضبان السكة الحديدية، يُمنَع السائق تحديدًا من فعل ماذا؟","options":["تبديل التروس يدويًا أثناء وجوده على القضبان","استخدام مكبح المحرك","العبور بتروس منخفضة","تشغيل أضواء التحذير الرباعية"],"explanation":"يوجِّه قانون بنسلفانيا السائق المُلزَم بالتوقف أن يعبر بترس لا يتطلب تغيير التروس أثناء العبور، وألا يبدِّل التروس يدويًا أثناء وجوده على القضبان. المصدر: 75 Pa.C.S. § 3342; دليل CDL في بنسلفانيا."},"65":{"q":"عند تقاطع للسكة الحديدية في بنسلفانيا محدَّد بلافتة مكتوب عليها 'EXEMPT'، فإن شاحنة المواد الخطرة الحاملة للافتات أو الحافلة:","options":["لا يُلزَم بتوقفها","يجب أن تتوقف رغم ذلك ضمن 50 feet من القضيب","يجب أن تتوقف وتُطلِق البوق","يجب أن تتوقف فقط إذا كانت هناك بوابة"],"explanation":"تُعفي بنسلفانيا التقاطعات المنصوب عليها لافتة 'exempt' (والتقاطعات المهجورة المُعلَّمة كذلك) من قاعدة التوقف الإلزامي؛ كما أن توجيه ضابط أو موجِّه إشارات للمركبة لتعبر، أو وجود إشارة مرور خضراء، يُعفي أيضًا من واجب التوقف. المصدر: 75 Pa.C.S. § 3342."},"66":{"q":"بموجب قانون \"Move Over\" في بنسلفانيا، عندما لا يستطيع السائق الانتقال بأمان إلى مسار غير مجاور قرب منطقة استجابة طوارئ، يجب عليه بدلاً من ذلك أن يمرّ بسرعة لا تزيد عن كم تحت السرعة المحددة؟","options":["20 mph تحت حد السرعة المحدد","10 mph تحت حد السرعة المحدد","15 mph تحت حد السرعة المحدد","25 mph تحت حد السرعة المحدد"],"explanation":"يشترط قانون \"Move Over\" (Steer Clear) في بنسلفانيا المرور في مسار غير مجاور لمنطقة استجابة الطوارئ عند الإمكان؛ وإذا كان ذلك مستحيلاً أو غير قانوني أو غير آمن، يجب على السائق المرور بسرعة لا تزيد عن 20 mph تحت حد السرعة المحدد وبسرعة معقولة للسلامة. المصدر: 75 Pa.C.S. § 3327."},"67":{"q":"كم عدد النقاط التي يخصصها قانون \"Move Over\" في بنسلفانيا (Act 105 of 2020) لعدم الاندماج في مسار غير مجاور لمنطقة استجابة الطوارئ؟","options":["2 points","3 points","4 points","5 points"],"explanation":"أضاف Act 105 of 2020 عقوبة قدرها 2 points لعدم الانتقال جانبًا، إضافة إلى غرامات متصاعدة قدرها 500$ (الأولى)، و1,000$ (الثانية)، و2,000$ مع تعليق لمدة 90-day (الثالثة أو ما بعدها). المصدر: 75 Pa.C.S. § 3327; حملة Move Over التابعة لـ PennDOT."},"68":{"q":"إلى جانب الشرطة والإطفاء والإسعاف وشاحنات القطر، يحمي قانون \"Move Over\" في بنسلفانيا أيضًا أيًّا مما يلي؟","options":["مركبة معطّلة تعرض علامتي طوارئ على الأقل (مثل أضواء الخطر والشُّعَل)","أي مركبة متوقفة بشكل قانوني على الكتف","المركبات المملوكة للحكومة فقط","المركبات المتوقفة عند إشارة حمراء"],"explanation":"وسّعت بنسلفانيا واجب \"Move Over\" ليشمل المركبات المعطّلة التي تعرض علامتي طوارئ على الأقل مثل أضواء الخطر أو لافتات/أجهزة التحذير أو الشُّعَل الطرقية. ويجب على السائقين تغيير المسار أو الإبطاء إلى ما لا يزيد عن 20 mph تحت الحد. المصدر: 75 Pa.C.S. § 3327 (الواجب فيما يتعلق بالمركبات المعطّلة)."},"69":{"q":"على طريق سريع محدود الوصول في بنسلفانيا ذي ثلاثة مسارات أو أكثر في اتجاه واحد، أين يجوز لمركبة شاحنة مركّبة يزيد وزنها عن 10,000 pounds أن تسير؟","options":["أي مسار باستثناء المسار الأيسر (الذي يُمنَع إلا للاستعداد لانعطاف يساري مسموح به)","المسار الأوسط فقط في جميع الأوقات","المسار الأيمن فقط في جميع الأوقات","أي مسار، دون أي قيد"],"explanation":"تمنع بنسلفانيا أي مركبة أو تركيبة يزيد وزنها عن 10,000 pounds من القيادة في المسار الأيسر لطريق سريع محدود الوصول ذي ثلاثة مسارات أو أكثر في الاتجاه نفسه، إلا عند الاستعداد لانعطاف يساري مسموح به قانونًا عند تقاطع أو مخرج أو ممر. المصدر: 75 Pa.C.S. § 3313 (قيود على استخدام الطرق السريعة محدودة الوصول)."},"70":{"q":"على الطرق السريعة محدودة الوصول في بنسلفانيا ذات مسارين أو أكثر في اتجاه واحد، القاعدة العامة لجميع المركبات هي القيادة في المسارات اليمنى إلا عندما:","options":["يجري التجاوز والتخطّي، أو السير بسرعة أعلى من تدفق المرور، أو الاستعداد لانعطاف يساري مسموح به","السير ليلاً","يكون الطريق مبتلاً","يطلب أحد الركاب المسار الأيسر"],"explanation":"تشترط بنسلفانيا على المركبات استخدام المسارات اليمنى عند توفرها، إلا عند التجاوز والتخطّي لمركبة، أو السير بسرعة أعلى من تدفق المرور، أو الاستعداد لانعطاف يساري مسموح به قانونًا. المصدر: 75 Pa.C.S. § 3313."},"71":{"q":"في غياب لافتة منصوبة، فإن الحد الأقصى الافتراضي للسرعة على معظم الطرق في بنسلفانيا (غير المناطق الحضرية أو الطرق السريعة الحرة) هو:","options":["55 mph","50 mph","60 mph","65 mph"],"explanation":"تحدد بنسلفانيا حدًا أقصى قانونيًا قدره 55 mph في المواقع غير المُعلَّمة بخلاف ذلك، و35 mph في أي منطقة حضرية، وحتى 65 أو 70 mph على الطرق السريعة الحرة حيث تنصب الإدارة ذلك الحد. المصدر: 75 Pa.C.S. § 3362 (الحدود القصوى للسرعة)."},"72":{"q":"على طريق سريع حر في بنسلفانيا محدد بسرعة 70 mph، كيف يقارن الحد الأقصى للسرعة لشاحنة تجارية ثقيلة بذلك الخاص بسيارة الركاب؟","options":["هو نفسه — تنطبق 70 mph على جميع المركبات","تُحدَّد الشاحنات بـ 55 mph","تُحدَّد الشاحنات بـ 60 mph","تُحدَّد الشاحنات بـ 65 mph"],"explanation":"لا تحدد بنسلفانيا حدًا أقصى منفصلاً وأدنى للشاحنات؛ فالحد الأقصى المُعلَن على الطريق السريع الحر وهو 65 أو 70 mph ينطبق على جميع المركبات. (يمكن أن تنطبق حدود أدنى على منحدرات محددة أو عبر لافتات منصوبة.) المصدر: 75 Pa.C.S. § 3362."},"73":{"q":"الحد الأقصى المُعلَن للسرعة على الخط الرئيسي لطريق Pennsylvania Turnpike (I-76) هو:","options":["70 mph","65 mph","75 mph","80 mph"],"explanation":"الحد الأقصى المُعلَن للسرعة على Pennsylvania Turnpike هو 70 mph، وهو ساري المفعول على معظم الخط الرئيسي (مثلاً بين تقاطعي Blue Mountain وMorgantown) والعديد من الطرق السريعة الحرة التابعة لـ PennDOT. ولا يوجد قسم مُعلَن بسرعة 75 mph. المصدر: Pennsylvania Turnpike Commission / PennDOT; 75 Pa.C.S. § 3362."},"74":{"q":"الحد القانوني للسرعة في المناطق الحضرية في بنسلفانيا، حيث لا يُعلَن حد آخر، هو:","options":["35 mph","25 mph","30 mph","40 mph"],"explanation":"في أي منطقة حضرية، الحد الأقصى القانوني للسرعة في بنسلفانيا هو 35 mph ما لم يُعلَن حد مختلف بعد دراسة مرورية. المصدر: 75 Pa.C.S. § 3362."},"75":{"q":"سائق شاحنة توقفت مركبته التجارية على الجزء المخصص للسير من طريق ذي مسارين واتجاهين في بنسلفانيا يجب أن يضع أجهزة التحذير خلال أي مدة، وأين؟","options":["خلال 10 minutes: على بُعد 10 ft، و100 ft إلى الخلف، و100 ft إلى الأمام","خلال 15 minutes: على بُعد 25 ft، و50 ft، و100 ft","خلال 30 minutes: على بُعد 10 ft، و200 ft، و300 ft","خلال 5 minutes: الثلاثة جميعًا ضمن 50 ft"],"explanation":"اتباعًا للمعيار الفيدرالي الذي تطبّقه بنسلفانيا، يجب على المركبة التجارية المتوقفة عرض أجهزة التحذير خلال 10 minutes. على طريق ذي اتجاهين، ضع واحدًا ضمن 10 ft من المركبة باتجاه المرور القادم، وواحدًا على بُعد نحو 100 ft إلى الخلف، وواحدًا على بُعد نحو 100 ft إلى الأمام. المصدر: دليل CDL في بنسلفانيا (PUB 223); 49 CFR 392.22."},"76":{"q":"عندما تتوقف مركبة تجارية على طريق أحادي الاتجاه أو مقسَّم في بنسلفانيا، أين تُوضَع أجهزة التحذير الثلاثة باتجاه المرور القادم؟","options":["على بُعد نحو 10 ft، و100 ft، و200 ft إلى الخلف","على بُعد نحو 10 ft، و50 ft، و100 ft إلى الخلف","على بُعد نحو 25 ft، و100 ft، و250 ft إلى الخلف","على بُعد نحو 10 ft، و100 ft، و150 ft إلى الخلف"],"explanation":"على طريق أحادي الاتجاه أو مقسَّم، ضع أجهزة التحذير على بُعد نحو 10 feet و100 feet و200 feet باتجاه المرور القادم (الجانب الذي يأتي منه المرور)، خلال 10 minutes من التوقف. المصدر: دليل CDL في بنسلفانيا (PUB 223); 49 CFR 392.22."},"77":{"q":"أي فئة من المواد الخطرة يُمنَع نقلها عبر أنفاق Pennsylvania Turnpike؟","options":["جميع المتفجرات ومواد Table 1 الأخرى (مثل الغاز السام والمواد المشعة)","السوائل القابلة للاشتعال بالجملة فقط","المواد الأكّالة فقط","الغازات المبرَّدة فقط"],"explanation":"يحظر Pennsylvania Turnpike جميع مواد Table 1 — بما في ذلك جميع المتفجرات والغاز السام والمواد الخطرة عند التبلل ومواد خطر الاستنشاق السام والمواد المشعة — من أنفاقه؛ وقد يُسمَح ببعض الشحنات غير السائبة من مواد خطرة أخرى. المصدر: قيود أنفاق المواد الخطرة الخاصة بـ Pennsylvania Turnpike Commission; 67 Pa. Code § 601.5."},"78":{"q":"السائق المُدان بتجاوز حافلة مدرسية متوقفة بشكل غير قانوني وأضواؤها الحمراء وامضة في بنسلفانيا يواجه غرامة أساسية إضافة إلى رسم إضافي قدرها:","options":["غرامة 250$ إضافة إلى رسم إضافي قدره 35$ (مع نقاط وتعليق الرخصة)","غرامة 100$ دون أي رسم إضافي","غرامة 500$ إضافة إلى رسم إضافي قدره 50$","غرامة 50$ إضافة إلى رسم إضافي قدره 25$"],"explanation":"تعاقب بنسلفانيا على تجاوز حافلة مدرسية متوقفة بشكل غير قانوني بغرامة 250$ ورسم إضافي قدره 35$؛ كما أن المخالفة التي يرصدها ضابط تجلب أيضًا 5 points وتعليقًا للرخصة لمدة 60-day. المصدر: 75 Pa.C.S. § 3345."},"79":{"q":"أي جهة تُصدِر رخص القيادة التجارية (CDLs) في بنسلفانيا؟","options":["شرطة ولاية بنسلفانيا، وحدة المركبات التجارية","وزارة النقل في بنسلفانيا (PennDOT)، مكتب خدمات السائقين والمركبات","لجنة المرافق العامة في بنسلفانيا (PUC)","الإدارة الفيدرالية لسلامة الناقلين بالمركبات (FMCSA)"],"explanation":"تُصدَر رخص CDL في بنسلفانيا من قِبل PennDOT عبر مكتب خدمات السائقين والمركبات التابع لها. وتضع FMCSA المعايير الفيدرالية لكنها لا تُصدِر رخص الولايات. المصدر: نشرة حقائق رخصة القيادة التجارية الخاصة بـ PennDOT (مرجع PUB 223) وخدمات السائقين والمركبات على pa.gov."},"80":{"q":"في بنسلفانيا، ما الحد الأدنى للسن للحصول على رخصة CDL للقيادة داخل الولاية (ضمن بنسلفانيا) مقابل القيادة بين الولايات؟","options":["21 لكلٍّ من القيادة داخل الولاية وبين الولايات","16 للقيادة داخل الولاية و18 للقيادة بين الولايات","18 للقيادة داخل الولاية و21 للقيادة بين الولايات","18 لكلٍّ من القيادة داخل الولاية وبين الولايات"],"explanation":"تسمح بنسلفانيا بالحصول على رخصة CDL في سن 18 للتشغيل داخل الولاية فقط، بينما يتطلب التشغيل بين الولايات (ونقل المواد الخطرة أو الركاب عبر حدود الولايات) أن يكون عمر السائق 21 على الأقل. المصدر: متطلبات ترخيص CDL لدى PennDOT (pa.gov) بما يتسق مع 49 CFR 383.3."},"81":{"q":"قبل إجراء اختبار مهارات CDL في بنسلفانيا، يجب على المتقدم أولاً الحصول على أي وثيقة؟","options":["إعفاء طبي من PennDOT","تصريح متعلّم القيادة التجارية (CLP)","رخصة مصوَّرة متوافقة مع REAL ID","رخصة CDL غير تجارية من الفئة Class C"],"explanation":"يجب على المتقدمين اجتياز اختبار (اختبارات) المعرفة المطلوب وأن يُصدَر لهم تصريح متعلّم القيادة التجارية قبل أن يُسمَح لهم بإجراء اختبار المهارات. المصدر: الأسئلة الشائعة عن تصريح متعلّم CDL ونشرة حقائق CDL الخاصة بـ PennDOT (pa.gov)."},"82":{"q":"أي نموذج يستخدمه المتقدم لرخصة CDL أو CLP في بنسلفانيا للإقرار الذاتي بنوع القيادة التجارية التي يؤديها؟","options":["طلب سجل السائق DL-503","طلب تصريح متعلّم القيادة التجارية DL-31CD","شهادة الفاحص الطبي DL-26","نموذج الإقرار الذاتي DL-11CD"],"explanation":"يجب على كل حامل رخصة CDL وكل متقدم لـ CLP تقديم نموذج الإقرار الذاتي DL-11CD يُعلِن فيه عن فئة تشغيله. أما DL-31CD فهو طلب CLP، وهو نموذج منفصل. المصدر: الأسئلة الشائعة عن الإقرار الذاتي/شهادة الفاحص الطبي ونموذج DL-11CD الخاص بـ PennDOT (pa.gov)."},"83":{"q":"أي مما يلي ليس واحدة من فئات الإقرار الذاتي الأربع التي يجب على المتقدم لرخصة CDL في بنسلفانيا الاختيار من بينها؟","options":["مشغّل زراعي معفى","Excepted Intrastate (داخل الولاية مستثنى)","Non-excepted Intrastate (داخل الولاية غير مستثنى)","Non-excepted Interstate (بين الولايات غير مستثنى)"],"explanation":"فئات الإقرار الذاتي الأربع هي Non-excepted Interstate وExcepted Interstate وNon-excepted Intrastate وExcepted Intrastate. أما \"المشغّل الزراعي المعفى\" فليس فئة إقرار ذاتي. المصدر: نموذج الإقرار الذاتي DL-11CD ونشرة حقائق CDL الخاصة بـ PennDOT (pa.gov)."},"84":{"q":"أي فئة إقرار ذاتي تتطلب من السائق أن يكون لديه شهادة فاحص طبي سارية (بطاقة الفحص البدني DOT) مسجَّلة لدى PennDOT؟","options":["Non-excepted Interstate (بين الولايات غير مستثنى)","Excepted Intrastate (داخل الولاية مستثنى)","Excepted Interstate وExcepted Intrastate","Excepted Interstate (بين الولايات مستثنى)"],"explanation":"فقط السائقون الذين يُقِرّون ذاتيًا بأنهم Non-excepted (Interstate أو Intrastate) يجب أن يحتفظوا بشهادة فاحص طبي سارية مسجَّلة لدى PennDOT. أما الفئات المستثناة فلا يُطلَب منها تقديم شهادة فاحص طبي (MEC). المصدر: الأسئلة الشائعة عن الإقرار الذاتي/شهادة الفاحص الطبي الخاصة بـ PennDOT (pa.gov)."},"85":{"q":"اعتبارًا من June 23, 2025، كيف يجب تقديم شهادة الفاحص الطبي (الفحص البدني DOT) لحامل رخصة CDL غير مستثنى في بنسلفانيا إلى PennDOT؟","options":["تُرسَل إلكترونيًا من سجل FMCSA الوطني مباشرة إلى PennDOT","يسلّم السائق البطاقة الورقية لموظف في أي مركز لرخص السائقين تابع لـ PennDOT","يرسل السائق نسخة ممسوحة ضوئيًا عبر البريد الإلكتروني إلى PennDOT","يرسل السائق البطاقة الورقية بالبريد إلى وحدة CDL التابعة لـ PennDOT في Harrisburg"],"explanation":"منذ June 23, 2025، لا تقبل PennDOT سوى معلومات شهادة الفاحص الطبي المُرسَلة إلكترونيًا من سجل FMCSA الوطني؛ ولم تعد تقبل شهادات MEC شخصيًا أو بالبريد أو بالبريد الإلكتروني. المصدر: الأسئلة الشائعة عن الإقرار الذاتي/شهادة الفاحص الطبي الخاصة بـ PennDOT (pa.gov)."},"86":{"q":"المكونات الثلاثة لاختبار مهارات CDL في بنسلفانيا هي فحص ما قبل الرحلة (فحص المركبة)، واختبار القيادة على الطريق، فما المكوّن الثالث؟","options":["اختبار تحريري للقيادة الدفاعية","التحكم الأساسي بالمركبة (مناورات خارج الطريق وركن المركبة)","اختبار موقوت لردة فعل المكابح","محاكاة مخبرية للوصل والفصل"],"explanation":"يتكون اختبار مهارات CDL في بنسلفانيا من ثلاثة أجزاء: فحص ما قبل الرحلة، والتحكم الأساسي بالمركبة (مناورات خارج الطريق وتمرين ركن المركبة)، واختبار القيادة على الطريق. المصدر: نشرة حقائق CDL الخاصة بـ PennDOT، قسم \"Skills Tests\" (pa.gov)."},"87":{"q":"أي متطلب تدريب فيدرالي يجب على المتقدم في بنسلفانيا إكماله قبل أن يُسمَح له بإجراء اختبار مهارات CDL لأول رخصة من الفئة Class A أو Class B؟","options":["دورة قيادة دفاعية صفّية تديرها PennDOT","تدريب السائق المبتدئ (ELDT) من مزوّد مسجَّل","دورة سلامة OSHA مدتها 40-hour","شهادة إتمام تدريب مهني صادرة عن الولاية"],"explanation":"يجب إكمال تدريب السائق المبتدئ (ELDT) من مزوّد مدرَج في سجل مزوّدي التدريب التابع لـ FMCSA قبل إجراء اختبار المهارات لرخصة CDL أولية من الفئة Class A أو B (وللحصول على تظهيرات P أو S أو H لأول مرة). المصدر: نشرة حقائق CDL الخاصة بـ PennDOT (pa.gov) وقاعدة ELDT الخاصة بـ FMCSA (49 CFR Part 380)."},"88":{"q":"وفقًا لنشرة حقائق CDL الخاصة بـ PennDOT، كم عدد الأسئلة في اختبار المعرفة العامة التحريري للفئة Class A في بنسلفانيا؟","options":["50 questions","30 questions","70 questions","100 questions"],"explanation":"تُدرِج نشرة حقائق CDL الخاصة بـ PennDOT اختبار المعرفة التحريري للفئة Class A بأنه 70 questions، بينما الفئتان Class B وClass C كل منهما 50 questions. المصدر: نشرة حقائق CDL الخاصة بـ PennDOT، \"What Tests Do I Need to Take?\" (pa.gov)."},"89":{"q":"كم عدد الأسئلة في اختبار معرفة تظهير المواد الخطرة (HazMat) في بنسلفانيا، وبأي لغة يُقدَّم؟","options":["25 questions، الإنجليزية فقط","30 questions، الإنجليزية فقط","50 questions، لغات متعددة","20 questions، لغات متعددة"],"explanation":"تُدرِج PennDOT اختبار معرفة تظهير HazMat بأنه 30 questions، ويُقدَّم اختبار HazMat بالإنجليزية فقط (بينما تتوفر اختبارات معرفة CDL الأخرى بلغات متعددة). المصدر: نشرة حقائق CDL الخاصة بـ PennDOT (pa.gov)."},"90":{"q":"وفقًا لنشرة حقائق CDL الخاصة بـ PennDOT، بعد كم من الوقت من اجتياز اختبار المعرفة وإصدار التصريح يمكن للمتقدم في بنسلفانيا إجراء اختبار المهارات؟","options":["ليس قبل 15 days بعد اجتياز اختبار المعرفة وإصدار التصريح","ليس قبل 30 days بعد إصدار التصريح","ليس قبل 60 days بعد إصدار التصريح","فورًا بعد اجتياز اختبار المعرفة"],"explanation":"تذكر PennDOT أن اختبار المهارات لا يمكن إجراؤه حتى 15 days بعد اجتياز اختبار المعرفة وإصدار التصريح (يمكن للمتقدم جدولة اختبار المهارات فورًا، لكن لا يمكنه إجراؤه قبل نقطة الـ 15-day). المصدر: نشرة حقائق CDL الخاصة بـ PennDOT، ملاحظة \"Skills Tests\" (pa.gov)."},"91":{"q":"ما مدة الصلاحية القياسية لرخصة القيادة التجارية في بنسلفانيا قبل وجوب تجديدها (للسائق دون 65)؟","options":["5 years","8 years","2 years","4 years"],"explanation":"تكون رخصة CDL في بنسلفانيا صالحة عمومًا لمدة 4 years؛ ويُصدَر للسائقين بعمر 65 فأكثر على دورة 2 years. المصدر: معلومات الترخيص لدى خدمات السائقين والمركبات في PennDOT (pa.gov)."},"92":{"q":"ما مدة رخصة CDL الصادرة في بنسلفانيا لسائق عمره 65 عامًا أو أكثر؟","options":["4 years","2 years","3 years","1 year"],"explanation":"بينما الدورة القياسية لرخصة CDL في بنسلفانيا هي 4 years، يُوضَع السائقون بعمر 65 فأكثر على دورة تجديد مدتها 2 years. المصدر: معلومات الترخيص لدى خدمات السائقين والمركبات في PennDOT (pa.gov)."},"93":{"q":"إذا ترك حامل رخصة CDL غير مستثنى في بنسلفانيا شهادة الفاحص الطبي الخاصة به تنتهي صلاحيتها ولم يقدّم واحدة جديدة، فماذا يحدث لرخصته؟","options":["يُخفَّض تصنيف الرخصة التجارية (CDL) إلى رخصة غير تجارية","تُفرَض غرامة مدنية قدرها 500$ لكن تظل رخصة CDL سارية","تُلغى الرخصة نهائيًا ولا يمكن إعادتها","لا يتغير شيء حتى التجديد التالي كل 4 years"],"explanation":"إذا انقضت شهادة طبية لسائق غير مستثنى، تُزيل PennDOT التصنيف التجاري وتخفّض الوثيقة إلى رخصة قيادة غير تجارية؛ ويجب على السائق إعادة التقديم للحصول على CLP لاستعادة الامتيازات التجارية. المصدر: الأسئلة الشائعة عن الإقرار الذاتي/شهادة الفاحص الطبي الخاصة بـ PennDOT (pa.gov)."},"94":{"q":"في بنسلفانيا، أي وثيقة تُستخدَم للتقدم بطلب الحصول على تصريح متعلّم القيادة التجارية نفسه؟","options":["النموذج MV-1، طلب سند ملكية المركبة","النموذج DL-180، طلب تصريح متعلّم القيادة غير التجارية","النموذج DL-11CD، نموذج الإقرار الذاتي","النموذج DL-31CD، طلب تصريح متعلّم القيادة التجارية"],"explanation":"طلب تصريح متعلّم القيادة التجارية هو النموذج DL-31CD. أما النموذج DL-11CD فهو نموذج الإقرار الذاتي المنفصل، وعادة ما يقدّم المتقدم لـ CLP كليهما. المصدر: الأسئلة الشائعة عن تصريح متعلّم CDL الخاصة بـ PennDOT (pa.gov)."},"95":{"q":"بموجب قواعد PennDOT، بمجرد أن يبدأ المتقدم لرخصة CDL في بنسلفانيا العملية، كم من الوقت أمامه لاجتياز جميع اختبارات المعرفة والمهارات المطلوبة قبل أن يضطر إلى البدء من جديد؟","options":["ستة أشهر","90 days","سنة واحدة","سنتان"],"explanation":"تمنح PennDOT المتقدم سنة واحدة لاجتياز جميع اختبارات المعرفة والمهارات للحصول على رخصة CDL؛ ويمكن تمديد التصريح بتقديم طلب DL-31CD جديد إذا لم يكتمل الاختبار في الوقت المحدد. المصدر: الأسئلة الشائعة عن تصريح متعلّم CDL الخاصة بـ PennDOT (pa.gov)."},"96":{"q":"يريد سائق رخصة CDL من الفئة Class C فقط لتشغيل مركبة سعتها 20 راكبًا. وفقًا لنشرة حقائق CDL الخاصة بـ PennDOT، ماذا يجب أن تتضمن رخصة CDL من الفئة Class C؟","options":["تظهير S أو P أو H","لا تظهير من أي نوع","تظهير المقطورات المزدوجة/الثلاثية","رمز قيد الفرامل الهوائية فقط"],"explanation":"تُعرِّف PennDOT الفئة Class C بأنها مركبات مفردة وزنها أقل من 26,001 lbs تنقل مواد خطرة تستلزم لافتات تحذيرية، أو تنقل 16 راكبًا فأكثر، أو هي حافلات مدرسية؛ وتذكر نشرة الحقائق أن رخصة CDL من الفئة Class C يجب أن تتضمن تظهير S أو P أو H. المصدر: نشرة حقائق CDL الخاصة بـ PennDOT، فئات الرخص (pa.gov)."},"97":{"q":"وفقًا لنشرة حقائق CDL الخاصة بـ PennDOT، أي تظهير يتطلب على نحو منفصل تدريب السائق المبتدئ (ELDT) عند الحصول عليه لأول مرة؟","options":["تظهير المواد الخطرة (H)","تظهير المقطورات المزدوجة/الثلاثية (T)","تظهير مركبة الصهريج (N)","إزالة قيد الفرامل الهوائية"],"explanation":"تُظهِر نشرة حقائق PennDOT أن ELDT مطلوب (للمرة الأولى فقط) لتظهيرات الركاب والحافلة المدرسية والمواد الخطرة (H)؛ بينما تظهيرا المقطورات المزدوجة/الثلاثية والصهريج مدرَجان على أنهما لا يتطلبان ELDT. المصدر: جدول التظهيرات/الاختبارات في نشرة حقائق CDL الخاصة بـ PennDOT (pa.gov)."},"98":{"q":"عندما يحضر المتقدم في بنسلفانيا لاختبار مهارات CDL، أي مركبة يجب أن يُحضِر؟","options":["أي سيارة ركاب بتسجيل ساري المفعول","مركبة اختبار مملوكة لـ PennDOT تُخصَّص في المركز","مركبة من فئة أصغر بدرجة من رخصة CDL المطلوبة","مركبة ممثِّلة للفئة والنوع الذي ينوي قيادته"],"explanation":"يجب إجراء اختبار المهارات في مركبة من الفئة والنوع الذي ينوي المتقدم قيادته (على سبيل المثال، يجب إجراء اختبار مهارات تظهير الحافلة المدرسية في حافلة مدرسية). المصدر: نشرة حقائق CDL الخاصة بـ PennDOT، قسم \"Skills Tests\" (pa.gov)."}}};
